import { Toaster } from '@/components/ui/toaster'
import { useEffect, useState, lazy, Suspense } from 'react'
import { SplashScreen } from './components/ui/layout/SplashScreen'
import { Toaster as Sonner } from '@/components/ui/sonner'
import { QueryClient, QueryClientProvider } from '@tanstack/react-query'

import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom'
import { AuthProvider } from '@/contexts/AuthContext'
import { AnalyticsProvider } from '@/components/analytics/AnalyticsProvider'
import ProtectedRoute from '@/components/auth/ProtectedRoute'
import AdminRoute from '@/features/auth/AdminRoute'
import { AIProvider } from '@/contexts/AIProvider'
const AIController = lazy(() => import('./features/ai/components/AIController'))

const AuthCallbackHandler = lazy(
  () => import('@/features/auth/AuthCallbackHandler'),
)
const MFAVerifyPage = lazy(() => import('@/features/auth/pages/MFAVerifyPage'))

import AppLayout from './components/ui/layout/AppLayout'
import MarketingLayout from './components/ui/layout/MarketingLayout'
import { ScrollToTop } from './components/utils/ScrollToTop'
import { GoogleAnalytics } from './components/analytics/GoogleAnalytics'
import { PageLoader } from '@/components/ui/PageLoader'

import { ErrorBoundary } from '@/components/ui/ErrorBoundary'
import { SkipToContent } from '@/components/a11y/SkipToContent'
import { InstallPrompt } from '@/components/pwa/InstallPrompt'
const OnboardingWizard = lazy(() =>
  import('@/components/onboarding/OnboardingWizard').then((m) => ({
    default: m.OnboardingWizard,
  })),
)
const AchievementNotifications = lazy(() =>
  import('@/components/onboarding/AchievementToast').then((m) => ({
    default: m.AchievementNotifications,
  })),
)

const ModernAIChat = lazy(() =>
  import('./components/ai/ModernAIChat').then((m) => ({
    default: m.ModernAIChat,
  })),
)
const CanvasPanel = lazy(() =>
  import('./components/ai/canvas/CanvasPanel').then((m) => ({
    default: m.CanvasPanel,
  })),
)

const Index = lazy(() => import('./pages/HomePage'))
const Login = lazy(() => import('@/features/auth/pages/Login'))
const Register = lazy(() => import('@/features/auth/pages/Register'))
const Resources = lazy(() => import('./pages/Resources'))
const Plans = lazy(() => import('./pages/Plans'))
const Blog = lazy(() => import('./pages/Blog'))
const BlogArticle = lazy(() => import('./pages/BlogArticle'))
const ForgotPassword = lazy(
  () => import('@/features/auth/pages/ForgotPassword'),
)
const UpdatePassword = lazy(
  () => import('@/features/auth/pages/UpdatePassword'),
)
const Dashboard = lazy(() => import('@/features/dashboard/pages/Dashboard'))
const BrideLoginPage = lazy(
  () => import('@/features/portal/pages/BrideLoginPage'),
)
const BrideDashboardPage = lazy(
  () => import('@/features/portal/pages/BrideDashboardPage'),
)
const BrideProtectedRoute = lazy(
  () => import('@/features/portal/components/BrideProtectedRoute'),
)
const FinancialPage = lazy(
  () => import('@/features/financial/pages/FinancialPage'),
)
const AdminDashboard = lazy(() => import('@/features/admin/AdminDashboard'))
const Clients = lazy(() => import('@/features/clients/pages/ClientsPage'))
const ClientDetails = lazy(
  () => import('@/features/clients/pages/ClientDetailsPage'),
)
const Projects = lazy(() => import('@/features/projects/pages/ProjectsPage'))
const ProjectDetails = lazy(
  () => import('@/features/projects/pages/ProjectDetailsPage'),
)
const Settings = lazy(() => import('./pages/Settings'))
const Contact = lazy(() => import('./pages/Contact'))
const Privacy = lazy(() => import('./pages/Privacy'))
const Terms = lazy(() => import('./pages/Terms'))
const AssistantsPage = lazy(
  () => import('@/features/assistants/pages/AssistantsPage'),
)
const Services = lazy(() => import('./pages/Services'))
const Marketing = lazy(() => import('./pages/Marketing'))
const Contracts = lazy(() => import('@/features/contracts/pages/Contracts'))
const ProjectContract = lazy(
  () => import('@/features/contracts/pages/ProjectContract'),
)
const NotFound = lazy(() => import('./pages/NotFound'))
const Refund = lazy(() => import('./pages/Refund'))
const Security = lazy(() => import('./pages/Security'))
const Cookies = lazy(() => import('./pages/Cookies'))
const DPA = lazy(() => import('./pages/DPA'))
const StudioCalendarPage = lazy(
  () => import('@/features/calendar/pages/StudioCalendarPage'),
)
const PublicBooking = lazy(
  () => import('@/features/public-booking/pages/PublicBooking'),
)
const Analytics = lazy(() => import('./pages/Analytics'))
const AcceptInvitePage = lazy(
  () => import('@/features/assistant-portal/pages/AcceptInvitePage'),
)
const AssistantDashboard = lazy(
  () => import('@/features/assistant-portal/pages/AssistantDashboard'),
)
const AssistantLayout = lazy(
  () => import('@/components/ui/layout/AssistantLayout'),
)
const UpgradePage = lazy(
  () => import('@/features/assistant-portal/pages/UpgradePage'),
)
const UpgradeSuccessPage = lazy(
  () => import('@/features/assistant-portal/pages/UpgradeSuccessPage'),
)
const UpgradeFailurePage = lazy(
  () => import('@/features/assistant-portal/pages/UpgradeFailurePage'),
)
const UpgradePendingPage = lazy(
  () => import('@/features/assistant-portal/pages/UpgradePendingPage'),
)
const CalendarPage = lazy(
  () => import('@/features/calendar/pages/CalendarPage'),
)
const GoogleCalendarCallback = lazy(
  () => import('@/pages/GoogleCalendarCallback'),
)
const SignContract = lazy(
  () => import('@/features/contracts/pages/SignContract'),
)
const LeaveReview = lazy(() => import('@/pages/LeaveReview'))
const Microsite = lazy(() => import('@/features/microsite/pages/Microsite'))
const MicrositeEditor = lazy(
  () => import('@/features/microsite/pages/MicrositeEditor'),
)
const SalesPipeline = lazy(
  () => import('@/features/pipeline/pages/SalesPipeline'),
)
const IntegrationsPage = lazy(() => import('./pages/Integrations'))
const AssistantQuickLogin = lazy(
  () => import('@/features/assistant-portal/pages/AssistantQuickLogin'),
)
const AssistantFreeDashboard = lazy(
  () => import('@/features/assistant-portal/pages/AssistantFreeDashboard'),
)
const StudioAvailabilityPage = lazy(
  () => import('@/features/calendar/pages/StudioAvailabilityPage'),
)

import '@/styles/calendar.css'

const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      staleTime: 5 * 60 * 1000,
      retry: 1,
      refetchOnWindowFocus: false,
    },
  },
})

function LazyPage({
  component: Component,
}: {
  component: React.ComponentType
}) {
  return (
    <Suspense fallback={<PageLoader />}>
      <Component />
    </Suspense>
  )
}

const App = () => {
  const [isLoading, setIsLoading] = useState(true)

  useEffect(() => {
    const timer = setTimeout(
      () => {
        setIsLoading(false)
      },
      window.innerWidth >= 768 ? 0 : 2500,
    )

    return () => clearTimeout(timer)
  }, [])

  if (isLoading) {
    return <SplashScreen />
  }

  return (
    <BrowserRouter>
      <Toaster />
      <Sonner />
      <InstallPrompt />
      <ScrollToTop />
      <GoogleAnalytics />
      <AuthProvider>
        <QueryClientProvider client={queryClient}>
          <AnalyticsProvider>
            <Suspense fallback={null}>
              <ModernAIChat />
              <CanvasPanel />
            </Suspense>
            <AIProvider>
              <div className="min-h-screen bg-[#050505] text-[#C0C0C0] selection:bg-white selection:text-black">
                <SkipToContent />
                <main id="main-content">
                  <ErrorBoundary>
                    <Suspense fallback={<PageLoader />}>
                      <Routes>
                        <Route
                          path="/"
                          element={<LazyPage component={Index} />}
                        />
                        <Route element={<MarketingLayout />}>
                          <Route
                            path="/recursos"
                            element={<LazyPage component={Resources} />}
                          />
                          <Route
                            path="/planos"
                            element={<LazyPage component={Plans} />}
                          />
                          <Route
                            path="/blog"
                            element={<LazyPage component={Blog} />}
                          />
                          <Route
                            path="/blog/:slug"
                            element={<LazyPage component={BlogArticle} />}
                          />
                          <Route
                            path="/contato"
                            element={<LazyPage component={Contact} />}
                          />
                          <Route
                            path="/privacidade"
                            element={<LazyPage component={Privacy} />}
                          />
                          <Route
                            path="/termos"
                            element={<LazyPage component={Terms} />}
                          />
                          <Route
                            path="/reembolso"
                            element={<LazyPage component={Refund} />}
                          />
                          <Route
                            path="/seguranca"
                            element={<LazyPage component={Security} />}
                          />
                          <Route
                            path="/cookies"
                            element={<LazyPage component={Cookies} />}
                          />
                          <Route
                            path="/dpa"
                            element={<LazyPage component={DPA} />}
                          />
                        </Route>

                        <Route
                          path="/login"
                          element={<LazyPage component={Login} />}
                        />
                        <Route
                          path="/register"
                          element={<LazyPage component={Register} />}
                        />
                        <Route path="/auth">
                          <Route
                            index
                            element={<Navigate to="/login" replace />}
                          />
                          <Route
                            path="login"
                            element={<Navigate to="/login" replace />}
                          />
                          <Route
                            path="register"
                            element={<Navigate to="/register" replace />}
                          />
                          <Route
                            path="mfa-verify"
                            element={<MFAVerifyPage />}
                          />
                        </Route>
                        <Route
                          path="/auth/callback"
                          element={<AuthCallbackHandler />}
                        />
                        <Route
                          path="/auth/forgot-password"
                          element={<LazyPage component={ForgotPassword} />}
                        />
                        <Route
                          path="/auth/update-password"
                          element={<LazyPage component={UpdatePassword} />}
                        />

                        <Route element={<AppLayout />}>
                          <Route element={<ProtectedRoute />}>
                            <Route
                              path="/dashboard"
                              element={<LazyPage component={Dashboard} />}
                            />
                            <Route
                              path="/dashboard/financial"
                              element={<LazyPage component={FinancialPage} />}
                            />
                            <Route
                              path="/analytics"
                              element={<LazyPage component={Analytics} />}
                            />

                            <Route element={<AdminRoute />}>
                              <Route
                                path="/admin"
                                element={
                                  <LazyPage component={AdminDashboard} />
                                }
                              />
                              <Route
                                path="/admin/users"
                                element={
                                  <Navigate to="/admin?tab=users" replace />
                                }
                              />
                              <Route
                                path="/admin/dashboard"
                                element={
                                  <Navigate to="/admin?tab=overview" replace />
                                }
                              />
                            </Route>

                            <Route
                              path="/calendar"
                              element={<LazyPage component={CalendarPage} />}
                            />
                            <Route
                              path="/calendar/callback"
                              element={
                                <LazyPage component={GoogleCalendarCallback} />
                              }
                            />
                            <Route
                              path="/studio"
                              element={<LazyPage component={StudioCalendarPage} />}
                            />

                            <Route
                              path="/clientes"
                              element={<LazyPage component={Clients} />}
                            />
                            <Route
                              path="/clientes/:id"
                              element={<LazyPage component={ClientDetails} />}
                            />
                            <Route
                              path="/projetos"
                              element={<LazyPage component={Projects} />}
                            />
                            <Route
                              path="/projetos/novo"
                              element={<LazyPage component={Projects} />}
                            />
                            <Route
                              path="/projetos/:id"
                              element={<LazyPage component={ProjectDetails} />}
                            />
                            <Route
                              path="/projects/:projectId/contract"
                              element={<LazyPage component={ProjectContract} />}
                            />
                            <Route
                              path="/configuracoes"
                              element={<LazyPage component={Settings} />}
                            />
                            <Route
                              path="/assistentes"
                              element={<LazyPage component={AssistantsPage} />}
                            />
                            <Route
                              path="/servicos"
                              element={<LazyPage component={Services} />}
                            />
                            <Route
                              path="/funil"
                              element={<LazyPage component={SalesPipeline} />}
                            />
                            <Route
                              path="/integracoes"
                              element={
                                <LazyPage component={IntegrationsPage} />
                              }
                            />
                            <Route
                              path="/contratos"
                              element={<LazyPage component={Contracts} />}
                            />
                            <Route
                              path="/marketing"
                              element={<LazyPage component={Marketing} />}
                            />
                          </Route>
                        </Route>

                        <Route
                          path="/assistant/accept/:token"
                          element={
                            <Navigate
                              to={window.location.pathname.replace(
                                '/assistant/accept/',
                                '/assistente/convite/',
                              )}
                              replace
                            />
                          }
                        />
                        <Route element={<ProtectedRoute />}>
                          <Route
                            path="/assistant"
                            element={<AssistantLayout />}
                          >
                            <Route
                              path="dashboard"
                              element={
                                <LazyPage component={AssistantDashboard} />
                              }
                            />
                            <Route
                              index
                              element={<Navigate to="dashboard" replace />}
                            />
                          </Route>
                        </Route>
                        <Route
                          path="/assistente/convite/:token"
                          element={<LazyPage component={AcceptInvitePage} />}
                        />
                        <Route
                          path="/upgrade"
                          element={<LazyPage component={UpgradePage} />}
                        />
                        <Route
                          path="/upgrade/success"
                          element={<LazyPage component={UpgradeSuccessPage} />}
                        />
                        <Route
                          path="/upgrade/failure"
                          element={<LazyPage component={UpgradeFailurePage} />}
                        />
                        <Route
                          path="/upgrade/pending"
                          element={<LazyPage component={UpgradePendingPage} />}
                        />
                        <Route
                          path="/b/:slug"
                          element={<LazyPage component={PublicBooking} />}
                        />

                        <Route
                          path="/agenda-equipa/:professionalId"
                          element={<LazyPage component={AssistantQuickLogin} />}
                        />
                        <Route
                          path="/agenda-equipa/:professionalId/dashboard"
                          element={
                            <LazyPage component={AssistantFreeDashboard} />
                          }
                        />
                        <Route
                          path="/agenda-equipa/:professionalId/disponibilidade"
                          element={
                            <LazyPage component={StudioAvailabilityPage} />
                          }
                        />

                        <Route
                          path="/assinar/:requestId"
                          element={<LazyPage component={SignContract} />}
                        />
                        <Route
                          path="/avaliar/:token"
                          element={<LazyPage component={LeaveReview} />}
                        />
                        <Route
                          path="/site/:slug"
                          element={<LazyPage component={Microsite} />}
                        />
                        <Route element={<ProtectedRoute />}>
                          <Route
                            path="/meu-site/editor"
                            element={<LazyPage component={MicrositeEditor} />}
                          />
                        </Route>
                        <Route
                          path="/portal/:clientId/login"
                          element={<LazyPage component={BrideLoginPage} />}
                        />
                        <Route element={<BrideProtectedRoute />}>
                          <Route
                            path="/portal/:clientId/dashboard"
                            element={
                              <LazyPage component={BrideDashboardPage} />
                            }
                          />
                        </Route>
                        <Route
                          path="*"
                          element={<LazyPage component={NotFound} />}
                        />
                        <Route
                          path="/404"
                          element={<LazyPage component={NotFound} />}
                        />
                      </Routes>
                    </Suspense>
                  </ErrorBoundary>
                </main>
              </div>
              <Suspense fallback={null}>
                <AIController />
                <AchievementNotifications />
              </Suspense>
            </AIProvider>
          </AnalyticsProvider>
        </QueryClientProvider>
      </AuthProvider>
    </BrowserRouter>
  )
}

export default App

import type { ComponentProps } from "react";

import {
  Card,
  CardAction,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import React, { Suspense } from "react";
import { cn } from "@/lib/utils";

const HandlePrimitive = React.lazy(() => import('@xyflow/react').then(m => ({ default: m.Handle })));

export type NodeProps = ComponentProps<typeof Card> & {
  handles: {
    target: boolean;
    source: boolean;
  };
};

export const Node = ({ handles, className, ...props }: NodeProps) => (
  <Card
    className={cn(
      "node-container relative size-full h-auto w-sm gap-0 rounded-md p-0",
      className
    )}
    {...props}
  >
    <Suspense fallback={null}>
      {handles.target && <HandlePrimitive position={"left" as any} type="target" />}
      {handles.source && <HandlePrimitive position={"right" as any} type="source" />}
    </Suspense>
    {props.children}
  </Card>
);

export type NodeHeaderProps = ComponentProps<typeof CardHeader>;

export const NodeHeader = ({ className, ...props }: NodeHeaderProps) => (
  <CardHeader
    className={cn("gap-0.5 rounded-t-md border-b bg-secondary p-3!", className)}
    {...props}
  />
);

export type NodeTitleProps = ComponentProps<typeof CardTitle>;

export const NodeTitle = (props: NodeTitleProps) => <CardTitle {...props} />;

export type NodeDescriptionProps = ComponentProps<typeof CardDescription>;

export const NodeDescription = (props: NodeDescriptionProps) => (
  <CardDescription {...props} />
);

export type NodeActionProps = ComponentProps<typeof CardAction>;

export const NodeAction = (props: NodeActionProps) => <CardAction {...props} />;

export type NodeContentProps = ComponentProps<typeof CardContent>;

export const NodeContent = ({ className, ...props }: NodeContentProps) => (
  <CardContent className={cn("p-3", className)} {...props} />
);

export type NodeFooterProps = ComponentProps<typeof CardFooter>;

export const NodeFooter = ({ className, ...props }: NodeFooterProps) => (
  <CardFooter
    className={cn("rounded-b-md border-t bg-secondary p-3!", className)}
    {...props}
  />
);

import React, { memo, useState, useMemo, useCallback } from 'react'
import { cn } from '@/lib/utils'
import { logger } from '@/services/logger'
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from '@/components/ui/collapsible'
import {
  MessageCircleCode,
  CheckCircle2,
  XCircle,
  Clock,
  AlertCircle,
  CheckCircle,
  CircleDashed,
} from 'lucide-react'
import { Spinner } from '@/components/ui/PageLoader'
import { Button } from '@/components/ui/button'
import {
  ToolInvocationStatusPending,
  ToolInvocationStatusInProgress,
  ToolInvocationStatusAwaitingInput,
  ToolInvocationStatusAwaitingApproval,
  ToolInvocationStatusCompleted,
  ToolInvocationStatusFailed,
  ToolInvocationStatusCancelled,
  ToolTypeApp,
} from '@inferencesh/sdk'
import {
  useAgentActions,
  useAgentClient,
  type ToolInvocationDTO,
  type UploadedFile,
} from '@inferencesh/sdk/agent'
import { WidgetRenderer } from '@/components/infsh/agent/widget-renderer'
import {
  parseWidget,
  type WidgetAction,
  type WidgetFormData,
} from '@/components/infsh/agent/widget-types'
import { TaskOutputWrapper } from '@/components/infsh/task/task-output-wrapper'

const ToolFinishStatusSucceeded = 'succeeded'
const ToolFinishStatusFailed = 'failed'
const ToolFinishStatusCancelled = 'cancelled'

interface ToolFinish {
  status: string
  result?: unknown
  error?: string
}

interface ToolInvocationProps {
  invocation: ToolInvocationDTO
  className?: string
  defaultOpen?: boolean
}

const FinishBlock = memo(function FinishBlock({
  finish,
  isActive = false,
}: {
  finish?: ToolFinish | null
  isActive?: boolean
}) {
  const getStatusIcon = () => {
    if (isActive) {
      return <Spinner className="size-3.5" />
    }
    switch (finish?.status) {
      case ToolFinishStatusSucceeded:
        return <CheckCircle className="h-3.5 w-3.5 text-emerald-400" />
      case ToolFinishStatusFailed:
        return <XCircle className="h-3.5 w-3.5 text-red-400" />
      case ToolFinishStatusCancelled:
        return <CircleDashed className="h-3.5 w-3.5 text-muted-foreground" />
      default:
        return <CheckCircle className="h-3.5 w-3.5 text-emerald-400" />
    }
  }

  const getStatusText = () => {
    if (isActive) return 'finishing'
    switch (finish?.status) {
      case ToolFinishStatusSucceeded:
        return 'completed'
      case ToolFinishStatusFailed:
        return 'failed'
      case ToolFinishStatusCancelled:
        return 'cancelled'
      default:
        return 'completed'
    }
  }

  const getLineColor = () => {
    switch (finish?.status) {
      case ToolFinishStatusFailed:
        return 'bg-red-400/30'
      case ToolFinishStatusCancelled:
        return 'bg-muted-foreground/30'
      default:
        return 'bg-muted-foreground/20'
    }
  }

  const resultMessage =
    finish?.result && typeof finish.result === 'string' && !isActive
      ? finish.result.toLowerCase()
      : null

  return (
    <div className="my-6 w-full">
      <div className="flex items-center gap-4 w-full">
        <div className={cn('flex-1 h-px', getLineColor())} />
        <div
          className={cn(
            'flex items-center gap-2 text-muted-foreground/50',
            isActive && 'animate-pulse',
          )}
        >
          {getStatusIcon()}
          <span className="text-xs font-medium">{getStatusText()}</span>
        </div>
        <div className={cn('flex-1 h-px', getLineColor())} />
      </div>
      {resultMessage && (
        <p className="text-xs text-muted-foreground/40 text-center mt-2 break-words">
          {resultMessage}
        </p>
      )}
    </div>
  )
})

export const ToolInvocation = memo(function ToolInvocation({
  invocation,
  className,
  defaultOpen = false,
}: ToolInvocationProps) {
  const widget = useMemo(() => {
    if (invocation.widget) {
      return parseWidget(invocation.widget)
    }
    if (invocation.result) {
      return parseWidget(invocation.result)
    }
    return null
  }, [invocation.widget, invocation.result])

  const isAwaitingApprovalStatus =
    invocation.status === ToolInvocationStatusAwaitingApproval
  const [isOpen, setIsOpen] = useState(
    defaultOpen || isAwaitingApprovalStatus || !!widget,
  )

  const {
    submitToolResult,
    approveTool,
    rejectTool,
    alwaysAllowTool,
    sendMessage,
  } = useAgentActions()
  const client = useAgentClient()

  const functionName = invocation.function?.name || 'tool'

  const status = invocation.status
  const isActive =
    status === ToolInvocationStatusInProgress ||
    status === ToolInvocationStatusAwaitingInput ||
    status === ToolInvocationStatusPending

  const isAppTool = invocation.type === ToolTypeApp

  const taskId = useMemo(() => {
    if (invocation.execution_id) {
      return invocation.execution_id
    }

    if (isAppTool && typeof invocation.result === 'string') {
      const match = invocation.result.match(/^Task\s+([a-z0-9]+)\s+/)
      if (match) {
        return match[1]
      }
    }
    return null
  }, [invocation.execution_id, invocation.result, isAppTool])

  const hasTaskOutput = isAppTool && taskId

  const isFinishTool = functionName === 'finish'

  const finishData = useMemo((): ToolFinish | null => {
    if (!isFinishTool) return null

    if (invocation.data) {
      try {
        const data =
          typeof invocation.data === 'string'
            ? JSON.parse(invocation.data)
            : invocation.data
        if (data && typeof data.status === 'string') {
          return data as ToolFinish
        }
      } catch {}
    }

    if (invocation.function?.arguments) {
      const args = invocation.function.arguments
      if (args.status && typeof args.status === 'string') {
        return {
          status: args.status as string,
          result: args.result as string | undefined,
        }
      }
    }

    return null
  }, [isFinishTool, invocation.data, invocation.function?.arguments])

  const statusIcon = useMemo(() => {
    switch (status) {
      case ToolInvocationStatusPending:
      case ToolInvocationStatusInProgress:
        return <Spinner className="size-3" />
      case ToolInvocationStatusAwaitingInput:
      case ToolInvocationStatusAwaitingApproval:
        return <Clock className="h-3 w-3" />
      case ToolInvocationStatusCompleted:
        return <CheckCircle2 className="h-3 w-3 text-emerald-400" />
      case ToolInvocationStatusFailed:
        return <AlertCircle className="h-3 w-3 text-red-400" />
      case ToolInvocationStatusCancelled:
        return <XCircle className="h-3 w-3 text-muted-foreground" />
      default:
        return <MessageCircleCode className="h-3 w-3" />
    }
  }, [status])

  const statusText = useMemo(() => {
    switch (status) {
      case ToolInvocationStatusPending:
        return 'pending'
      case ToolInvocationStatusInProgress:
        return 'running'
      case ToolInvocationStatusAwaitingInput:
        return 'awaiting input'
      case ToolInvocationStatusAwaitingApproval:
        return 'awaiting approval'
      case ToolInvocationStatusCompleted:
        return 'completed'
      case ToolInvocationStatusFailed:
        return 'failed'
      case ToolInvocationStatusCancelled:
        return 'cancelled'
      default:
        return ''
    }
  }, [status])

  const handleWidgetAction = useCallback(
    async (action: WidgetAction, formData?: WidgetFormData) => {
      const isAwaitingInput = status === ToolInvocationStatusAwaitingInput

      if (isAwaitingInput) {
        if (!submitToolResult) return
        try {
          await submitToolResult(
            invocation.id,
            JSON.stringify({ action, form_data: formData }),
          )
        } catch (error) {
          logger.error(
            '[ToolInvocation] Failed to submit widget action:',
            error,
          )
        }
      } else {
        if (!sendMessage) return
        try {
          const actionText =
            action.payload?.message || action.payload?.text || action.type

          const files: UploadedFile[] = []
          if (action.payload?.image_uri) {
            files.push({
              uri: action.payload.image_uri as string,
              content_type: 'image/png',
            })
          }
          await sendMessage(
            String(actionText),
            files.length > 0 ? files : undefined,
          )
        } catch (error) {
          logger.error(
            '[ToolInvocation] Failed to send widget action as message:',
            error,
          )
        }
      }
    },
    [invocation.id, status, submitToolResult, sendMessage],
  )

  const handleApprove = useCallback(async () => {
    try {
      await approveTool(invocation.id)
    } catch (error) {
      logger.error('[ToolInvocation] Failed to approve:', error)
    }
  }, [invocation.id, approveTool])

  const handleReject = useCallback(async () => {
    try {
      await rejectTool(invocation.id)
    } catch (error) {
      logger.error('[ToolInvocation] Failed to reject:', error)
    }
  }, [invocation.id, rejectTool])

  const handleAlwaysAllow = useCallback(async () => {
    try {
      await alwaysAllowTool(invocation.id, functionName)
    } catch (error) {
      logger.error('[ToolInvocation] Failed to always-allow:', error)
    }
  }, [invocation.id, functionName, alwaysAllowTool])

  const hasArgs =
    invocation.function?.arguments &&
    Object.keys(invocation.function.arguments).length > 0
  const hasResult = !!invocation.result && !widget && !hasTaskOutput

  const isWidgetInteractive =
    status === ToolInvocationStatusAwaitingInput ||
    status === ToolInvocationStatusCompleted

  if (isFinishTool && (finishData || isActive)) {
    return <FinishBlock finish={finishData} isActive={isActive} />
  }

  if (isAwaitingApprovalStatus) {
    if (widget) {
      return (
        <div className={cn('flex flex-col items-start', className)}>
          <WidgetRenderer
            widget={widget}
            onAction={handleWidgetAction}
            className="max-w-md"
          />
        </div>
      )
    }

    return (
      <div className={cn('flex flex-col items-start', className)}>
        <div className="overflow-hidden rounded border bg-muted/10">
          <div className="flex items-center gap-1.5 px-2 py-1.5 text-xs text-muted-foreground">
            {statusIcon}
            <span className="lowercase">
              {functionName} {statusText}
            </span>
          </div>

          {hasArgs && (
            <div className="border-t px-2 py-1.5 text-xs">
              <div className="text-muted-foreground/50 mb-1">arguments:</div>
              <pre className="text-muted-foreground whitespace-pre-wrap overflow-y-auto max-h-[150px]">
                {JSON.stringify(invocation.function?.arguments, null, 2)}
              </pre>
            </div>
          )}

          <div className="flex items-center justify-end gap-2 border-t px-2 py-1.5">
            <Button
              size="sm"
              variant="ghost"
              className="h-6 px-2 text-xs text-muted-foreground hover:text-foreground"
              onClick={handleReject}
            >
              skip
            </Button>
            <Button
              size="sm"
              variant="ghost"
              className="h-6 px-2 text-xs text-emerald-400 hover:text-emerald-400/80 hover:bg-emerald-400/10"
              onClick={handleApprove}
            >
              allow
            </Button>
            <Button
              size="sm"
              variant="ghost"
              className="h-6 px-2 text-xs text-blue-400 hover:text-blue-400/80 hover:bg-blue-400/10"
              onClick={handleAlwaysAllow}
            >
              always allow
            </Button>
          </div>
        </div>
      </div>
    )
  }

  if (hasTaskOutput) {
    return (
      <div className={cn('flex flex-col items-start', className)}>
        <Collapsible
          open={isOpen}
          onOpenChange={setIsOpen}
          className={cn(
            'group w-full overflow-hidden rounded text-muted-foreground',
            isOpen && 'border bg-muted/10',
          )}
        >
          <div className="flex items-center px-1 py-0.5">
            <CollapsibleTrigger asChild>
              <button className="flex items-center gap-1.5 text-xs text-muted-foreground/50 hover:text-muted-foreground cursor-pointer">
                {statusIcon}
                <span className={cn('lowercase', isActive && 'animate-pulse')}>
                  {functionName} {statusText}
                </span>
              </button>
            </CollapsibleTrigger>
          </div>
          <CollapsibleContent>
            <div className="border-t p-2">
              <TaskOutputWrapper
                client={client}
                taskId={taskId!}
                compact={true}
              />
            </div>
          </CollapsibleContent>
        </Collapsible>
      </div>
    )
  }

  if (widget) {
    return (
      <div className={cn('flex flex-col items-start flex-grow-0', className)}>
        <WidgetRenderer
          widget={widget}
          onAction={handleWidgetAction}
          disabled={!isWidgetInteractive}
        />
      </div>
    )
  }

  return (
    <div className={cn('flex flex-col items-start w-fit', className)}>
      <Collapsible
        open={isOpen}
        onOpenChange={setIsOpen}
        className={cn(
          'group w-full overflow-hidden rounded text-muted-foreground',
          isOpen && 'border bg-muted/10',
        )}
      >
        <div className="flex items-center px-1 py-0.5">
          <CollapsibleTrigger asChild>
            <button className="flex items-center gap-1.5 text-xs text-muted-foreground/50 hover:text-muted-foreground cursor-pointer">
              {statusIcon}
              <span className={cn('lowercase', isActive && 'animate-pulse')}>
                {functionName} {statusText}
              </span>
            </button>
          </CollapsibleTrigger>
        </div>
        <CollapsibleContent>
          <div className="border-t px-2 py-1.5 text-xs space-y-1.5">
            {hasArgs && (
              <div>
                <div className="text-muted-foreground/50 mb-1">arguments:</div>
                <pre className="text-muted-foreground whitespace-pre-wrap overflow-y-auto max-h-[150px]">
                  {JSON.stringify(invocation.function?.arguments, null, 2)}
                </pre>
              </div>
            )}
            {hasResult && (
              <div>
                <div className="text-muted-foreground/50 mb-1">result:</div>
                <pre className="text-foreground whitespace-pre-wrap overflow-y-auto max-h-[150px]">
                  {typeof invocation.result === 'string'
                    ? invocation.result
                    : JSON.stringify(invocation.result, null, 2)}
                </pre>
              </div>
            )}
          </div>
        </CollapsibleContent>
      </Collapsible>
    </div>
  )
})

