import React from 'react'
import { motion, Variants } from 'framer-motion'

export interface SplitTextProps {
  text: string
  className?: string
  delay?: number
  duration?: number
  ease?: string | number[]
  splitType?: 'chars' | 'words' | 'lines'
  from?: Record<string, any>
  to?: Record<string, any>
  threshold?: number
  rootMargin?: string
  tag?: 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6' | 'p' | 'span'
  textAlign?: React.CSSProperties['textAlign']
  onLetterAnimationComplete?: () => void
}

const SplitText: React.FC<SplitTextProps> = ({
  text,
  className = '',
  delay = 50,
  duration = 0.5,
  ease = 'easeOut',
  splitType = 'chars',
  from = { opacity: 0, y: 20 },
  to = { opacity: 1, y: 0 },
  threshold = 0.1,
  tag = 'p',
  textAlign = 'center',
  onLetterAnimationComplete,
}) => {
  const Tag = motion[tag] as any

  const variants: Variants = {
    hidden: from,
    visible: (i: number) => ({
      ...to,
      transition: {
        delay: (i * delay) / 1000,
        duration: duration,
        ease: ease,
      },
    }),
  }

  const renderContent = () => {
    if (splitType === 'words') {
      return text.split(' ').map((word, i) => (
        <span key={i} className="inline-block whitespace-nowrap">
          <motion.span
            custom={i}
            variants={variants}
            initial="hidden"
            whileInView="visible"
            viewport={{ once: true, amount: threshold }}
            onAnimationComplete={
              i === text.split(' ').length - 1
                ? onLetterAnimationComplete
                : undefined
            }
            className="inline-block"
          >
            {word}
          </motion.span>
          <span className="inline-block">&nbsp;</span>
        </span>
      ))
    }

    if (splitType === 'chars') {
      return text.split('').map((char, i) => (
        <motion.span
          key={i}
          custom={i}
          variants={variants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, amount: threshold }}
          onAnimationComplete={
            i === text.length - 1 ? onLetterAnimationComplete : undefined
          }
          className="inline-block"
        >
          {char === ' ' ? '\u00A0' : char}
        </motion.span>
      ))
    }

    return text.split('\n').map((line, i) => (
      <motion.span
        key={i}
        custom={i}
        variants={variants}
        initial="hidden"
        whileInView="visible"
        viewport={{ once: true, amount: threshold }}
        className="block"
      >
        {line}
      </motion.span>
    ))
  }

  return (
    <Tag
      className={`inline-block overflow-hidden ${className}`}
      style={{ textAlign, width: '100%' }}
    >
      {renderContent()}
    </Tag>
  )
}

export default SplitText

import React from 'react'

interface ErrorBoundaryProps {
  children: React.ReactNode
  fallback?: React.ReactNode
}

interface ErrorBoundaryState {
  hasError: boolean
  error: Error | null
}

export class ErrorBoundary extends React.Component<
  ErrorBoundaryProps,
  ErrorBoundaryState
> {
  constructor(props: ErrorBoundaryProps) {
    super(props)
    this.state = { hasError: false, error: null }
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error }
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {}

  render() {
    if (this.state.hasError) {
      if (this.props.fallback) return this.props.fallback

      return (
        <div className="flex items-center justify-center min-h-[50vh]">
          <div className="text-center p-8 max-w-md">
            <h2 className="text-xl font-semibold mb-2">Algo deu errado</h2>
            <p className="text-muted-foreground mb-4">
              {this.state.error?.message || 'Erro inesperado'}
            </p>
            <button
              onClick={() => window.location.reload()}
              className="px-4 py-2 bg-primary text-primary-foreground rounded-md hover:opacity-90"
            >
              Recarregar
            </button>
          </div>
        </div>
      )
    }

    return this.props.children
  }
}

export default ErrorBoundary

import { useEffect, useState, useRef } from 'react'
import { Loader2, Navigation, MapPin } from 'lucide-react'
import { cn } from '@/lib/utils'
import { supabase } from '@/integrations/supabase/client'
import { Input } from '@/components/ui/input'
import { logger } from '@/services/logger'

interface AddressAutocompleteProps {
  value: string
  onChange: (value: string) => void
  onCoordinatesChange?: (lat: number | null, lng: number | null) => void
  onFocus?: () => void
  onBlur?: () => void
  placeholder?: string
  className?: string
  showMiniMap?: boolean
  latitude?: number | null
  longitude?: number | null
}

interface PlaceSuggestion {
  description: string
  place_id: string
}

function useDebounce<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState<T>(value)
  useEffect(() => {
    const handler = setTimeout(() => setDebouncedValue(value), delay)
    return () => clearTimeout(handler)
  }, [value, delay])
  return debouncedValue
}

function getGPSDeepLink(
  address: string,
  lat?: number | null,
  lng?: number | null,
): string {
  const userAgent = navigator.userAgent.toLowerCase()
  const isIOS = /iphone|ipad|ipod/.test(userAgent)
  const isAndroid = /android/.test(userAgent)
  if (lat && lng) {
    if (isIOS) return `maps:///?daddr=${lat},${lng}&dirflg=d`
    if (isAndroid) return `geo:${lat},${lng}?q=${lat},${lng}`
    return `https://www.google.com/maps/dir/?api=1&destination=${lat},${lng}`
  }
  const encoded = encodeURIComponent(address)
  if (isIOS) return `maps:///?daddr=${encoded}&dirflg=d`
  if (isAndroid) return `geo:0,0?q=${encoded}`
  return `https://www.google.com/maps/dir/?api=1&destination=${encoded}`
}

export function AddressAutocomplete({
  value,
  onChange,
  onCoordinatesChange,
  onFocus,
  onBlur,
  placeholder = 'Digite o endere├ºo...',
  className,
  latitude,
  longitude,
}: AddressAutocompleteProps) {
  const [inputValue, setInputValue] = useState(value)
  const [suggestions, setSuggestions] = useState<PlaceSuggestion[]>([])
  const [loading, setLoading] = useState(false)
  const [showSuggestions, setShowSuggestions] = useState(false)
  const [coords, setCoords] = useState<{ lat: number; lng: number } | null>(
    latitude && longitude ? { lat: latitude, lng: longitude } : null,
  )

  const containerRef = useRef<HTMLDivElement>(null)
  const debouncedSearch = useDebounce(inputValue, 500)

  useEffect(() => {
    if (value !== inputValue) {
      setInputValue(value)
    }
  }, [value])

  useEffect(() => {
    if (latitude && longitude) setCoords({ lat: latitude, lng: longitude })
  }, [latitude, longitude])

  useEffect(() => {
    if (
      !window.google &&
      !document.querySelector('script[src*="maps.googleapis.com/maps/api/js"]')
    ) {
      const script = document.createElement('script')
      const apiKey = import.meta.env.VITE_GOOGLE_MAPS_API_KEY

      if (!apiKey) {
        logger.error(
          'VITE_GOOGLE_MAPS_API_KEY missing',
          'AddressAutocomplete.loadScript',
          { showToast: false },
        )
        return
      }

      script.src = `https://maps.googleapis.com/maps/api/js?key=${apiKey}&libraries=places`
      script.async = true
      script.defer = true
      document.body.appendChild(script)
    }
  }, [])

  useEffect(() => {
    const searchPlaces = async () => {
      if (!debouncedSearch || debouncedSearch === value) {
        setSuggestions([])
        return
      }

      if (!window.google || !window.google.maps || !window.google.maps.places) {
        return
      }

      setLoading(true)
      try {
        const autocompleteService =
          new window.google.maps.places.AutocompleteService()

        autocompleteService.getPlacePredictions(
          {
            input: debouncedSearch,
            language: 'pt-BR',
            componentRestrictions: { country: 'br' },
          },
          (predictions, status) => {
            if (
              status === google.maps.places.PlacesServiceStatus.OK &&
              predictions
            ) {
              setSuggestions(predictions)
              setShowSuggestions(true)
            } else {
              setSuggestions([])
            }
            setLoading(false)
          },
        )
      } catch (err) {
        logger.error(err, 'AddressAutocomplete.searchPlaces', {
          showToast: false,
        })
        setLoading(false)
      }
    }

    searchPlaces()
  }, [debouncedSearch, value])

  const handleSelect = async (place: PlaceSuggestion) => {
    setInputValue(place.description)
    onChange(place.description)
    setShowSuggestions(false)

    try {
      const typedSupabase = supabase
      const { data: cached } = await typedSupabase
        .from('geo_cache')
        .select('response')
        .eq('query', place.place_id)
        .maybeSingle()

      if (cached?.response) {
        const responseData = cached.response as {
          geometry: { location: { lat: number; lng: number } }
        }
        const location = responseData.geometry.location
        if (onCoordinatesChange) onCoordinatesChange(location.lat, location.lng)
        setCoords({ lat: location.lat, lng: location.lng })
        return
      }

      if (window.google && window.google.maps && window.google.maps.places) {
        setLoading(true)
        const placesService = new window.google.maps.places.PlacesService(
          document.createElement('div'),
        )

        placesService.getDetails(
          { placeId: place.place_id, fields: ['geometry'] },
          async (result, status) => {
            setLoading(false)
            if (
              status === window.google.maps.places.PlacesServiceStatus.OK &&
              result?.geometry?.location
            ) {
              const lat = result.geometry.location.lat()
              const lng = result.geometry.location.lng()

              if (onCoordinatesChange) onCoordinatesChange(lat, lng)
              setCoords({ lat, lng })

              const cachePayload = {
                geometry: {
                  location: { lat, lng },
                },
              }

              const expiresAt = new Date()
              expiresAt.setDate(expiresAt.getDate() + 30)

              const typedSupabase = supabase
              await typedSupabase.from('geo_cache').upsert({
                query: place.place_id,
                response: cachePayload,
                expires_at: expiresAt.toISOString(),
              })
            }
          },
        )
      }
    } catch (err) {
      logger.error(err, 'AddressAutocomplete.handleSelect', {
        showToast: false,
      })
    }
  }

  const handleOpenGPS = (e: React.MouseEvent) => {
    e.stopPropagation()
    if (value) {
      window.open(getGPSDeepLink(value, coords?.lat, coords?.lng), '_blank')
    }
  }

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (
        containerRef.current &&
        !containerRef.current.contains(event.target as Node)
      ) {
        setShowSuggestions(false)
      }
    }
    document.addEventListener('mousedown', handleClickOutside)
    return () => document.removeEventListener('mousedown', handleClickOutside)
  }, [])

  return (
    <div ref={containerRef} className={cn('relative space-y-2', className)}>
      <div className="relative">
        <Input
          value={inputValue}
          onChange={(e) => {
            setInputValue(e.target.value)
            setShowSuggestions(true)
          }}
          onFocus={() => {
            onFocus?.()
            if (suggestions.length > 0) setShowSuggestions(true)
          }}
          onBlur={onBlur}
          placeholder={placeholder}
          className="bg-white/5 border-white/10 text-white placeholder:text-white/30 rounded-none pr-10 focus-visible:ring-0 focus-visible:border-[#00e5ff]/50 transition-colors"
        />
        {loading && (
          <div className="absolute right-3 top-2.5">
            <Loader2 className="h-4 w-4 animate-spin text-white/50" />
          </div>
        )}
      </div>

      {showSuggestions && suggestions.length > 0 && (
        <ul className="absolute z-[9999] w-full bg-[#1A1A1A] border border-white/10 shadow-xl max-h-60 overflow-y-auto rounded-none top-full mt-1">
          {suggestions.map((suggestion) => (
            <li
              key={suggestion.place_id}
              onClick={() => handleSelect(suggestion)}
              className="px-4 py-3 text-sm text-white/80 hover:bg-white/5 hover:text-white cursor-pointer flex items-center gap-3 transition-colors border-b border-white/5 last:border-0"
            >
              <MapPin className="h-4 w-4 text-white/40 shrink-0" />
              <span>{suggestion.description}</span>
            </li>
          ))}
        </ul>
      )}

      {value && (
        <div className="flex justify-end">
          <button
            type="button"
            onClick={handleOpenGPS}
            className="flex items-center gap-2 text-[10px] uppercase tracking-widest text-neutral-400 hover:text-white transition-colors"
          >
            <Navigation className="h-3 w-3" />
            Abrir no GPS
          </button>
        </div>
      )}
    </div>
  )
}

import React, { useState, useEffect, ReactNode } from 'react'
import { supabase } from '@/integrations/supabase/client'
import { logger } from '@/services/logger'
import { useAuth } from '@/hooks/useAuth'

import { AIContext, AIProviderContextType, AIProviderMode } from './AIContext'

export function AIProvider({ children }: { children: ReactNode }) {
  const { user } = useAuth()
  const [mode, setMode] = useState<AIProviderMode>('cloud')
  const [byokSettings, setByokSettings] =
    useState<AIProviderContextType['byokSettings']>(null)
  const [isLoading, setIsLoading] = useState(true)

  const fetchSettings = async () => {
    if (!user) {
      setByokSettings(null)
      setIsLoading(false)
      return
    }

    try {
      const { data, error } = await supabase
        .from('user_ai_settings')
        .select('*')
        .eq('user_id', user.id)
        .maybeSingle()

      if (error) throw error

      if (data) {
        setByokSettings({
          provider: data.provider,
          apiKey: data.api_key || '',
          modelName: data.model_name || '',
        })
      } else {
        setByokSettings(null)
      }
    } catch (err) {
      logger.error('[AIProvider] Error fetching settings:', err)
    } finally {
      setIsLoading(false)
    }
  }

  useEffect(() => {
    fetchSettings()
  }, [user])

  const value = {
    mode,
    setMode,
    byokSettings,
    isLoading,
    refreshSettings: fetchSettings,
  }

  return <AIContext.Provider value={value}>{children}</AIContext.Provider>
}

