import { useEffect, useState } from 'react'
import { supabase } from '@/integrations/supabase/client'
import { logger } from '@/services/logger'
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Trash2, AlertTriangle } from 'lucide-react'
import { useToast } from '@/hooks/use-toast'
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog'
import { Avatar, AvatarFallback } from '@/components/ui/avatar'

interface AssistantProfile {
  id: string
  email: string
  full_name: string
  created_at: string
  role: string
  connections: {
    professional_name: string
    professional_email: string
  }[]
}

export default function AdminAssistants() {
  const { toast } = useToast()
  const [assistants, setAssistants] = useState<AssistantProfile[]>([])
  const [loading, setLoading] = useState(true)
  const [deleteId, setDeleteId] = useState<string | null>(null)

  useEffect(() => {
    fetchAssistants()

    const channel = supabase
      .channel('admin-assistants-channel')
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'profiles',
          filter: 'role=eq.assistant',
        },
        () => {
          logger.info('Real-time event on assistant profiles')
          fetchAssistants()
        },
      )
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'assistant_access' },
        () => {
          logger.info('Real-time event on assistant connections')
          fetchAssistants()
        },
      )
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [])

  const fetchAssistants = async () => {
    setLoading(true)
    try {
      const { data: profiles, error: profileError } = await supabase
        .from('profiles')
        .select('*')
        .eq('role', 'assistant')

      if (profileError) throw profileError

      const enriched = await Promise.all(
        profiles.map(async (p) => {
          const { data: connections } = await supabase
            .from('assistant_access')
            .select('makeup_artist_id')
            .eq('assistant_id', p.id)

          const connectedPros = []
          if (connections && connections.length > 0) {
            const proIds = connections.map((c) => c.makeup_artist_id)
            const { data: pros } = await supabase
              .from('profiles')
              .select('full_name, email')
              .in('id', proIds)
            if (pros)
              connectedPros.push(
                ...pros.map((pro) => ({
                  professional_name: pro.full_name || 'Desconhecido',
                  professional_email: pro.email || '',
                })),
              )
          }

          return {
            ...p,
            connections: connectedPros,
          }
        }),
      )

      setAssistants(enriched)
    } catch (error) {
      logger.error(error, 'AdminAssistants.fetchAssistants', {
        showToast: false,
      })
      toast({
        title: 'Erro ao carregar assistentes',
        variant: 'destructive',
      })
    } finally {
      setLoading(false)
    }
  }

  const handleDelete = async () => {
    if (!deleteId) return

    try {
      const { error: connError } = await supabase
        .from('assistant_access')
        .delete()
        .eq('assistant_id', deleteId)

      if (connError) throw connError

      const { error: profError } = await supabase
        .from('profiles')
        .delete()
        .eq('id', deleteId)

      if (profError) throw profError

      setAssistants((prev) => prev.filter((a) => a.id !== deleteId))
      toast({
        title: 'Assistente removida',
        description: 'O cadastro e todos os v├¡nculos foram apagados.',
      })
    } catch (error) {
      logger.error(error, 'AdminAssistants.handleDelete', { showToast: false })
      toast({
        title: 'Erro ao excluir',
        description:
          'N├úo foi poss├¡vel remover, verifique se existem outros registros dependentes.',
        variant: 'destructive',
      })
    } finally {
      setDeleteId(null)
    }
  }

  if (loading) {
    return (
      <div className="p-8 text-center text-gray-500 font-mono text-xs uppercase animate-pulse">
        Carregando Assistentes...
      </div>
    )
  }

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-xl font-serif text-white">Gest├úo de Assistentes</h2>
        <Badge
          variant="outline"
          className="font-mono text-xs border-white/20 text-white"
        >
          {assistants.length} Cadastrados
        </Badge>
      </div>

      <div className="border border-white/10 rounded-none bg-black overflow-hidden">
        <Table>
          <TableHeader className="bg-white/5">
            <TableRow className="border-white/10 hover:bg-transparent">
              <TableHead className="text-gray-500 font-mono text-[10px] uppercase">
                Assistente
              </TableHead>
              <TableHead className="text-gray-500 font-mono text-[10px] uppercase">
                V├¡nculos (Maquiadoras)
              </TableHead>
              <TableHead className="text-right text-gray-500 font-mono text-[10px] uppercase">
                A├º├Áes
              </TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {assistants.map((assistant) => (
              <TableRow
                key={assistant.id}
                className="border-white/5 hover:bg-white/5"
              >
                <TableCell>
                  <div className="flex items-center gap-3">
                    <Avatar className="h-8 w-8 rounded-none border border-white/10">
                      <AvatarFallback className="bg-white/10 text-white text-xs">
                        {assistant.full_name?.charAt(0)}
                      </AvatarFallback>
                    </Avatar>
                    <div>
                      <div className="text-white font-medium text-sm">
                        {assistant.full_name}
                      </div>
                      <div className="text-gray-500 text-xs">
                        {assistant.email}
                      </div>
                    </div>
                  </div>
                </TableCell>
                <TableCell>
                  <div className="flex flex-col gap-1">
                    {assistant.connections.length > 0 ? (
                      assistant.connections.map((conn, idx) => (
                        <Badge
                          key={idx}
                          variant="outline"
                          className="w-fit border-white/10 text-gray-400 font-mono text-[10px]"
                        >
                          {conn.professional_name}
                        </Badge>
                      ))
                    ) : (
                      <span className="text-gray-600 text-xs italic">
                        Sem v├¡nculos
                      </span>
                    )}
                  </div>
                </TableCell>
                <TableCell className="text-right">
                  <Button
                    variant="ghost"
                    size="sm"
                    className="text-red-500 hover:text-red-400 hover:bg-red-950/30 rounded-none"
                    onClick={() => setDeleteId(assistant.id)}
                  >
                    <Trash2 className="h-4 w-4" />
                  </Button>
                </TableCell>
              </TableRow>
            ))}
            {assistants.length === 0 && (
              <TableRow>
                <TableCell
                  colSpan={3}
                  className="text-center py-12 text-gray-500"
                >
                  Nenhuma assistente encontrada.
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </div>

      <AlertDialog open={!!deleteId} onOpenChange={() => setDeleteId(null)}>
        <AlertDialogContent className="bg-black border border-white/20 rounded-none">
          <AlertDialogHeader>
            <AlertDialogTitle className="text-white flex items-center gap-2">
              <AlertTriangle className="text-red-500 h-5 w-5" />
              Excluir Cadastro?
            </AlertDialogTitle>
            <AlertDialogDescription className="text-gray-400">
              Esta a├º├úo remover├í a assistente de <strong>todas</strong> as
              agendas conectadas. O acesso dela ser├í revogado imediatamente.
              <br />
              <br />
              <span className="text-xs font-mono uppercase text-red-500">
                A├º├úo irrevers├¡vel.
              </span>
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel className="rounded-none bg-transparent border-white/20 text-white hover:bg-white/10">
              Cancelar
            </AlertDialogCancel>
            <AlertDialogAction
              onClick={handleDelete}
              className="rounded-none bg-red-600 text-white hover:bg-red-700 font-bold uppercase tracking-widest"
            >
              Confirmar Exclus├úo
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { Card, CardContent } from '@/components/ui/card'
import { logger } from '@/services/logger'
import { Button } from '@/components/ui/button'
import { CreditCard, Users, TrendingUp, Download, Loader2 } from 'lucide-react'
import { supabase } from '@/integrations/supabase/client'
import { exportMonthlyClosing } from '@/services/reportService'
import { format } from 'date-fns/format'
import { startOfMonth } from 'date-fns/startOfMonth'
import { endOfMonth } from 'date-fns/endOfMonth'
import { ptBR } from 'date-fns/locale'
import {
  CommissionTable,
  AssistantCommission,
} from './components/CommissionTable'
import { useToast } from '@/hooks/use-toast'
import type { Database } from '@/types/supabase'

type EventWithAssistants = Database['public']['Tables']['events']['Row'] & {
  wedding_clients: { name: string | null } | null
  event_assistants: {
    assistant_id: string
    assistant: { name: string | null } | null
  }[]
}

interface FinancialStats {
  mrr: number
  activeSubscribers: number
  churnRate: string
  growth: string
}

interface AdminFinancialsProps {
  stats: FinancialStats
  loading: boolean
}

export default function AdminFinancials({
  stats,
  loading,
}: AdminFinancialsProps) {
  const { toast } = useToast()
  const [events, setEvents] = useState<Record<string, unknown>[]>([])
  const [commissions, setCommissions] = useState<AssistantCommission[]>([])
  const [dataLoading, setDataLoading] = useState(true)

  useEffect(() => {
    const fetchMonthlyData = async () => {
      const now = new Date()
      const start = startOfMonth(now).toISOString()
      const end = endOfMonth(now).toISOString()

      try {
        const { data: eventsData, error } = await supabase
          .from('events')
          .select(
            `
                        *,
                        wedding_clients (name),
                        event_assistants (
                            assistant_id,
                            assistant:profiles!assistants (name)
                        )
                    `,
          )
          .gte('event_date', start)
          .lte('event_date', end)

        if (error) throw error

        setEvents(eventsData || [])
        calculateCommissions((eventsData as EventWithAssistants[]) || [])
      } catch (error) {
        logger.error('AdminFinancials.fetchMonthlyData', error, 'SYSTEM', {
          showToast: false,
        })
        toast({
          title: 'Erro ao carregar dados',
          description: 'N├úo foi poss├¡vel carregar o fechamento financeiro.',
          variant: 'destructive',
        })
      } finally {
        setDataLoading(false)
      }
    }

    fetchMonthlyData()
  }, [])

  const calculateCommissions = (eventsData: EventWithAssistants[]) => {
    const commissionMap = new Map<string, AssistantCommission>()

    eventsData.forEach((event) => {
      const totalCommission = Number(event.assistant_commission) || 0
      const assistants = event.event_assistants || []

      if (assistants.length > 0 && totalCommission > 0) {
        const splitCommission = totalCommission / assistants.length

        assistants.forEach((ea) => {
          const assistantName = ea.assistant?.name || 'Desconhecido'
          const assistantId = ea.assistant_id

          if (!commissionMap.has(assistantId)) {
            commissionMap.set(assistantId, {
              assistant_id: assistantId,
              assistant_name: assistantName,
              total_events: 0,
              total_commission: 0,
            })
          }

          const current = commissionMap.get(assistantId)!
          current.total_events += 1
          current.total_commission += splitCommission
        })
      }
    })

    setCommissions(Array.from(commissionMap.values()))
  }

  const handleExport = () => {
    if (!events || events.length === 0) {
      toast({
        title: 'Sem dados',
        description: 'N├úo h├í dados para exportar neste m├¬s.',
        variant: 'destructive',
      })
      return
    }
    exportMonthlyClosing(events)
    toast({
      title: 'Exporta├º├úo Iniciada',
      description: 'O arquivo Excel est├í sendo gerado.',
    })
  }

  if (loading) {
    return (
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
        {[1, 2, 3].map((i) => (
          <Card key={i} className="bg-[#1A1A1A] border-white/10">
            <CardContent className="pt-6 h-32 animate-pulse bg-white/5" />
          </Card>
        ))}
      </div>
    )
  }

  return (
    <div className="space-y-8">
      {}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <Card className="bg-black border border-white/10 rounded-none hover:border-white/30 transition-all group">
          <CardContent className="pt-6">
            <div className="flex justify-between items-start">
              <div>
                <p className="text-zinc-500 font-mono text-[10px] uppercase tracking-widest font-bold">MRR (Receita Mensal)</p>
                <h3 className="text-3xl font-serif text-white mt-2 tracking-tighter">
                  {new Intl.NumberFormat('pt-BR', {
                    style: 'currency',
                    currency: 'BRL',
                  }).format(stats.mrr)}
                </h3>
              </div>
              <div className="p-2 bg-white/5 border border-white/10 group-hover:border-white/30 transition-colors">
                <CreditCard className="w-5 h-5 text-white/50" />
              </div>
            </div>
            <div className="mt-4 h-1 bg-zinc-900 overflow-hidden">
                <div className="h-full bg-white/40 w-full animate-pulse shadow-[0_0_10px_rgba(255,255,255,0.2)]" />
            </div>
          </CardContent>
        </Card>

        <Card className="bg-black border border-white/10 rounded-none hover:border-white/30 transition-all group">
          <CardContent className="pt-6">
            <div className="flex justify-between items-start">
              <div>
                <p className="text-zinc-500 font-mono text-[10px] uppercase tracking-widest font-bold">Assinantes Ativos</p>
                <h3 className="text-3xl font-serif text-white mt-2 tracking-tighter">
                  {stats.activeSubscribers}
                </h3>
              </div>
              <div className="p-2 bg-white/5 border border-white/10 group-hover:border-white/30 transition-colors">
                <Users className="w-5 h-5 text-white/50" />
              </div>
            </div>
          </CardContent>
        </Card>

        <Card className="bg-black border border-white/10 rounded-none hover:border-white/30 transition-all group">
          <CardContent className="pt-6">
            <div className="flex justify-between items-start">
              <div>
                <p className="text-zinc-500 font-mono text-[10px] uppercase tracking-widest font-bold">Churn Rate</p>
                <h3 className="text-3xl font-serif text-white mt-2 tracking-tighter">
                  {stats.churnRate}
                </h3>
              </div>
              <div className="p-2 bg-white/5 border border-white/10 group-hover:border-white/30 transition-colors">
                <TrendingUp className="w-5 h-5 text-white/50" />
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {}
      <div className="space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4">
          <div>
            <h2 className="text-2xl font-serif text-white tracking-tight">
              Gest├úo Financeira e Comiss├Áes
            </h2>
            <p className="text-zinc-500 font-mono text-[10px] uppercase tracking-[0.3em] mt-1">
              Terminal: {format(new Date(), 'MMMM yyyy', { locale: ptBR })}
            </p>
          </div>
          <Button
            onClick={handleExport}
            disabled={dataLoading}
            className="rounded-none bg-white text-black hover:bg-zinc-200 font-mono text-[11px] uppercase tracking-widest font-bold h-11 px-8"
          >
            {dataLoading ? (
              <Loader2 className="w-4 h-4 animate-spin" />
            ) : (
              <Download className="w-4 h-4 mr-2" />
            )}
            EXPORT_CLOSING_REPORT
          </Button>
        </div>

        <CommissionTable data={commissions} />
      </div>
    </div>
  )
}

