      service: 'Supabase Database',
      status: 'unknown',
      message: 'Checking connection...',
    },
    {
      service: 'Supabase Auth',
      status: 'unknown',
      message: 'Checking connection...',
    },
    {
      service: 'Google Calendar Sync',
      status: 'unknown',
      message: 'Checking Edge Function...',
    },
    {
      service: 'Stripe',
      status: 'unknown',
      message: 'Checking Configuration...',
    },
    {
      service: 'Google Maps',
      status: 'unknown',
      message: 'Checking API Key...',
    },
    {
      service: 'Resend Email',
      status: 'unknown',
      message: 'Checking Client Configuration...',
    },
  ])

  const checkStatus = async () => {
    setLoading(true)
    const newStatuses = [...statuses]

    try {
      const { error } = await supabase
        .from('profiles')
        .select('count')
        .limit(1)
        .maybeSingle()
      updateStatus(
        newStatuses,
        'Supabase Database',
        error ? 'degraded' : 'operational',
        error?.message || 'Connected',
      )
      updateStatus(
        newStatuses,
        'Supabase Auth',
        'operational',
        'Session Active',
      )
    } catch (e) {
      updateStatus(
        newStatuses,
        'Supabase Database',
        'down',
        'Connection Failed',
      )
      logger.error(e, 'Health Check Failed', {
        context: { service: 'Supabase Database' },
      })
    }

    try {
      const { data, error } = await supabase.functions.invoke(
        'google-calendar-sync',
        {
          body: { action: 'check_config' },
        },
      )

      if (error) throw error

      if (data?.error === 'Service configuration error') {
        updateStatus(
          newStatuses,
          'Google Calendar Sync',
          'not_configured',
          `Missing: ${data.missing_keys?.join(', ')}`,
        )
      } else if (data?.error === 'Invalid action') {
        updateStatus(
          newStatuses,
          'Google Calendar Sync',
          'operational',
          'Edge Function Configured',
        )
      } else {
        updateStatus(
          newStatuses,
          'Google Calendar Sync',
          'operational',
          'Responding',
        )
      }
    } catch (_e) {
      updateStatus(newStatuses, 'Google Calendar Sync', 'down', 'Unreachable')
    }

    try {
      const { data, error } = await supabase.functions.invoke(
        'check-stripe-status',
      )

      if (error || data?.status === 'down') {
        const msg = error?.message || data?.error || 'Unknown Error'
        updateStatus(newStatuses, 'Stripe', 'down', msg)
        logger.error(new Error(`Stripe Health Check Failed: ${msg}`), {
          context: { service: 'Stripe', data, error },
        })
      } else {
        updateStatus(
          newStatuses,
          'Stripe',
          'operational',
          `Latency: ${data?.latency || 'OK'}`,
        )
      }
    } catch (e) {
      updateStatus(newStatuses, 'Stripe', 'down', 'Invocation Failed')
      logger.error(e, 'Health Check Failed', { context: { service: 'Stripe' } })
    }

    const mapsKey = import.meta.env.VITE_GOOGLE_MAPS_API_KEY
    if (mapsKey) {
      updateStatus(
        newStatuses,
        'Google Maps',
        'operational',
        'Key Present in Client',
      )
    } else {
      updateStatus(
        newStatuses,
        'Google Maps',
        'not_configured',
        'VITE_GOOGLE_MAPS_API_KEY Missing',
      )
    }

    try {
      const { data, error } =
        await supabase.functions.invoke('check-ses-status')

      if (error || data?.status === 'down') {
        const msg = error?.message || data?.error || 'Unknown Error'
        updateStatus(newStatuses, 'Resend Email', 'down', msg)
        logger.error(new Error(`SES Health Check Failed: ${msg}`), {
          context: { service: 'Resend Email', data, error },
        })
      } else {
        updateStatus(newStatuses, 'Resend Email', 'operational', `Operational`)
      }
    } catch (e) {
      updateStatus(newStatuses, 'Resend Email', 'down', 'Invocation Failed')
      logger.error(e, 'Health Check Failed', {
        context: { service: 'Resend Email' },
      })
    }

    setStatuses(newStatuses)
    setLoading(false)
    toast.success('System Status Updated')
  }

  const updateStatus = (
    list: IntegrationStatus[],
    service: string,
    status: IntegrationStatus['status'],
    message: string,
  ) => {
    const idx = list.findIndex((s) => s.service === service)
    if (idx >= 0) {
      list[idx] = { ...list[idx], status, message, lastChecked: new Date() }
    }
  }

  useEffect(() => {
    checkStatus()
  }, [])

  const getIcon = (service: string) => {
    switch (service) {
      case 'Supabase Database':
        return Database
      case 'Google Calendar Sync':
        return Calendar
      case 'Stripe':
        return CreditCard
      case 'Google Maps':
        return Map
      case 'Resend Email':
        return Mail
      default:
        return ShieldCheck
    }
  }

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'operational':
        return 'text-green-500 border-green-500/50 bg-green-500/10'
      case 'degraded':
        return 'text-yellow-500 border-yellow-500/50 bg-yellow-500/10'
      case 'not_configured':
        return 'text-red-500 border-red-500/50 bg-red-500/10'
      case 'down':
        return 'text-red-500 border-red-500/50 bg-red-500/10'
      default:
        return 'text-gray-500 border-gray-500/50 bg-gray-500/10'
    }
  }

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'operational':
        return <CheckCircle className="h-4 w-4" />
      case 'degraded':
        return <AlertTriangle className="h-4 w-4" />
      case 'not_configured':
        return <XCircle className="h-4 w-4" />
      case 'down':
        return <XCircle className="h-4 w-4" />
      default:
        return <RefreshCw className="h-4 w-4 animate-spin" />
    }
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-foreground font-serif text-3xl font-light tracking-tight">
            System Status
          </h2>
          <p className="text-muted-foreground text-xs font-mono uppercase tracking-widest mt-1">
            Integration Health Monitor
          </p>
        </div>
        <Button
          onClick={checkStatus}
          disabled={loading}
          variant="outline"
          className="font-mono text-xs uppercase"
        >
          <RefreshCw
            className={`mr-2 h-3 w-3 ${loading ? 'animate-spin' : ''}`}
          />
          Run Diagnostics
        </Button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {statuses.map((item) => {
          const Icon = getIcon(item.service)
          return (
            <Card
              key={item.service}
              className="bg-black border border-border/40 hover:border-border transition-all"
            >
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium font-mono uppercase tracking-widest text-muted-foreground">
                  {item.service}
                </CardTitle>
                <Icon className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="flex items-center justify-between mt-2">
                  <Badge
                    variant="outline"
                    className={`rounded-none px-3 py-1 flex items-center gap-2 ${getStatusColor(item.status)}`}
                  >
                    {getStatusIcon(item.status)}
                    <span className="uppercase tracking-wider text-[10px] font-bold">
                      {item.status.replace('_', ' ')}
                    </span>
                  </Badge>
                </div>
                <p
                  className="text-xs text-muted-foreground mt-4 font-mono truncate"
                  title={item.message}
                >
                  {item.message}
                </p>
              </CardContent>
            </Card>
          )
        })}
      </div>

      <Card className="bg-muted/5 border-none">
        <CardHeader>
          <CardTitle className="text-lg font-serif">Diagnostic Logs</CardTitle>
          <CardDescription>Recent check results</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="text-xs font-mono text-muted-foreground bg-black/50 p-4 rounded border border-white/5 space-y-1">
            {statuses.map((s, i) => (
              <div key={i} className="flex justify-between">
                <span>
                  [
                  {s.lastChecked
                    ? s.lastChecked.toLocaleTimeString()
                    : '--:--:--'}
                  ] checking {s.service}...
                </span>
                <span
                  className={
                    s.status === 'operational'
                      ? 'text-green-500'
                      : 'text-red-500'
                  }
                >
                  {s.status.toUpperCase()}
                </span>
              </div>
            ))}
            <div className="text-green-500 mt-2">-- DIAGNOSTIC COMPLETE --</div>
          </div>
        </CardContent>
      </Card>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { logger } from '@/services/logger'
import { Button } from '@/components/ui/button'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { Terminal, RefreshCw, FileDown } from 'lucide-react'
import { format } from 'date-fns/format'
import { supabase } from '@/integrations/supabase/client'
import { SupabaseClient } from '@supabase/supabase-js'
import {
  AuditDatabase,
  AuditLog,
  NotificationLog,
  SystemLog,
} from '@/types/audit'
import { LogFilters } from './components/logs/LogFilters'
import { LogTable } from './components/logs/LogTable'
import { LogDetailDialog } from './components/logs/LogDetailDialog'

export default function AdminLogs() {
  const [activeTab, setActiveTab] = useState('system')
  const [systemLogs, setSystemLogs] = useState<SystemLog[]>([])
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>([])
  const [emailLogs, setEmailLogs] = useState<NotificationLog[]>([])
  const [loading, setLoading] = useState(false)

  const [filterUser, setFilterUser] = useState<string>('all')
  const [filterTable, setFilterTable] = useState<string>('all')
  const [filterAction, setFilterAction] = useState<string>('all')
  const [availableTables, setAvailableTables] = useState<string[]>([])
  const [selectedAudit, setSelectedAudit] = useState<AuditLog | null>(null)

  useEffect(() => {
    fetchData()
  }, [activeTab, filterUser, filterTable, filterAction])

  useEffect(() => {
    if (activeTab === 'audit') {
      fetchAvailableTables()
    }
  }, [activeTab])

  const fetchAvailableTables = async () => {
    try {
      const { data, error } = await supabase.rpc('get_audit_tables')
      if (data) setAvailableTables(data as string[])

      if (error) {
        const { data: fallbackData } = await (
          supabase.from(
            'audit_logs',
          ) as unknown as SupabaseClient<AuditDatabase>['from']
        )
          .select('table_name')
          .limit(100)
        if (fallbackData) {
          const uniqueTables = Array.from(
            new Set((fallbackData as AuditLog[]).map((d) => d.table_name)),
          )
          setAvailableTables(uniqueTables)
        }
      }
    } catch (e) {
      logger.error(e, 'AdminLogs.fetchAvailableTables', { showToast: false })
    }
  }

  const fetchData = async () => {
    setLoading(true)
    try {
      const typedSupabase = supabase
      if (activeTab === 'system') {
        let query = typedSupabase
          .from('system_logs')
          .select('*')
          .order('timestamp', { ascending: false })
          .limit(100)

        if (filterUser !== 'all') {
          query = query.eq('user_id', filterUser)
        }

        const { data, error } = await query
        if (error) throw error
        setSystemLogs(data || [])
      } else if (activeTab === 'audit') {
        let query = typedSupabase
          .from('audit_logs')
          .select('*')
          .order('created_at', { ascending: false })
          .limit(100)

        if (filterUser !== 'all') query = query.eq('user_id', filterUser)
        if (filterTable !== 'all') query = query.eq('table_name', filterTable)
        if (filterAction !== 'all') query = query.eq('action', filterAction)

        const { data, error } = await query
        if (error) throw error
        setAuditLogs(data || [])
      } else if (activeTab === 'email') {
        const { data, error } = await typedSupabase
          .from('notification_logs')
          .select('*')
          .order('created_at', { ascending: false })
          .limit(100)
        if (error) throw error
        setEmailLogs(data || [])
      }
    } catch (error) {
      logger.error(error, 'AdminLogs.fetchData', { showToast: false })
    } finally {
      setLoading(false)
    }
  }

  const handleExportCSV = () => {
    const dataToExport =
      activeTab === 'system'
        ? systemLogs
        : activeTab === 'audit'
          ? auditLogs
          : emailLogs
    if (dataToExport.length === 0) return

    const headers = Object.keys(dataToExport[0]).join(',')
    const csvRows = dataToExport.map((row) => {
      const _record = row as Record<string, unknown>
      return Object.values(row)
        .map((value) => {
          const stringValue =
            typeof value === 'object' ? JSON.stringify(value) : String(value)
          return `"${stringValue.replace(/"/g, '""')}"`
        })
        .join(',')
    })

    const csvContent = [headers, ...csvRows].join('\n')
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' })
    const url = URL.createObjectURL(blob)
    const link = document.createElement('a')
    link.setAttribute('href', url)
    link.setAttribute(
      'download',
      `kontrol_${activeTab}_logs_${format(new Date(), 'yyyy-MM-dd')}.csv`,
    )
    link.style.visibility = 'hidden'
    document.body.appendChild(link)
    link.click()
    document.body.removeChild(link)
  }

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <Card className="bg-black border border-white/20 rounded-none">
        <CardHeader className="flex flex-col md:flex-row md:items-center justify-between border-b border-white/10 pb-4 gap-4">
          <div className="flex items-center gap-2">
            <Terminal className="h-5 w-5 text-white" />
            <CardTitle className="text-white font-serif tracking-tight text-xl uppercase">
              KONTROL.AUDIT_TERMINAL
            </CardTitle>
          </div>
          <div className="flex items-center gap-4">
            <Button
              variant="outline"
              size="sm"
              onClick={handleExportCSV}
              className="rounded-none border-white/20 hover:bg-white hover:text-black font-mono text-[10px] uppercase"
            >
              <FileDown className="h-3 w-3 mr-2" />
              EXPORT_CSV
            </Button>
            <Button
              variant="outline"
              size="sm"
              onClick={fetchData}
              className="rounded-none border-white/20 hover:bg-white hover:text-black font-mono text-[10px] uppercase"
            >
              <RefreshCw
                className={`h-3 w-3 mr-2 ${loading ? 'animate-spin' : ''}`}
              />
              RELOAD_BUFFER
            </Button>
          </div>
        </CardHeader>
        <CardContent className="p-0">
          <LogFilters
            filterAction={filterAction}
            setFilterAction={setFilterAction}
            filterTable={filterTable}
            setFilterTable={setFilterTable}
            filterUser={filterUser}
            setFilterUser={setFilterUser}
            activeTab={activeTab}
            availableTables={availableTables}
          />

          <Tabs
            defaultValue="system"
            value={activeTab}
            onValueChange={setActiveTab}
            className="w-full"
          >
            <div className="px-6 border-b border-white/10">
              <TabsList className="bg-transparent h-12 gap-6 p-0">
                {['system', 'audit', 'email'].map((tab) => (
                  <TabsTrigger
                    key={tab}
                    value={tab}
                    className="rounded-none border-b-2 border-transparent data-[state=active]:border-white data-[state=active]:bg-transparent text-gray-500 data-[state=active]:text-white font-mono text-[10px] uppercase tracking-widest px-0"
                  >
                    {tab === 'system'
                      ? 'SYSTEM_LOGS'
                      : tab === 'audit'
                        ? 'AUDIT_TRAIL'
                        : 'EMAIL_DELIVERY'}
                  </TabsTrigger>
                ))}
              </TabsList>
            </div>

            <TabsContent value="system" className="m-0">
              <LogTable
                activeTab="system"
                loading={loading}
                systemLogs={systemLogs}
                auditLogs={[]}
                emailLogs={[]}
                onSelectAudit={() => {}}
              />
            </TabsContent>
            <TabsContent value="audit" className="m-0">
              <LogTable
                activeTab="audit"
                loading={loading}
                systemLogs={[]}
                auditLogs={auditLogs}
                emailLogs={[]}
                onSelectAudit={setSelectedAudit}
              />
            </TabsContent>
            <TabsContent value="email" className="m-0">
              <LogTable
                activeTab="email"
                loading={loading}
                systemLogs={[]}
                auditLogs={[]}
                emailLogs={emailLogs}
                onSelectAudit={setSelectedAudit}
              />
            </TabsContent>
          </Tabs>
        </CardContent>
      </Card>

      <div className="p-4 border border-white/10 bg-white/5 font-mono text-[10px] uppercase text-gray-500 leading-relaxed flex justify-between items-center">
        <div>STATUS_OK: AUDIT_SYSTEM_ONLINE PROTOCOL: KONTROL_PRO</div>
        <div className="flex gap-4">
          <span>UPTIME: 99.99%</span>
          <span className="text-white animate-pulse">ÔùÅ LIVE</span>
        </div>
      </div>

      <LogDetailDialog
        selectedAudit={selectedAudit}
        onClose={() => setSelectedAudit(null)}
      />
    </div>
  )
}

import { useState } from 'react'
import { useAuth } from '@/hooks/useAuth'
import { logger } from '@/services/logger'
import { supabase } from '@/integrations/supabase/client'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { useToast } from '@/hooks/use-toast'
import {
  LogIn,
  Shield,
  User,
  Users,
  AlertCircle,
  MoreHorizontal,
  Lock,
  RefreshCw,
  Search,
  ShieldOff,
  CreditCard,
  Building2,
} from 'lucide-react'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/components/ui/dialog'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { Input } from '@/components/ui/input'
import { useAdminUsers } from './hooks/useAdminUsers'
import { Skeleton } from '@/components/ui/skeleton'

const PLAN_OPTIONS = [
  { value: 'free', label: 'Gratuito' },
  { value: 'essencial', label: 'Essencial' },
  { value: 'profissional', label: 'Profissional' },
  { value: 'studio', label: 'Studio' },
]

export default function AdminUsers() {
  const { user: adminUser } = useAuth()
  const { toast } = useToast()
  const { data: users, isLoading, isError, refetch } = useAdminUsers()

  const [searchQuery, setSearchQuery] = useState('')
  const [impersonating, setImpersonating] = useState<string | null>(null)
  const [planDialog, setPlanDialog] = useState<{
    open: boolean
    userId: string
    userName: string
    currentPlan: string
  }>({ open: false, userId: '', userName: '', currentPlan: '' })
  const [selectedPlan, setSelectedPlan] = useState('')

  const [planFilter, setPlanFilter] = useState<string>('all')

  const filteredUsers =
    users?.filter((u) => {
      const lowerQuery = searchQuery.toLowerCase().trim()
      const matchesSearch = lowerQuery === '' || 
        (u.full_name?.toLowerCase() || '').includes(lowerQuery) ||
        (u.email?.toLowerCase() || '').includes(lowerQuery) ||
        (u.id?.toLowerCase() || '').includes(lowerQuery)

      const matchesPlan = planFilter === 'all' || 
        (u.plan?.toLowerCase() || 'free') === planFilter.toLowerCase()

      return matchesSearch && matchesPlan
    }) || []

  const handleImpersonate = async (targetUserId: string) => {
    try {
      setImpersonating(targetUserId)

      const { data, error } = await supabase.functions.invoke(
        'admin-ghost-login',
        {
          body: { target_user_id: targetUserId },
        },
      )

      if (error) throw error

      if (data?.session_url) {
        window.open(data.session_url, '_blank')
      }

      toast({
        title: 'Ghost Login',
        description: `Sess├úo iniciada para ${targetUserId.slice(-8)}`,
      })
    } catch (error) {
      logger.error('AdminUsers.handleImpersonate', error)
      toast({
        title: 'Erro',
        description:
          'Falha ao iniciar ghost session. Verifique a Edge Function.',
        variant: 'destructive',
      })
    } finally {
      setImpersonating(null)
    }
  }

  const handleResetPassword = async (email: string) => {
    try {
      const { error } = await supabase.auth.resetPasswordForEmail(email, {
        redirectTo: `${window.location.origin}/reset-password`,
      })

      if (error) throw error

      toast({
        title: 'Email enviado',
        description: `Link de recupera├º├úo enviado para ${email}`,
      })
    } catch (error) {
      logger.error('AdminUsers.handleResetPassword', error)
      toast({
        title: 'Erro',
        description: 'Falha ao enviar email de recupera├º├úo.',
        variant: 'destructive',
      })
    }
  }

  const handleBlockUser = async (userId: string, block: boolean) => {
    try {
      const { data, error } = await (supabase.rpc as any)('admin_block_user', {
        p_user_id: userId,
        p_blocked: block,
      })

      if (error) throw error

      toast({
        title: block ? 'Usu├írio bloqueado' : 'Usu├írio desbloqueado',
        description: data?.user_name || userId.slice(-8),
      })

      refetch()
    } catch (error) {
      logger.error('AdminUsers.handleBlockUser', error)
      toast({
        title: 'Erro',
        description: 'Falha ao atualizar status do usu├írio.',
        variant: 'destructive',
      })
    }
  }

  const handleChangePlan = async () => {
    try {
      const { data, error } = await (supabase.rpc as any)(
        'admin_update_user_plan',
        {
          p_user_id: planDialog.userId,
          p_new_plan: selectedPlan,
        },
      )

      if (error) throw error

      toast({
        title: 'Plano atualizado',
        description: `${data?.user_name}: ${data?.old_plan} ÔåÆ ${data?.new_plan}`,
      })

      setPlanDialog({ open: false, userId: '', userName: '', currentPlan: '' })
      refetch()
    } catch (error) {
      logger.error('AdminUsers.handleChangePlan', error)
      toast({
        title: 'Erro',
        description: 'Falha ao atualizar plano.',
        variant: 'destructive',
      })
    }
  }

  const handleStudioTag = async (userId: string, isStudio: boolean) => {
    try {
      const { data, error } = await (supabase.rpc as any)('admin_set_studio_tag', {
        p_user_id: userId,
        p_is_studio: isStudio,
      })
      if (error) throw error
      toast({
        title: isStudio ? 'Acesso KAOS ativado' : 'Acesso KAOS removido',
        description: `O terminal de agenda KAOS foi ${(data as any)?.is_studio ? 'habilitado' : 'desabilitado'}.`,
      })
      refetch()
    } catch (error) {
      logger.error('AdminUsers.handleStudioTag', error)
      toast({ title: 'Erro ao alterar modo KAOS', variant: 'destructive' })
    }
  }

  const getPlanLabel = (plan: string) => {
    return PLAN_OPTIONS.find((p) => p.value === plan.toLowerCase())?.label || plan
  }

  const isBlocked = (u: any) => u.subscription_status === 'blocked'

