}

import { useQuery } from '@tanstack/react-query'
import { supabase } from '@/integrations/supabase/client'
import { logger } from '@/services/logger'
import { exportFinancialExcel } from '@/utils/exportExcel'

interface AnalyticsData {
  total_events: number
  total_clients: number
  new_clients_month: number
  monthly_revenue: number
  previous_month_revenue: number
  conversion_rate: number
  growth_revenue_percentage: number
  growth_client_percentage: number
  events_by_category: Array<{ name: string; value: number }>
  revenue_chart: Array<{ name: string; value: number }>
  client_sources: Array<{ name: string; value: number }>
  page_views: Array<{ name: string; value: number }>
}

export function useAdminAnalytics() {
  const { data, isLoading: loading } = useQuery({
    queryKey: ['admin-analytics'],
    queryFn: async (): Promise<AnalyticsData> => {
      const { data, error } = await (supabase.rpc as any)('get_admin_analytics')
      if (error) {
        logger.error('useAdminAnalytics.fetch', error)
        throw error
      }

      return data as AnalyticsData
    },
    staleTime: 1000 * 60 * 5,
  })

  const stats = {
    totalEvents: data?.total_events || 0,
    totalRevenue: data?.monthly_revenue || 0,
    newLeads: data?.new_clients_month || 0,
    conversionRate: data?.conversion_rate || 0,
    growth_client_percentage: data?.growth_client_percentage || 0,
    growth_revenue_percentage: data?.growth_revenue_percentage || 0,
    monthly_revenue: data?.monthly_revenue || 0,
    previous_month_revenue: data?.previous_month_revenue || 0,
    new_clients_month: data?.new_clients_month || 0,
    total_clients: data?.total_clients || 0,
  }

  const charts = {
    revenue: data?.revenue_chart || [],
    clients: data?.client_sources || [],
  }

  const categoryData = data?.events_by_category || []

  const pageData = (data?.page_views || []).map((p) => ({
    name: p.name.length > 15 ? p.name.slice(0, 15) + '...' : p.name,
    value: p.value,
  }))

  const handleExportExcel = () => {
    if (!charts.revenue || charts.revenue.length === 0) return

    const dataToExport = charts.revenue.map((item) => ({
      M├¬s: item.name,
      Receita: item.value,
    }))

    exportFinancialExcel(dataToExport, 'Relatorio_Financeiro_KhaosKontrol')
  }

  const isPositive = (value: number) => value > 0

  return {
    events: [],
    charts,
    loading,
    stats,
    categoryData,
    pageData,
    handleExportExcel,
    isPositive,
  }
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { supabase } from '@/integrations/supabase/client'
import { useToast } from '@/hooks/use-toast'
import { logger } from '@/services/logger'

export interface Campaign {
  id: string
  name: string
  subject: string
  target_segment: string
  target_plans: string[]
  status: string
  scheduled_at: string | null
  sent_at: string | null
  total_recipients: number
  total_sent: number
  total_opened: number
  total_clicked: number
  created_at: string
}

export function useAdminMarketing() {
  const queryClient = useQueryClient()
  const { toast } = useToast()

  const campaignsQuery = useQuery({
    queryKey: ['admin-marketing-campaigns'],
    queryFn: async (): Promise<Campaign[]> => {
      const { data, error } = await (supabase.rpc as any)(
        'get_marketing_campaigns',
        {
          p_limit: 50,
        },
      )

      if (error) {
        logger.error('useAdminMarketing.fetch', error)
        throw error
      }

      return (data as Campaign[]) || []
    },
  })

  const createCampaign = useMutation({
    mutationFn: async (params: {
      name: string
      subject: string
      body_html: string
      target_segment: string
      target_plans?: string[]
    }) => {
      const { data, error } = await (supabase.rpc as any)(
        'create_marketing_campaign',
        {
          p_name: params.name,
          p_subject: params.subject,
          p_body_html: params.body_html,
          p_target_segment: params.target_segment,
          p_target_plans: params.target_plans || [],
        },
      )

      if (error) throw error
      return data as {
        success: boolean
        campaign_id: string
        recipient_count: number
      }
    },
    onSuccess: (data) => {
      toast({
        title: 'Campanha criada',
        description: `${data.recipient_count} destinat├írios no segmento`,
      })
      queryClient.invalidateQueries({
        queryKey: ['admin-marketing-campaigns'],
      })
    },
    onError: (error) => {
      logger.error('useAdminMarketing.create', error)
      toast({
        title: 'Erro ao criar campanha',
        variant: 'destructive',
      })
    },
  })

  const sendCampaign = useMutation({
    mutationFn: async (campaignId: string) => {
      const { data, error } = await supabase.functions.invoke(
        'send-marketing-campaign',
        {
          body: { campaign_id: campaignId },
        },
      )

      if (error) throw error
      return data
    },
    onSuccess: () => {
      toast({
        title: 'Envio iniciado',
        description: 'Os emails est├úo sendo enviados em lote.',
      })
      queryClient.invalidateQueries({
        queryKey: ['admin-marketing-campaigns'],
      })
    },
    onError: (error) => {
      logger.error('useAdminMarketing.send', error)
      toast({
        title: 'Erro ao enviar campanha',
        variant: 'destructive',
      })
    },
  })

  const deleteCampaign = useMutation({
    mutationFn: async (campaignId: string) => {
      const { data, error } = await (supabase.rpc as any)(
        'delete_marketing_campaign',
        { p_campaign_id: campaignId },
      )
      if (error) throw error
      return data
    },
    onSuccess: () => {
      toast({ title: 'Campanha exclu├¡da' })
      queryClient.invalidateQueries({
        queryKey: ['admin-marketing-campaigns'],
      })
    },
    onError: (error) => {
      logger.error('useAdminMarketing.delete', error)
      toast({
        title: 'Erro ao excluir',
        description: 'S├│ ├® poss├¡vel excluir campanhas em rascunho.',
        variant: 'destructive',
      })
    },
  })

  return {
    campaigns: campaignsQuery.data || [],
    isLoading: campaignsQuery.isLoading,
    createCampaign,
    sendCampaign,
    deleteCampaign,
    refetch: campaignsQuery.refetch,
  }
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
