export function useAdminSubscriptions() {
  const { toast } = useToast()
  const queryClient = useQueryClient()

  const statsQuery = useQuery({
    queryKey: ['admin-subscription-stats'],
    queryFn: async (): Promise<SubscriptionStats> => {
      const { data, error } = await (supabase.rpc as any)(
        'get_admin_subscription_stats',
      )
      if (error) {
        logger.error('useAdminSubscriptions.fetchStats', error)
        throw error
      }

      const raw = data as {
        mrr: number
        active_subscribers: number
        churn_rate: number
        growth: number
      }

      return {
        mrr: raw.mrr,
        activeSubscribers: raw.active_subscribers,
        churnRate: `${raw.churn_rate}%`,
        growth: `${raw.growth >= 0 ? '+' : ''}${raw.growth}%`,
      }
    },
    staleTime: 1000 * 60 * 3,
  })

  const usersQuery = useQuery({
    queryKey: ['admin-subscription-users'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('profiles')
        .select('id, full_name, email, plan, subscription_status, created_at')
        .neq('role', 'admin')
        .order('created_at', { ascending: false })

      if (error) {
        logger.error('useAdminSubscriptions.fetchUsers', error)
        throw error
      }
      return data as SubscriptionUser[]
    },
  })

  const updatePlanMutation = useMutation({
    mutationFn: async ({
      userId,
      newPlan,
    }: {
      userId: string
      newPlan: string
    }) => {
      const { data, error } = await (supabase.rpc as any)(
        'admin_update_user_plan',
        {
          p_user_id: userId,
          p_new_plan: newPlan,
        },
      )
      if (error) throw error
      return data
    },
    onSuccess: (data) => {
      const result = data as {
        user_name?: string
        old_plan?: string
        new_plan?: string
      } | null
      toast({
        title: 'Plano atualizado',
        description: `${result?.user_name}: ${result?.old_plan} ÔåÆ ${result?.new_plan}`,
      })
      queryClient.invalidateQueries({ queryKey: ['admin-subscription-stats'] })
      queryClient.invalidateQueries({ queryKey: ['admin-subscription-users'] })
      queryClient.invalidateQueries({ queryKey: ['admin-dashboard-stats'] })
    },
    onError: (error) => {
      logger.error('useAdminSubscriptions.updatePlan', error)
      toast({
        title: 'Erro ao atualizar plano',
        variant: 'destructive',
      })
    },
  })

  const handleUpdatePlan = (userId: string, newPlan: string) => {
    updatePlanMutation.mutate({ userId, newPlan })
  }

  return {
    users: usersQuery.data || [],
    stats: statsQuery.data || {
      mrr: 0,
      activeSubscribers: 0,
      churnRate: '0%',
      growth: '+0%',
    },
    loading: statsQuery.isLoading || usersQuery.isLoading,
    handleUpdatePlan,
    refresh: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-subscription-stats'] })
      queryClient.invalidateQueries({ queryKey: ['admin-subscription-users'] })
    },
  }
}

import { useMemo, useState } from 'react'
import { useChat } from '@ai-sdk/react'
import {
  ChatMessageContentTypeText,
  ChatMessageStatusReady,
  type ChatMessageDTO,
} from '@inferencesh/sdk'
import { useAI } from '@/hooks/useAI'
import { createWebLLM } from '../services/web-llm-provider'

export function useKhaosAgent() {
  const { mode, byokSettings } = useAI()
  const [localInput, setLocalInput] = useState('')
  const [artifact, setArtifact] = useState<{
    title: string
    content: string
    type: 'document' | 'code'
    isOpen: boolean
  } | null>(null)
  const [localProgress, setLocalProgress] = useState<{
    progress: number
    text: string
  } | null>(null)

  const localModel = useMemo(() => {
    if (mode === 'local') {
      return createWebLLM('Llama-3-8B-q4f16_1-MLC', (report) => {
        setLocalProgress(report)
      })
    }
    return undefined
  }, [mode])

  const chatHelpers = useChat({
    api:
      mode === 'cloud'
        ? `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/ai-assistant`
        : undefined,
    headers: {
      Authorization: `Bearer ${import.meta.env.VITE_SUPABASE_ANON_KEY}`,
      ...(byokSettings?.apiKey && {
        'x-ai-provider': byokSettings.provider,
        'x-ai-key': byokSettings.apiKey,
        'x-ai-model': byokSettings.modelName,
      }),
    },
    model: mode === 'local' ? localModel : undefined,
    onFinish: ({ message }: { message: { content: string } }) => {
      const artifactMatch = message.content.match(
        /<artifact\s+title="([^"]+)"(?:\s+type="([^"]+)")?>([\s\S]*?)<\/artifact>/i,
      )
      if (artifactMatch) {
        setArtifact({
          title: artifactMatch[1],
          type: (artifactMatch[2] as 'document' | 'code') || 'document',
          content: artifactMatch[3].trim(),
          isOpen: true,
        })
      }
    },
  })

  const chatMessages = useMemo((): ChatMessageDTO[] => {
    return (chatHelpers.messages || []).map((m: any) => {
      const reasoning =
        (m.parts as Record<string, unknown>[])?.find(
          (p) => p.type === 'reasoning',
        )?.reasoning ||
        m.reasoning ||
        null

      return {
        id: m.id,
        role: m.role,
        content: [
          {
            type: ChatMessageContentTypeText,

            text: m.content
              .replace(/<artifact[\s\S]*?<\/artifact>/gi, '')
              .trim(),
          },
        ],
        reasoning: reasoning,
        status: ChatMessageStatusReady,
        created_at: m.createdAt?.toISOString() || new Date().toISOString(),
        tool_invocations: (m.toolInvocations as Record<string, unknown>[])?.map(
          (ti) => ({
            id: ti.toolCallId as string,
            status: ti.state as string,
            function: {
              name: ti.toolName as string,
              arguments: ti.args as string,
            },
            result: ti.result,
          }),
        ),
      }
    })
  }, [chatHelpers.messages, chatHelpers.status])

  const handleSubmit = (e?: React.FormEvent) => {
    if (e) e.preventDefault()
    if (!localInput.trim()) return

    chatHelpers.append({
      role: 'user',
      content: localInput,
    })
    setLocalInput('')
  }

  return {
    messages: chatMessages,
    input: localInput,
    setInput: setLocalInput,
    handleInputChange: (e: React.ChangeEvent<HTMLTextAreaElement>) =>
      setLocalInput(e.target.value),
    handleSubmit,
    isGenerating:
      chatHelpers.status === 'streaming' || chatHelpers.status === 'submitted',
    stop: chatHelpers.stop,
    error: chatHelpers.error?.message,
    sendMessage: (content: string) =>
      chatHelpers.sendMessage({ role: 'user', content }),
    artifact,
    closeArtifact: () =>
      setArtifact((prev) => (prev ? { ...prev, isOpen: false } : null)),
    localProgress,
  }
}

import type { MLCEngine } from '@mlc-ai/web-llm'
export class WebLLMProvider {
  readonly specificationVersion = 'v1'
  readonly provider = 'web-llm'
  readonly modelId: string

  private engine: MLCEngine | null = null
  private onProgress?: (report: { progress: number; text: string }) => void

  constructor(
    modelId: string = 'Llama-3-8B-q4f16_1-MLC',
    onProgress?: (report: { progress: number; text: string }) => void,
  ) {
    this.modelId = modelId
    this.onProgress = onProgress
  }

  async doGenerate(options: any): Promise<any> {
    const engine = await this.getEngine()

    const messages = options.prompt.map((p: any) => ({
      role: p.role,
      content: p.content,
    }))

    const result = await engine.chat.completions.create({
      messages,
      stream: false,
      ...options.settings,
    })

    return {
      text: result.choices[0].message.content,
      usage: result.usage,
      rawCall: { rawPrompt: options.prompt, rawSettings: options.settings },
      finishReason: result.choices[0].finish_reason || 'stop',
    }
  }

  async doStream(options: any): Promise<any> {
    const engine = await this.getEngine()

    const messages = options.prompt.map((p: any) => ({
      role: p.role,
      content: p.content,
    }))

    const asyncIterable = (await engine.chat.completions.create({
      messages,
      stream: true,
      ...options.settings,
    })) as any

    const stream = new ReadableStream<any>({
      async start(controller) {
        for await (const chunk of asyncIterable) {
          const content = chunk.choices[0]?.delta?.content
          if (content) {
            controller.enqueue({ type: 'text-delta', textDelta: content })
          }
        }
        controller.enqueue({
          type: 'finish',
          finishReason: 'stop',
          usage: { promptTokens: 0, completionTokens: 0 },
        })
        controller.close()
      },
    })

    return {
      stream,
      rawCall: { rawPrompt: options.prompt, rawSettings: options.settings },
    }
  }

  private async getEngine(): Promise<MLCEngine> {
    if (this.engine) return this.engine

    const { CreateMLCEngine } = await import('@mlc-ai/web-llm')
    this.engine = await CreateMLCEngine(this.modelId, {
      initProgressCallback: (report) => {
        if (this.onProgress) {
          this.onProgress({ progress: report.progress, text: report.text })
        }
      },
    })

    return this.engine
  }
}

export const createWebLLM = (
  modelId?: string,
  onProgress?: (report: { progress: number; text: string }) => void,
) => {
  return new WebLLMProvider(modelId, onProgress)
}

import SEOHead from '@/components/seo/SEOHead'
import { useEffect, useState } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { useAuth } from '@/hooks/useAuth'
import { supabase } from '@/integrations/supabase/client'
import { useToast } from '@/hooks/use-toast'
import { PageLoader } from '@/components/ui/PageLoader'

import { Button } from '@/components/ui/button'
import { AssistantSignupForm } from '@/features/assistants/components/AssistantSignupForm'
import { getErrorMessage } from '@/utils/error-handler'

export default function AcceptInvitePage() {
  const { token } = useParams<{ token: string }>()
  const { user, loading: authLoading } = useAuth()
  const { toast } = useToast()
  const navigate = useNavigate()
  const [processing, setProcessing] = useState(false)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    if (authLoading) return

    if (user && token && !processing && !error) {
      acceptInvite()
    }
  }, [user, authLoading, token])

  const acceptInvite = async () => {
    if (!token || !user) return
    setProcessing(true)

    try {
      const { data, error } = await supabase.rpc('accept_assistant_invite', {
        p_invite_token: token,
        p_user_id: user.id,
      })

      if (error) throw error

      const result = data as {
        success: boolean
        is_new_connection: boolean
        error?: string
      }

      if (result.success) {
        toast({
          title: result.is_new_connection
            ? 'Acesso Concedido!'
            : 'Acesso Verificado',
          description: 'Voc├¬ agora tem acesso ├á agenda desta maquiadora.',
        })
        setTimeout(() => navigate('/assistant/dashboard'), 1500)
      } else {
        const errorMessage = result.error || 'Convite inv├ílido ou expirado.'
        setError(errorMessage)
        toast({
          title: 'Erro',
          description: errorMessage,
          variant: 'destructive',
        })
      }
    } catch (err: unknown) {
      const { title, description } = getErrorMessage(
        err,
        'Erro ao aceitar convite',
      )
      setError(description)
      toast({
        title,
        description,
        variant: 'destructive',
      })
    } finally {
      setProcessing(false)
    }
  }

  if (authLoading) return <PageLoader />

  if (!user) {
    return (
      <div className="container mx-auto px-4 py-8">
        <AssistantSignupForm token={token || ''} />
      </div>
    )
  }

  if (processing) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen">
        <PageLoader />
        <p className="text-muted-foreground animate-pulse mt-4">
          Verificando convite e configurando acesso...
        </p>
      </div>
    )
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen p-4 bg-background">
        <SEOHead title="Aceitar Convite" noindex={true} />
        <div className="bg-destructive/10 border border-destructive/20 text-destructive p-8 rounded-lg max-w-md w-full text-center shadow-lg">
          <h3 className="text-xl font-bold mb-4">Erro no Convite</h3>
          <p className="mb-6">{error}</p>
          <Button
            onClick={() => navigate('/')}
            variant="outline"
            className="w-full"
          >
            Voltar para In├¡cio
          </Button>
        </div>
      </div>
    )
  }

  return null
}

