            <div className="flex justify-end gap-3 pt-6 border-t border-white/5">
              <Button
                type="button"
                variant="outline"
                onClick={() => onOpenChange(false)}
                className="rounded-none border-white/10 text-gray-400 hover:text-white hover:bg-white/5 hover:border-white/30 uppercase text-xs tracking-wider"
              >
                Cancelar
              </Button>
              <Button
                type="submit"
                disabled={form.formState.isSubmitting}
                className="rounded-none bg-white text-black hover:bg-gray-200 border-none uppercase text-xs tracking-wider font-semibold px-6"
              >
                {form.formState.isSubmitting
                  ? 'Salvando...'
                  : assistant
                    ? 'Salvar'
                    : 'Cadastrar'}
              </Button>
            </div>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  )
}

import { useState, useEffect } from 'react'
import { useMFA } from '@/hooks/useMFA'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert'
import { Loader2, CheckCircle2 } from 'lucide-react'
import { toast } from 'sonner'

interface MFAFactor {
  id: string
  status: string
  created_at: string
}

interface EnrollmentData {
  id: string
  totp: {
    qr_code: string
    secret: string
  }
}

export default function MFAEnrollment() {
  const { enroll, verify, challenge, listFactors, unenroll, isLoading } =
    useMFA()

  const [factors, setFactors] = useState<MFAFactor[]>([])
  const [enrollmentData, setEnrollmentData] = useState<EnrollmentData | null>(
    null,
  )
  const [verificationCode, setVerificationCode] = useState('')
  const [isVerifying, setIsVerifying] = useState(false)
  const [enrolled, setEnrolled] = useState(false)
  const [qrCodeUrl, setQrCodeUrl] = useState<string | null>(null)

  const fetchFactors = async () => {
    const facts = await listFactors()
    setFactors(facts || [])
  }

  useEffect(() => {
    fetchFactors()
  }, [])

  const handleEnroll = async () => {
    const response = await enroll()
    if (response) {
      setEnrollmentData(response)
      setQrCodeUrl(response.totp.qr_code)
    }
  }

  const handleVerify = async () => {
    if (!enrollmentData) return
    setIsVerifying(true)
    try {
      const challengeData = await challenge(enrollmentData.id)
      if (challengeData) {
        const verifyData = await verify(
          enrollmentData.id,
          challengeData.id,
          verificationCode,
        )
        if (verifyData) {
          toast.success('MFA ativado com sucesso!')
          setEnrollmentData(null)
          setQrCodeUrl(null)
          setVerificationCode('')
          setEnrolled(true)
          fetchFactors()
        }
      }
    } catch (_e) {
      toast.error('Erro na verifica├º├úo. Tente novamente.')
    } finally {
      setIsVerifying(false)
    }
  }

  const handleUnenroll = async (factorId: string) => {
    if (confirm('Tem certeza que deseja desativar o MFA?')) {
      await unenroll(factorId)
      toast.success('MFA desativado.')
      fetchFactors()
    }
  }

  const hasMFA = factors.length > 0

  if (enrolled) {
    return (
      <div className="space-y-6">
        <Alert className="bg-green-500/10 border-green-500/20 text-green-500">
          <CheckCircle2 className="h-4 w-4" />
          <AlertTitle>MFA Ativado!</AlertTitle>
          <AlertDescription>Sua conta est├í mais segura.</AlertDescription>
        </Alert>

        <div className="space-y-4 text-center">
          <h3 className="font-medium text-white">Pronto para usar</h3>
          <p className="text-sm text-gray-400">
            Utilize seu aplicativo autenticador na pr├│xima vez que fizer login.
          </p>
          <div className="p-4 border border-neutral-800 rounded-md bg-neutral-900/50 text-center">
            <p className="text-sm text-muted-foreground">
              Recovery codes estar├úo dispon├¡veis em breve.
            </p>
            <p className="text-xs text-neutral-500 mt-2">
              Por enquanto, guarde seu dispositivo de autentica├º├úo em local
              seguro.
            </p>
          </div>
          <Button onClick={() => setEnrolled(false)} className="w-full">
            Entendido
          </Button>
        </div>
      </div>
    )
  }

  return (
    <div className="space-y-6 max-w-xl">
      <div>
        <h2 className="text-lg font-medium text-white mb-1">
          Multi-Factor Authentication (MFA)
        </h2>
        <p className="text-sm text-gray-400">
          Adicione uma camada extra de seguran├ºa ├á sua conta exigindo um c├│digo
          do seu aplicativo autenticador ao fazer login.
        </p>
      </div>

      {isLoading && factors.length === 0 && !enrollmentData && (
        <div className="flex justify-center p-4">
          <Loader2 className="animate-spin text-primary" />
        </div>
      )}

      {!enrollmentData && !hasMFA && (
        <Button onClick={handleEnroll} disabled={isLoading}>
          {isLoading ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null}
          Ativar MFA
        </Button>
      )}

      {hasMFA && !enrollmentData && (
        <div className="space-y-4">
          <Alert className="bg-emerald-500/10 border-emerald-500/20 text-emerald-500">
            <CheckCircle2 className="h-4 w-4" />
            <AlertTitle>MFA Ativo</AlertTitle>
            <AlertDescription>
              Sua conta est├í protegida com autentica├º├úo de dois fatores.
            </AlertDescription>
          </Alert>

          <div className="border border-gray-800 rounded-lg p-4">
            {factors.map((factor) => (
              <div
                key={factor.id}
                className="flex items-center justify-between"
              >
                <div>
                  <p className="font-medium text-white">
                    Aplicativo Autenticador (TOTP)
                  </p>
                  <p className="text-xs text-gray-500">
                    Adicionado em{' '}
                    {new Date(factor.created_at).toLocaleDateString()}
                  </p>
                  <p className="text-xs text-gray-600 mt-1">
                    Status: {factor.status}
                  </p>
                </div>
                <Button
                  variant="destructive"
                  size="sm"
                  onClick={() => handleUnenroll(factor.id)}
                >
                  Desativar
                </Button>
              </div>
            ))}
          </div>
        </div>
      )}

      {enrollmentData && (
        <div className="space-y-6 border border-gray-800 rounded-lg p-6 bg-gray-900/50">
          <div className="space-y-4">
            <h3 className="text-white font-medium">1. Escaneie o QR Code</h3>
            <div className="flex justify-center bg-white p-4 rounded-lg w-fit mx-auto">
              {qrCodeUrl && (
