              setEnrollmentData(null)
              setQrCodeUrl(null)
            }}
          >
            Cancelar
          </Button>
        </div>
      )}
    </div>
  )
}

import { useMutation, useQueryClient } from '@tanstack/react-query'
import { supabase } from '@/integrations/supabase/client'
import { QUERY_KEYS } from '@/constants/queryKeys'
import { useToast } from '@/hooks/use-toast'
import { logger } from '@/services/logger'
import { sanitizeFormData } from '@/lib/security'

export function useEventMutations() {
  const queryClient = useQueryClient()
  const { toast } = useToast()

  const createMutation = useMutation({
    mutationFn: async (eventData: any) => {
      const cleanData = sanitizeFormData(eventData)
      const { data: event, error } = await supabase
        .from('calendar_events')
        .insert(cleanData)
        .select()
        .single()

      if (error) throw error

      try {
        await supabase.functions.invoke('sync-event-to-google', {
          body: { event_id: event.id, action: 'create' },
        })
      } catch (syncError) {
        logger.warning('Falha ao sincronizar com Google Calendar:', syncError)
      }

      return event
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['events'] })
      queryClient.invalidateQueries({ queryKey: [QUERY_KEYS.CALENDAR_EVENTS] })
      queryClient.invalidateQueries({ queryKey: [QUERY_KEYS.DASHBOARD_STATS] })
      queryClient.invalidateQueries({ queryKey: ['calendar'] })
      toast({ title: 'Evento criado!' })
    },
    onError: (error) => {
      logger.error(error, 'useEventMutations.create')
      toast({
        title: 'Erro ao criar evento',
        variant: 'destructive',
      })
    },
  })

  const updateMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string; data: any }) => {
      const cleanData = sanitizeFormData(data)
      const { data: event, error } = await supabase
        .from('calendar_events')
        .update(cleanData)
        .eq('id', id)
        .select()
        .single()

      if (error) throw error

      try {
        await supabase.functions.invoke('sync-event-to-google', {
          body: { event_id: id, action: 'update' },
        })
      } catch (syncError) {
        logger.warning('Falha ao sincronizar com Google Calendar:', syncError)
      }

      return event
    },
    onSuccess: (_, variables) => {
      queryClient.invalidateQueries({ queryKey: ['events'] })
      queryClient.invalidateQueries({ queryKey: ['event', variables.id] })
      queryClient.invalidateQueries({ queryKey: [QUERY_KEYS.CALENDAR_EVENTS] })
      queryClient.invalidateQueries({ queryKey: [QUERY_KEYS.DASHBOARD_STATS] })
      queryClient.invalidateQueries({ queryKey: ['calendar'] })
      toast({ title: 'Evento atualizado!' })
    },
    onError: (error) => {
      logger.error(error, 'useEventMutations.update')
      toast({
        title: 'Erro ao atualizar evento',
        variant: 'destructive',
      })
    },
  })

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase
        .from('calendar_events')
        .delete()
        .eq('id', id)

      if (error) throw error

      try {
        await supabase.functions.invoke('sync-event-to-google', {
          body: { event_id: id, action: 'delete' },
        })
      } catch (syncError) {
        logger.warning('Falha ao sincronizar com Google Calendar:', syncError)
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['events'] })
      queryClient.invalidateQueries({ queryKey: [QUERY_KEYS.CALENDAR_EVENTS] })
      queryClient.invalidateQueries({ queryKey: [QUERY_KEYS.DASHBOARD_STATS] })
      queryClient.invalidateQueries({ queryKey: ['calendar'] })
      toast({ title: 'Evento exclu├¡do!' })
    },
    onError: (error) => {
      logger.error(error, 'useEventMutations.delete')
      toast({
        title: 'Erro ao excluir evento',
        variant: 'destructive',
      })
    },
  })

  return {
    createMutation,
    updateMutation,
    deleteMutation,
  }
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { useEffect } from 'react'
import { supabase } from '@/integrations/supabase/client'
import { useAuth } from '@/hooks/useAuth'
import { useToast } from '@/hooks/use-toast'
import { logger } from '@/services/logger'

export interface StudioEvent {
  id: string
  title: string
  description: string | null
  event_date: string
  start_time: string
  end_time: string
  color: string
  created_by: string
  creator_name: string | null
  created_at: string
}

export function useStudioCalendar(startDate: string, endDate: string) {
  const queryClient = useQueryClient()
  const { user } = useAuth()
  const { toast } = useToast()

  const eventsQuery = useQuery({
    queryKey: ['studio-events', startDate, endDate],
    queryFn: async (): Promise<StudioEvent[]> => {
      const { data, error } = await supabase.rpc('get_studio_events', {
        p_start_date: startDate,
        p_end_date: endDate,
      })
      if (error) {
        logger.error('useStudioCalendar.fetch', error)
        throw error
      }
      return (data as StudioEvent[]) || []
    },
    enabled: !!startDate && !!endDate,
  })

  const createEvent = useMutation({
    mutationFn: async (params: {
      title: string
      event_date: string
      start_time: string
      end_time: string
      description?: string
      color?: string
    }) => {
      const { data, error } = await supabase.rpc('create_studio_event', {
        p_title: params.title,
        p_event_date: params.event_date,
        p_start_time: params.start_time,
        p_end_time: params.end_time,
        p_description: params.description || null,
        p_color: params.color || '#ffffff',
      })
      if (error) throw error
      return data as { success: boolean; event_id: string; has_conflict: boolean }
    },
    onSuccess: (data) => {
      toast({
        title: 'Evento criado',
        description: data.has_conflict
          ? 'Aten├º├úo: h├í conflito de hor├írio com outro evento.'
          : 'Adicionado ao calend├írio do studio.',
        variant: data.has_conflict ? 'destructive' : 'default',
      })
      queryClient.invalidateQueries({ queryKey: ['studio-events'] })
    },
    onError: (error) => {
      logger.error('useStudioCalendar.create', error)
      toast({
        title: 'Erro ao criar evento',
        variant: 'destructive',
      })
    },
  })

  const updateEvent = useMutation({
    mutationFn: async (params: {
      event_id: string
      title: string
      event_date: string
      start_time: string
      end_time: string
      description?: string
      color?: string
    }) => {
      const { data, error } = await supabase.rpc('update_studio_event', {
        p_event_id: params.event_id,
        p_title: params.title,
        p_event_date: params.event_date,
        p_start_time: params.start_time,
        p_end_time: params.end_time,
        p_description: params.description || null,
        p_color: params.color || '#ffffff',
      })
      if (error) throw error
      return data
    },
    onSuccess: () => {
      toast({ title: 'Evento atualizado' })
      queryClient.invalidateQueries({ queryKey: ['studio-events'] })
    },
    onError: (error) => {
      logger.error('useStudioCalendar.update', error)
      toast({ title: 'Erro ao atualizar', variant: 'destructive' })
    },
  })

  const deleteEvent = useMutation({
    mutationFn: async (eventId: string) => {
      const { data, error } = await supabase.rpc('delete_studio_event', {
        p_event_id: eventId,
      })
      if (error) throw error
      return data
    },
    onSuccess: () => {
      toast({ title: 'Evento removido' })
      queryClient.invalidateQueries({ queryKey: ['studio-events'] })
    },
    onError: (error) => {
      logger.error('useStudioCalendar.delete', error)
      toast({ title: 'Erro ao remover', variant: 'destructive' })
    },
  })

  // Realtime updates
  useEffect(() => {
    const channel = supabase
      .channel('studio-calendar-realtime')
      .on(
        'postgres_changes',
        { event: '*', schema: 'public', table: 'studio_events' },
        () => {
          queryClient.invalidateQueries({ queryKey: ['studio-events'] })
        },
      )
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [queryClient])

  return {
    events: eventsQuery.data || [],
    isLoading: eventsQuery.isLoading,
    createEvent,
    updateEvent,
    deleteEvent,
    refetch: eventsQuery.refetch,
  }
}

export function useIsStudioMember() {
  const { user, role } = useAuth()

  const { data: isStudio } = useQuery({
    queryKey: ['is-studio-member', user?.id],
    queryFn: async () => {
      if (!user) return false
      if (role === 'admin') return true

      const { data } = await supabase
        .from('profiles')
        .select('subscription_tier, plan')
        .eq('id', user.id)
        .single()

      return data?.subscription_tier === 'studio' || data?.plan === 'studio'
    },
    enabled: !!user,
    staleTime: 1000 * 60 * 10,
  })

  return isStudio ?? false
}

import { useState, useMemo } from 'react'
import { useParams, useSearchParams } from 'react-router-dom'
import { supabase } from '@/integrations/supabase/client'
import { useQuery } from '@tanstack/react-query'
import { format, startOfWeek, addDays, parseISO, isSameDay } from 'date-fns'
import { ptBR } from 'date-fns/locale'
import { Calendar, CheckCircle, AlertCircle } from 'lucide-react'
import { PageLoader } from '@/components/ui/PageLoader'
import { Button } from '@/components/ui/button'

interface StudioEvent {
  id: string
  event_date: string
  start_time: string
  end_time: string
}

export default function StudioAvailabilityPage() {
  const { professionalId } = useParams<{ professionalId: string }>()
  const [searchParams] = useSearchParams()
  const weekParam = searchParams.get('week')

  const baseDate = useMemo(() => {
    if (weekParam) {
      try {
        return parseISO(weekParam)
      } catch (e) {
        return new Date()
      }
    }
    return new Date()
  }, [weekParam])

  const weekStart = startOfWeek(baseDate, { weekStartsOn: 0 })
  const weekDays = Array.from({ length: 7 }).map((_, i) => addDays(weekStart, i))

  const { data: professional, isLoading: loadingProf } = useQuery({
    queryKey: ['professional-profile', professionalId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('profiles')
        .select('full_name, id')
        .eq('id', professionalId)
        .single()
      if (error) throw error
      return data
    },
    enabled: !!professionalId,
  })

  const { data: events, isLoading: loadingEvents } = useQuery({
    queryKey: ['studio-availability', professionalId, weekParam],
    queryFn: async () => {
      const startDate = format(weekStart, 'yyyy-MM-dd')
      const endDate = format(addDays(weekStart, 6), 'yyyy-MM-dd')

      const { data, error } = await supabase
        .from('studio_events')
        .select('id, event_date, start_time, end_time')
        .eq('created_by', professionalId)
        .gte('event_date', startDate)
        .lte('event_date', endDate)

      if (error) throw error
      return (data as StudioEvent[]) || []
    },
    enabled: !!professionalId,
  })

  const timeSlots = Array.from({ length: 13 }).map((_, i) => ({
    hour: 8 + i,
    label: `${(8 + i).toString().padStart(2, '0')}:00`,
  }))

  const isSlotOccupied = (day: Date, hour: number) => {
    return events?.some((e) => {
      if (!isSameDay(parseISO(e.event_date), day)) return false
      if (!e.start_time || !e.end_time) return false
      const startH = parseInt(e.start_time.split(':')[0])
      const endH = parseInt(e.end_time.split(':')[0])
      return hour >= startH && hour < endH
    })
  }

  if (loadingProf || loadingEvents) return <PageLoader />

  if (!professional) {
    return (
      <div className="min-h-screen bg-black text-white flex items-center justify-center p-8">
        <div className="text-center space-y-4">
          <AlertCircle className="w-12 h-12 text-zinc-800 mx-auto" />
          <h1 className="text-xl font-serif">Profissional n├úo encontrado</h1>
          <p className="text-sm text-zinc-500 font-mono uppercase tracking-widest">
            Link inv├ílido ou expirado
          </p>
        </div>
      </div>
    )
  }

  const professionalFirstName = professional.full_name 
    ? professional.full_name.split(' ')[0] 
    : 'Profissional'

  return (
    <div className="min-h-screen bg-[#030303] text-white selection:bg-white selection:text-black font-sans pb-20">
      <header className="border-b border-white/5 bg-black/50 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 py-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 border border-white/10 bg-white/[0.03] flex items-center justify-center">
              <Calendar className="w-5 h-5 text-white/40" />
            </div>
            <div>
              <h1 className="text-sm font-semibold tracking-tight uppercase">
                Disponibilidade Studio
              </h1>
              <p className="text-[10px] font-mono text-white/30 uppercase tracking-[0.2em] mt-0.5">
                {professional.full_name || 'Profissional'}
              </p>
            </div>
          </div>
          <div className="hidden sm:flex items-center gap-2 px-3 py-1 border border-white/5 bg-white/[0.02]">
            <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse" />
            <span className="text-[9px] font-mono text-white/40 uppercase tracking-widest">Live Updates</span>
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-12">
        <div className="mb-12 text-center md:text-left">
          <h2 className="text-3xl md:text-4xl font-serif tracking-tight mb-2">
            Agenda Semanal
          </h2>
          <p className="text-zinc-500 font-mono text-xs uppercase tracking-[0.3em]">
            {format(weekStart, "dd 'de' MMM", { locale: ptBR })} ÔÇö {format(addDays(weekStart, 6), "dd 'de' MMM", { locale: ptBR })}
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-7 gap-4">
          {weekDays.map((day, i) => (
            <div key={i} className="space-y-4">
              <div className="text-center p-3 border border-white/5 bg-white/[0.02]">
                <p className="text-[10px] font-mono text-zinc-500 uppercase tracking-widest mb-1">
                  {format(day, 'EEEE', { locale: ptBR })}
                </p>
                <p className="text-lg font-serif">
                  {format(day, 'dd')}
                </p>
              </div>

              <div className="space-y-2">
                {timeSlots.map((slot) => {
                  const occupied = isSlotOccupied(day, slot.hour)
                  return (
                    <div
                      key={slot.label}
                      className={`p-3 border transition-all duration-300 flex flex-col items-center justify-center gap-1
                        ${occupied 
                          ? 'border-zinc-900 bg-zinc-900/10 text-zinc-700 opacity-40 grayscale' 
                          : 'border-white/5 bg-white/[0.01] hover:border-white/20 hover:bg-white/[0.03] text-white/70'
                        }`}
                    >
                      <span className="text-[10px] font-mono">{slot.label}</span>
                      <span className={`text-[8px] font-bold uppercase tracking-widest ${occupied ? '' : 'text-green-500/50'}`}>
                        {occupied ? 'Ocupado' : 'Livre'}
                      </span>
                    </div>
                  )
                })}
              </div>
            </div>
          ))}
        </div>

        <div className="mt-20 p-8 border border-white/5 bg-white/[0.01] text-center max-w-2xl mx-auto">
          <CheckCircle className="w-8 h-8 text-white/20 mx-auto mb-4" />
          <h3 className="text-lg font-serif mb-2">Gostou de algum hor├írio?</h3>
          <p className="text-sm text-zinc-500 mb-6 font-sans">
            Entre em contato diretamente para confirmar sua reserva no Studio.
          </p>
          <Button className="rounded-none bg-white text-black hover:bg-zinc-200 px-8 uppercase text-xs font-bold tracking-widest h-11">
            Falar com {professionalFirstName}
          </Button>
        </div>
      </main>

      <footer className="mt-auto py-10 border-t border-white/5 text-center">
        <p className="text-[9px] font-mono text-white/10 uppercase tracking-[0.4em]">
          Khaos Kontrol System ÔÇö Powering Modern Professionals
        </p>
      </footer>
    </div>
  )
}

