export const ClientsTable = () => {
  const [page, setPage] = useState(1)
  const limit = 50
  const parentRef = useRef<HTMLDivElement>(null)

  const { data: result, isLoading, error } = useClients(page, limit)
  const { mutate: deleteClient, isPending: _isDeleting } = useDeleteClient()
  const { searchTerm } = useUIStore()

  const clients = result?.data || []
  const totalCount = result?.count || 0
  const totalPages = Math.ceil(totalCount / limit)

  const filteredClients = clients.filter((client) => {
    if (!searchTerm) return true
    const term = searchTerm.toLowerCase()
    return (
      (client.name || '').toLowerCase().includes(term) ||
      (client.email || '').toLowerCase().includes(term)
    )
  })

  const rowVirtualizer = useVirtualizer({
    count: filteredClients.length,
    getScrollElement: () => parentRef.current,
    estimateSize: () => 64,
    overscan: 10,
  })

  const handleDelete = useCallback(
    (id: string, name: string) => {
      if (window.confirm(`CONFIRM DELETION OF TARGET: ${name}?`)) {
        deleteClient(id)
      }
    },
    [deleteClient],
  )

  if (isLoading) {
    return (
      <div className="space-y-4 p-4 border border-white/10 bg-black/50 animate-pulse text-white font-mono">
        LOADING_DATABASE...
      </div>
    )
  }

  if (error) {
    return (
      <div className="p-4 border border-red-500/20 bg-red-950/10 text-red-400 font-mono text-sm">
        SYSTEM_ERROR: {error.message}
      </div>
    )
  }

  if (!clients.length) {
    return (
      <div className="bg-white text-black border border-black flex flex-col">
        <div className="p-4 border-b border-black flex justify-end bg-gray-50">
          <CreateClientDialog />
        </div>
        <div className="p-12 font-mono text-sm text-black/40 text-center uppercase tracking-widest">
          NO_RECORDS_IN_DATABASE
        </div>
      </div>
    )
  }

  return (
    <div className="bg-white text-black border border-black flex flex-col">
      <div className="p-4 border-b border-black flex justify-between items-center bg-gray-50">
        <span className="font-mono text-xs uppercase text-gray-500 tracking-wider">
          Total Records:{' '}
          <span className="text-black font-bold">{totalCount}</span>
        </span>
        <CreateClientDialog />
      </div>

      <div
        ref={parentRef}
        className="h-[600px] overflow-auto relative scrollbar-thin scrollbar-thumb-black scrollbar-track-transparent border-b border-black"
      >
        <div
          style={{
            height: `${rowVirtualizer.getTotalSize()}px`,
            width: '100%',
            position: 'relative',
          }}
        >
          <Table>
            <TableHeader className="bg-gray-100 border-b-2 border-black sticky top-0 z-10 w-full">
              <TableRow className="border-black hover:bg-transparent bg-gray-100 flex w-full">
                <TableHead className="font-bold text-xs uppercase tracking-wider text-black w-[30%] flex items-center border-r border-black/10">
                  NOME
                </TableHead>
                <TableHead className="font-bold text-xs uppercase tracking-wider text-black flex-1 flex items-center border-r border-black/10">
                  EMAIL
                </TableHead>
                <TableHead className="font-bold text-xs uppercase tracking-wider text-black flex-1 flex items-center border-r border-black/10">
                  TELEFONE
                </TableHead>
                <TableHead className="font-bold text-xs uppercase tracking-wider text-black flex-1 flex items-center border-r border-black/10">
                  DATA DO EVENTO
                </TableHead>
                <TableHead className="font-bold text-xs uppercase tracking-wider text-black w-[80px] flex items-center justify-center border-r border-black/10">
                  DOCS
                </TableHead>
                <TableHead className="font-bold text-xs uppercase tracking-wider text-black w-[100px] flex items-center justify-end pr-4">
                  A├ç├òES
                </TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {rowVirtualizer.getVirtualItems().map((virtualRow) => {
                const client = filteredClients[virtualRow.index]
                if (!client) return null

                return (
                  <ClientRow
                    key={virtualRow.key}
                    client={client}
                    virtualRow={virtualRow}
                    onDelete={handleDelete}
                  />
                )
              })}
            </TableBody>
          </Table>
        </div>
      </div>

      <Pagination
        currentPage={page}
        totalPages={totalPages}
        onPageChange={setPage}
        isLoading={isLoading}
      />
    </div>
  )
}

import { useState } from 'react'
import { supabase } from '@/integrations/supabase/client'
import { useToast } from '@/hooks/use-toast'
import { useOrganization } from '@/hooks/useOrganization'
import { exportClientsToCSV } from '@/utils/exportCSV'
import { toast as sonnerToast } from 'sonner'
import { format } from 'date-fns/format'
import { ptBR } from 'date-fns/locale'
import type { ClientFormData } from '../components/ClientForm'
import { getErrorMessage } from '@/utils/error-handler'
import { useClientMutations } from './useClientMutations'
import { useDeleteClient } from './useDeleteClient'

export interface ClientRecord {
  id: string
  name: string
  email: string | null
  phone: string | null
  avatar_url: string | null
  notes: string | null
  last_visit: string | null
  created_at: string
  user_id: string
  is_bride?: boolean
  wedding_date?: string | null
  access_pin?: string | null
  portal_link?: string | null
}

interface UseClientActionsProps {
  fetchClients: () => void
  clients: ClientRecord[]
}

export function useClientActions({
  fetchClients,
  clients,
}: UseClientActionsProps) {
  const { organizationId } = useOrganization()
  const { toast } = useToast()

  const { createMutation, updateMutation } = useClientMutations()
  const { mutateAsync: deleteClient } = useDeleteClient()

  const [isDialogOpen, setIsDialogOpen] = useState(false)
  const [editingClient, setEditingClient] = useState<ClientRecord | null>(null)
  const [isExporting, setIsExporting] = useState(false)

  const openEditDialog = (client: ClientRecord) => {
    setEditingClient(client)
    setIsDialogOpen(true)
  }

  const handleFormSubmit = async (formData: ClientFormData) => {
    if (!organizationId) {
      toast({ title: 'Erro de organiza├º├úo', variant: 'destructive' })
      return
    }

    const clientData = {
      full_name: formData.name.trim(),
      name: formData.name.trim(),
      email: formData.email.trim() || null,
      phone: formData.phone.trim() || null,
      notes: formData.notes.trim() || null,
      user_id: organizationId,
      is_bride: Boolean(formData.is_bride),
      wedding_date: formData.wedding_date
        ? new Date(formData.wedding_date).toISOString()
        : null,
      access_pin: formData.access_pin
        ? String(formData.access_pin).trim() || null
        : null,
    }

    try {
      if (editingClient) {
        await updateMutation.mutateAsync({
          id: editingClient.id,
          data: clientData,
        })
      } else {
        await createMutation.mutateAsync(clientData)
      }

      setIsDialogOpen(false)
      setEditingClient(null)
      fetchClients()
    } catch (_error) {}
  }

  const handleDelete = async (id: string) => {
    if (!confirm('Tem certeza que deseja excluir este cliente?')) return

    try {
      await deleteClient(id)
      fetchClients()
    } catch (_error) {}
  }

  const copyPortalLink = async (clientId: string) => {
    try {
      const { data: client, error: clientError } = await supabase
        .from('wedding_clients')
        .select('access_pin')
        .eq('id', clientId)
        .single()

      if (clientError) throw clientError

      if (!client?.access_pin) {
        const newPin = Math.floor(1000 + Math.random() * 9000).toString()
        const { error: updateError } = await supabase
          .from('wedding_clients')
          .update({ access_pin: newPin })
          .eq('id', clientId)
        if (updateError) throw updateError
        toast({ title: 'PIN Gerado', description: `Novo PIN: ${newPin}` })
      }

      const link = `${window.location.origin}/portal/${clientId}/login`
      await navigator.clipboard.writeText(link)
      toast({
        title: 'Link do Portal Copiado!',
        description: 'Envie este link para a noiva.',
      })
    } catch (error) {
      const { title, description } = getErrorMessage(
        error,
        'Erro ao gerar link',
      )
      toast({
        title,
        description,
        variant: 'destructive',
      })
    }
  }

  const handleExportCSV = async () => {
    if (clients.length === 0) {
      sonnerToast.error('Nenhum cliente para exportar')
      return
    }

    setIsExporting(true)
    try {
      const result = exportClientsToCSV(clients)
      if (result.success) {
        sonnerToast.success('Arquivo CSV exportado com sucesso!')
      } else {
        sonnerToast.error(result.error || 'Erro ao exportar')
      }
    } catch (_error) {
      sonnerToast.error('Erro inesperado na exporta├º├úo')
    } finally {
      setIsExporting(false)
    }
  }

  const formatDate = (dateString: string | null) => {
    if (!dateString) return 'Nunca'
    try {
      return format(new Date(dateString), "d 'de' MMM, yyyy", { locale: ptBR })
    } catch (_e) {
      return 'Data inv├ílida'
    }
  }

  return {
    isDialogOpen,
    setIsDialogOpen,
    editingClient,
    setEditingClient,
    isExporting,
    openEditDialog,
    handleFormSubmit,
    handleDelete,
    copyPortalLink,
    handleExportCSV,
    formatDate,
  }
}

import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { supabase } from '@/integrations/supabase/client'
import { logger } from '@/services/logger'
import { generateClientPDF } from '@/services/reportService'
import { useToast } from '@/hooks/use-toast'
import {
  ClientService,
  Client,
  TreatmentRecord,
} from '@/features/clients/api/clientService'
import { ReportProject } from '@/types/service-types'

export interface EventWithServices {
  id: string
  event_date: string
  title?: string
  location?: string
  status?: string
  total_value?: number
  project_services?: Array<{
    id: string
    quantity: number
    unit_price: number
    total_price: number
    services: { name: string }
  }>
}

export function useClientDetails(id: string | undefined) {
  const navigate = useNavigate()
  const { toast } = useToast()
  const [client, setClient] = useState<Client | null>(null)
  const [records, setRecords] = useState<TreatmentRecord[]>([])
  const [events, setEvents] = useState<EventWithServices[]>([])
  const [loadingData, setLoadingData] = useState(true)

  useEffect(() => {
    if (id) {
      fetchData()
    }
  }, [id])

  const fetchData = async () => {
    if (!id) return
    setLoadingData(true)

    try {
      const { data: clientData, error: clientError } =
        await ClientService.get(id)

      if (clientError || !clientData) {
        toast({ title: 'Cliente n├úo encontrado', variant: 'destructive' })
        navigate('/clientes')
        return
      }

      setClient(clientData as Client)

      const { data: recordsData } = await ClientService.getTreatmentRecords(id)
      setRecords(recordsData || [])

      const { data: eventsData, error: eventsError } = await supabase
        .from('events')
        .select(
          `
                    id,
                    event_date,
                    title,
                    location,
                    status,
                    total_value,
                    project_services (
                        id,
                        quantity,
                        unit_price,
                        total_price,
                        services (name)
                    )
                `,
        )
        .eq('client_id', id)
        .order('event_date', { ascending: false })

      if (eventsError) throw eventsError

      if (eventsData) {
        setEvents(eventsData)
      }
    } catch (error) {
      logger.error(error, 'useClientDetails.fetchData', { showToast: false })
      toast({
        title: 'Erro ao carregar dados',
        description: 'N├úo foi poss├¡vel carregar as informa├º├Áes do cliente.',
        variant: 'destructive',
      })
    } finally {
      setLoadingData(false)
    }
  }

  const handleExportPDF = () => {
    if (!client) return

    const reportProjects: ReportProject[] = events.map((e) => ({
      title: e.title || 'Evento sem t├¡tulo',
      event_date: e.event_date,
      location: e.location || null,
      status: e.status || 'N/A',
      total_value: e.total_value,
      project_services: e.project_services?.map((ps) => ({
        name: ps.services.name,
        quantity: ps.quantity,
        unit_price: ps.unit_price,
        total_price: ps.total_price,
        services: ps.services,
      })),
    }))

    generateClientPDF(client, reportProjects)
    toast({
      title: 'Relat├│rio gerado',
      description: 'O PDF do hist├│rico foi baixado com sucesso.',
    })
  }

  const deleteRecord = async (recordId: string) => {
    try {
      const typedSupabase = supabase
      const { error } = await typedSupabase
        .from('treatment_records' as never)
        .delete()
        .eq('id', recordId)

      if (error) throw error

      toast({
        title: 'Registro exclu├¡do',
        description: 'O registro foi removido com sucesso.',
      })
      fetchData()
    } catch (error) {
      logger.error(error, 'useClientDetails.deleteRecord', { showToast: false })
      toast({
        title: 'Erro',
        description: 'N├úo foi poss├¡vel excluir o registro.',
        variant: 'destructive',
      })
    }
  }

  return {
    client,
    records,
    loadingData,
    events,
    fetchData,
    handleExportPDF,
    deleteRecord,
  }
}

import { useMutation, useQueryClient } from '@tanstack/react-query'
import { supabase } from '@/integrations/supabase/client'
import { ClientService } from '../api/clientService'
import { QUERY_KEYS } from '@/constants/queryKeys'
import { useToast } from '@/hooks/use-toast'
import { logger } from '@/services/logger'

export function useClientMutations() {
  const queryClient = useQueryClient()
  const { toast } = useToast()

  const createMutation = useMutation({
    mutationFn: async (clientData: any) => {
      const newClient = await ClientService.create(clientData)

      if (clientData.is_bride && newClient && 'id' in newClient) {
        const link = `https://khaoskontrol.com.br/portal/${newClient.id}`
        await ClientService.update(newClient.id, { portal_link: link })
      }

      if (clientData.is_bride && clientData.email && newClient?.id) {
        try {
          await supabase.functions.invoke('send-welcome-email', {
            body: {
              clientId: newClient.id,
              subject: 'Bem-vinda ao KONTROL',
            },
          })
        } catch (emailErr) {
          logger.error(emailErr, 'useClientMutations.create.email')
        }
      }

      return newClient
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [QUERY_KEYS.CLIENTS] })
      queryClient.invalidateQueries({ queryKey: [QUERY_KEYS.DASHBOARD_STATS] })
      toast({ title: 'Cliente adicionado!' })
    },
    onError: (error) => {
      logger.error(error, 'useClientMutations.create')
      toast({
        title: 'Erro ao adicionar cliente',
        description:
          error instanceof Error ? error.message : 'Ocorreu um erro inesperado',
        variant: 'destructive',
      })
    },
  })

  const updateMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string; data: any }) => {
      if (data.is_bride) {
        data.portal_link = `https://khaoskontrol.com.br/portal/${id}`
      }

      const result = await ClientService.update(id, data)

      if (data.is_bride && data.wedding_date) {
        await supabase
          .from('projects')
          .update({ event_date: data.wedding_date })
          .eq('client_id', id)
      }

      return result
    },
    onSuccess: (_, variables) => {
      queryClient.invalidateQueries({ queryKey: [QUERY_KEYS.CLIENTS] })
      queryClient.invalidateQueries({ queryKey: ['client', variables.id] })
      queryClient.invalidateQueries({ queryKey: [QUERY_KEYS.DASHBOARD_STATS] })
      toast({ title: 'Cliente atualizado!' })
    },
    onError: (error) => {
      logger.error(error, 'useClientMutations.update')
      toast({
        title: 'Erro ao atualizar cliente',
        description:
          error instanceof Error ? error.message : 'Ocorreu um erro inesperado',
        variant: 'destructive',
      })
    },
  })

  return {
    createMutation,
    updateMutation,
  }
}

import { useMutation, useQueryClient } from '@tanstack/react-query'
import { supabase } from '@/integrations/supabase/client'
import { useToast } from '@/hooks/use-toast'
import { logger } from '@/services/logger'
import { sanitizeFormData } from '@/lib/security'

export function useContractMutations() {
  const queryClient = useQueryClient()
  const { toast } = useToast()

  const createMutation = useMutation({
    mutationFn: async (contractData: any) => {
      const cleanData = sanitizeFormData(contractData)
      const { data, error } = await supabase
        .from('contracts')
        .insert(cleanData)
        .select()
        .single()

      if (error) throw error
      return data
    },
    onSuccess: (_, variables) => {
      queryClient.invalidateQueries({ queryKey: ['contracts'] })
      if (variables.project_id) {
        queryClient.invalidateQueries({
          queryKey: ['project', variables.project_id],
        })
      }
      toast({ title: 'Contrato criado com sucesso!' })
    },
    onError: (error) => {
      logger.error(error, 'useContractMutations.create')
      toast({
        title: 'Erro ao criar contrato',
        variant: 'destructive',
      })
    },
  })

  const updateMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string; data: any }) => {
      const cleanData = sanitizeFormData(data)
      const { data: result, error } = await supabase
        .from('contracts')
        .update(cleanData)
        .eq('id', id)
        .select()
        .single()

      if (error) throw error
      return result
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ['contracts'] })
      queryClient.invalidateQueries({ queryKey: ['contract', data.id] })
      if (data.project_id) {
        queryClient.invalidateQueries({
          queryKey: ['project', data.project_id],
        })
      }
      toast({ title: 'Contrato atualizado!' })
    },
    onError: (error) => {
      logger.error(error, 'useContractMutations.update')
      toast({
        title: 'Erro ao atualizar contrato',
        variant: 'destructive',
      })
    },
  })

  const signMutation = useMutation({
    mutationFn: async ({
      id,
      signature_url,
      project_id,
    }: {
      id: string
      signature_url: string
      project_id?: string
    }) => {
      const { error } = await supabase
        .from('contracts')
        .update({
          status: 'signed',
          signature_url,
          signed_at: new Date().toISOString(),
        })
        .eq('id', id)

      if (error) throw error
      return { id, project_id }
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ['contracts'] })
      queryClient.invalidateQueries({ queryKey: ['contract', data.id] })
      if (data.project_id) {
        queryClient.invalidateQueries({
          queryKey: ['project', data.project_id],
        })
      }
      toast({ title: 'Contrato assinado com sucesso!' })
    },
    onError: (error) => {
      logger.error(error, 'useContractMutations.sign')
      toast({
        title: 'Erro ao assinar contrato',
        variant: 'destructive',
      })
    },
  })

  const deleteMutation = useMutation({
    mutationFn: async ({
      id,
      project_id,
    }: {
      id: string
      project_id?: string
    }) => {
      const { error } = await supabase.from('contracts').delete().eq('id', id)

      if (error) throw error
      return { id, project_id }
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ['contracts'] })
      if (data.project_id) {
        queryClient.invalidateQueries({
          queryKey: ['project', data.project_id],
        })
      }
      toast({ title: 'Contrato exclu├¡do!' })
    },
    onError: (error) => {
      logger.error(error, 'useContractMutations.delete')
      toast({
        title: 'Erro ao excluir contrato',
        variant: 'destructive',
      })
    },
  })

  return {
    createMutation,
    updateMutation,
    signMutation,
    deleteMutation,
  }
}

import { useState, useEffect } from 'react'
import { supabase } from '@/integrations/supabase/client'
import { useAuth } from '@/hooks/useAuth'
import { toast } from 'sonner'
import { logger } from '@/services/logger'
import { Contract, Client } from '../types'
import { deletePhotoSafely, uploadImageSafely } from '@/lib/upload'
import { useContractsQuery } from './useContractsQuery'
import { useContractMutations } from './useContractMutations'

export const useContracts = () => {
  const { user } = useAuth()
  const { data: contractsData = [], isLoading: loading } = useContractsQuery()
  const { createMutation, signMutation } = useContractMutations()

  const [searchTerm, setSearchTerm] = useState('')
  const [statusFilter, setStatusFilter] = useState('all')

  const [isDialogOpen, setIsDialogOpen] = useState(false)
  const [newTitle, setNewTitle] = useState('')
  const [newClient, setNewClient] = useState('')
  const [newContent, setNewContent] = useState('')
  const [clients, setClients] = useState<Client[]>([])

  const [signatureOpen, setSignatureOpen] = useState(false)
  const [selectedContract, setSelectedContract] = useState<Contract | null>(
    null,
  )

  useEffect(() => {
    if (user) {
      fetchClients()
    }
  }, [user])

  const fetchClients = async () => {
    const { data } = await supabase
      .from('wedding_clients')
      .select('id, name:full_name')
      .order('full_name')
    if (data) setClients(data)
  }

  const handleCreate = async () => {
    if (!newTitle || !newClient) {
      toast.error('Preencha todos os campos obrigat├│rios')
      return
    }

    try {
      await createMutation.mutateAsync({
        user_id: user?.id,
        title: newTitle,
        client_id: newClient,
        content: newContent || 'Conte├║do do contrato...',
        status: 'draft',
      })
      setIsDialogOpen(false)
      setNewTitle('')
      setNewClient('')
      setNewContent('')
    } catch (_error) {}
  }

  const handleSignatureSave = async (dataUrl: string) => {
    if (!selectedContract) return

    let publicUrl: string | null = null
    try {
      const fileName = `${selectedContract.id}_signature_${Date.now()}.png`
      const blob = await fetch(dataUrl).then((res) => res.blob())
      const file = new File([blob], fileName, { type: 'image/png' })

      publicUrl = await uploadImageSafely(
        file,
        'contract-signatures',
        'signatures',
      )

      await signMutation.mutateAsync({
        id: selectedContract.id,
        signature_url: publicUrl,
        project_id: selectedContract.project_id,
      })

      setSignatureOpen(false)
    } catch (error) {
      if (publicUrl) {
        await deletePhotoSafely(publicUrl, 'contract-signatures')
      }
      logger.error(error, 'useContracts.handleSignatureSave')
      toast.error('Erro ao salvar assinatura')
    }
  }

  const filteredContracts = (contractsData as Contract[]).filter((c) => {
    const matchesSearch =
      c.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.clients?.name?.toLowerCase().includes(searchTerm.toLowerCase())
    const matchesStatus = statusFilter === 'all' || c.status === statusFilter
    return matchesSearch && matchesStatus
  })

  return {
    contracts: contractsData as Contract[],
    filteredContracts,
    loading,
    searchTerm,
    setSearchTerm,
    statusFilter,
    setStatusFilter,
    isDialogOpen,
    setIsDialogOpen,
    isSubmitting: createMutation.isPending || signMutation.isPending,
    newTitle,
    setNewTitle,
    newClient,
    setNewClient,
    newContent,
    setNewContent,
    clients,
    signatureOpen,
    setSignatureOpen,
    selectedContract,
    setSelectedContract,
    handleCreate,
    handleSignatureSave,
  }
}

import SEOHead from '@/components/seo/SEOHead'
