  const [isDialogOpen, setIsDialogOpen] = useState(false)

  useEffect(() => {
    fetchContracts()
  }, [])

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'signed':
        return (
          <Badge className="bg-white text-black border-white rounded-none font-mono uppercase text-[10px] tracking-widest hover:bg-white/90">
            ASSINADO
          </Badge>
        )
      case 'sent':
        return (
          <Badge className="bg-transparent text-white border-white/40 rounded-none font-mono uppercase text-[10px] tracking-widest hover:border-white">
            ENVIADO
          </Badge>
        )
      default:
        return (
          <Badge className="bg-white/5 text-white/50 border-white/10 rounded-none font-mono uppercase text-[10px] tracking-widest hover:bg-white/10">
            PENDENTE
          </Badge>
        )
    }
  }

  return (
    <div className="container mx-auto px-4 py-8 space-y-8">
      <SEOHead title="Contratos" noindex={true} />
      <div className="flex justify-between items-center border-b border-white/10 pb-6">
        <div>
          <h1 className="text-3xl font-serif font-light text-white mb-2 tracking-wide uppercase">
            {t('pages.contracts.title')}
          </h1>
          <p className="text-white/40 font-mono text-xs uppercase tracking-widest">
            {t('pages.contracts.subtitle')}
          </p>
        </div>
        <Button
          onClick={() => setIsDialogOpen(true)}
          className="bg-white text-black hover:bg-white/90 rounded-none font-mono text-xs uppercase tracking-widest font-bold h-10 px-6"
        >
          <Plus className="w-4 h-4 mr-2" />
          {t('pages.contracts.new')}
        </Button>
      </div>

      {loading ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {[1, 2, 3].map((i) => (
            <div
              key={i}
              className="h-48 bg-white/5 animate-pulse rounded-none border border-white/10"
            />
          ))}
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {contracts.map((contract) => (
            <Card
              key={contract.id}
              className="bg-[#050505] border-white/10 hover:border-white/30 transition-all rounded-none group"
            >
              <CardHeader className="pb-4 border-b border-white/5">
                <div className="flex justify-between items-start">
                  <div className="w-10 h-10 border border-white/10 bg-black flex items-center justify-center mb-0 group-hover:border-white/40 transition-colors">
                    <FileText className="w-4 h-4 text-white" />
                  </div>
                  {getStatusBadge(contract.status)}
                </div>
                <div className="mt-4">
                  <CardTitle className="text-white text-lg font-serif font-light tracking-wide line-clamp-1">
                    {contract.title}
                  </CardTitle>
                  <CardDescription className="text-white/40 font-mono text-[10px] uppercase tracking-widest flex items-center gap-2 mt-2">
                    <User className="w-3 h-3" />
                    {contract.project?.name || 'SEM PROJETO'}
                  </CardDescription>
                </div>
              </CardHeader>
              <CardContent className="pt-4">
                <div className="space-y-6">
                  <div className="text-[10px] text-white/30 font-mono uppercase tracking-widest flex items-center gap-2">
                    <Calendar className="w-3 h-3" />
                    CRIADO EM{' '}
                    {formatDate(
                      contract.created_at,
                      DATE_FORMATS.DISPLAY,
                    ).toUpperCase()}
                  </div>

                  <div className="flex gap-3">
                    <Button
                      variant="outline"
                      className="flex-1 border-white/10 hover:bg-white hover:text-black text-white rounded-none font-mono text-[10px] uppercase tracking-widest h-9 bg-transparent transition-all"
                      onClick={() =>
                        window.open(
                          `/projects/${contract.project_id}/contract`,
                          '_blank',
                        )
                      }
                    >
                      <Eye className="w-3 h-3 mr-2" />
                      VISUALIZAR
                    </Button>

                    {contract.status === 'signed' && (
                      <Button
                        variant="outline"
                        className="border-white/10 hover:bg-white hover:text-black text-white rounded-none w-9 h-9 p-0 bg-transparent transition-all flex items-center justify-center"
                        onClick={() => {
                          window.open(
                            `/projects/${contract.project_id}/contract`,
                            '_blank',
                          )
                        }}
                      >
                        <Download className="w-3 h-3" />
                      </Button>
                    )}
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}

          {contracts.length === 0 && (
            <div className="col-span-full py-16 text-center border border-dashed border-white/10 rounded-none bg-white/[0.02]">
              <FileText className="w-10 h-10 mx-auto mb-4 text-white/20" />
              <p className="text-white/40 font-mono text-xs uppercase tracking-widest">
                {t('pages.contracts.no_pending')}
              </p>
            </div>
          )}
        </div>
      )}

      <ContractDialog
        open={isDialogOpen}
        onOpenChange={(open) => {
          setIsDialogOpen(open)
          if (!open) fetchContracts()
        }}
      />
    </div>
  )
}

import { useState } from 'react'
import { supabase } from '@/integrations/supabase/client'
import { useToast } from '@/hooks/use-toast'
import { useOrganization } from '@/hooks/useOrganization'
import { useAuth } from '@/hooks/useAuth'
import { ProjectService } from '../api/projectService'

import { generateWhatsAppLink } from '@/utils/whatsappGenerator'
import { format } from 'date-fns/format'
import type {
  Task,
  ProjectServiceItem,
  ProjectWithRelations,
  ServiceUI,
} from '@/types/api.types'
import { getErrorMessage } from '@/utils/error-handler'
import { useProjectMutations } from './useProjectMutations'

interface UseProjectActionsProps {
  projectId: string | undefined
  project: ProjectWithRelations | null
  tasks: Task[]
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>
  services: ServiceUI[]
  projectServices: ProjectServiceItem[]
  refetch: () => void
}

export function useProjectActions({
  projectId,
  project,
  tasks,
  setTasks,
  services,
  projectServices,
  refetch,
}: UseProjectActionsProps) {
  const { user } = useAuth()
  const { organizationId } = useOrganization()
  const { toast } = useToast()

  const {
    createTaskMutation,
    updateTaskMutation,
    deleteTaskMutation,
    addServiceMutation,
    removeServiceMutation,
    registerPaymentMutation,
  } = useProjectMutations()

  const [newTaskTitle, setNewTaskTitle] = useState('')
  const [copied, setCopied] = useState(false)

  const [isServiceDialogOpen, setIsServiceDialogOpen] = useState(false)
  const [selectedServiceId, setSelectedServiceId] = useState('')
  const [serviceQuantity, setServiceQuantity] = useState('1')
  const [servicePrice, setServicePrice] = useState('')

  const [isPaymentDialogOpen, setIsPaymentDialogOpen] = useState(false)
  const [paymentServiceId, setPaymentServiceId] = useState('')
  const [paymentAmount, setPaymentAmount] = useState('')
  const [paymentDescription, setPaymentDescription] = useState('')

  const addTask = async (e?: React.FormEvent) => {
    if (e) e.preventDefault()
    if (!newTaskTitle.trim() || !projectId || !organizationId) return

    try {
      await createTaskMutation.mutateAsync({
        project_id: projectId,
        user_id: organizationId,
        title: newTaskTitle.trim(),
        status: 'pending',
        sort_order: tasks.length,
      })
      setNewTaskTitle('')
      refetch()
    } catch (_error) {}
  }

  const toggleTask = async (taskId: string, currentStatus: string | null) => {
    const newStatus = currentStatus === 'completed' ? 'pending' : 'completed'
    try {
      await updateTaskMutation.mutateAsync({
        id: taskId,
        project_id: projectId || '',
        data: { status: newStatus },
      })
      setTasks(
        tasks.map((t) => (t.id === taskId ? { ...t, status: newStatus } : t)),
      )
    } catch (_error) {}
  }

  const deleteTask = async (taskId: string) => {
    if (!projectId) return
    try {
      await deleteTaskMutation.mutateAsync({
        id: taskId,
        project_id: projectId,
      })
      setTasks(tasks.filter((t) => t.id !== taskId))
    } catch (_error) {}
  }

  const copyPortalLink = async () => {
    if (!project?.client?.id) {
      toast({
        title: 'Erro',
        description: 'Cliente n├úo vinculado ao projeto.',
        variant: 'destructive',
      })
      return
    }

    try {
      const clientId = project.client.id
      const { data: clientData, error } = await supabase
        .from('wedding_clients')
        .select('access_pin, secret_code')
        .eq('id', clientId)
        .single()

      if (error || !clientData) {
        throw new Error('Cliente n├úo encontrado.')
      }

      if (!clientData.secret_code) {
        throw new Error('Cliente sem c├│digo de acesso gerado.')
      }

      const { secret_code } = clientData
      const link = `${window.location.origin}/portal/${secret_code}`
      await navigator.clipboard.writeText(link)
      setCopied(true)
      toast({
        title: 'Link Copiado!',
        description: 'Link enviado para a ├írea de transfer├¬ncia.',
      })
      setTimeout(() => setCopied(false), 2000)
    } catch (error) {
      const { title, description } = getErrorMessage(
        error,
        'Erro ao gerar link',
      )
      toast({ title, description, variant: 'destructive' })
    }
  }

  const handleSendReminder = async () => {
    if (!project || !project.client || !user) return

    if (!project.client.phone) {
      toast({
        title: 'Cliente sem telefone cadastrado',
        variant: 'destructive',
      })
      return
    }

    try {
      const { data: templateData } = await supabase
        .from('message_templates')
        .select('content')
        .eq('organization_id', organizationId)
        .eq('type', 'reminder_24h')
        .single()

      const textPattern =
        templateData?.content ||
        'Ol├í {client_name}, passando para lembrar do seu agendamento dia {date} ├ás {time}.'

      let professionalName = 'Khaos Kontrol'
      const { data: profData } = await supabase
        .from('profiles')
        .select('full_name')
        .eq('id', user.id)
        .single()

      if (profData?.full_name) professionalName = profData.full_name

      const eventDateObj = project.event_date
        ? new Date(project.event_date)
        : null
      const dateStr = eventDateObj
        ? format(eventDateObj, 'dd/MM')
        : 'Data a definir'
      const timeStr = eventDateObj
        ? format(eventDateObj, 'HH:mm')
        : 'Hor├írio a definir'

      const link = generateWhatsAppLink(textPattern, {
        client_name: project.client.full_name || 'Cliente',
        professional_name: professionalName,
        date: dateStr,
        time: timeStr,
        location: project.event_location || 'Local a definir',
        phone: project.client.phone,
      })

      window.open(link, '_blank')
    } catch (error) {
      const { title, description } = getErrorMessage(
        error,
        'Erro ao gerar link',
      )
      toast({ title, description, variant: 'destructive' })
    }
  }

  const createDefaultBriefing = async () => {
    if (!projectId || !organizationId) return

    const defaultQuestions = [
      {
        id: '1',
        question: 'Qual ├® o seu tipo de pele? (oleosa, seca, mista, normal)',
        type: 'text',
      },
      {
        id: '2',
        question: 'Voc├¬ tem alguma alergia a cosm├®ticos?',
        type: 'text',
      },
      {
        id: '3',
        question: 'Qual estilo de maquiagem voc├¬ prefere?',
        type: 'text',
      },
      { id: '4', question: 'Quais cores voc├¬ gostaria de usar?', type: 'text' },
      { id: '5', question: 'Voc├¬ usar├í c├¡lios posti├ºos?', type: 'text' },
      { id: '6', question: 'Alguma observa├º├úo adicional?', type: 'text' },
    ]

    const { error } = await ProjectService.createBriefing({
      project_id: projectId,
      status: 'pending',
      user_id: organizationId,
      content: { questions: defaultQuestions },
    })

    if (!error) {
      toast({ title: 'Question├írio criado!' })
      refetch()
    }
  }

  const addServiceToProject = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!selectedServiceId || !projectId || !organizationId) return

    const service = services.find((s) => s.id === selectedServiceId)
    if (!service) return

    const qty = parseInt(serviceQuantity) || 1
    const priceStr = service.price ? String(service.price) : '0'
    const price = servicePrice ? parseFloat(servicePrice) : parseFloat(priceStr)
    const total = qty * price

    try {
      await addServiceMutation.mutateAsync({
        project_id: projectId,
        service_id: selectedServiceId,
        quantity: qty.toString(),
        unit_price: price,
        total_price: total.toString(),
      })
      setIsServiceDialogOpen(false)
      setSelectedServiceId('')
      setServiceQuantity('1')
      setServicePrice('')
      refetch()
    } catch (_error) {}
  }

  const removeServiceFromProject = async (projectServiceId: string) => {
    if (!projectId) return
    try {
      await removeServiceMutation.mutateAsync({
        id: projectServiceId,
        project_id: projectId,
      })
      refetch()
    } catch (_error) {}
  }

  const registerPayment = async (e: React.FormEvent) => {
    e.preventDefault()

    const cleanAmount =
      typeof paymentAmount === 'string'
        ? parseFloat(
            paymentAmount.replace('R$', '').replace('.', '').replace(',', '.'),
          )
        : parseFloat(paymentAmount)

    if (isNaN(cleanAmount)) {
      toast({ title: 'Valor inv├ílido', variant: 'destructive' })
      return
    }

    if (
      !projectId ||
      (!project?.client_id && !project?.client?.id) ||
      !organizationId
    ) {
      toast({
        title: 'Erro interno',
        description: 'Identifica├º├úo do projeto ou usu├írio ausente.',
        variant: 'destructive',
      })
      return
    }

    const ps = projectServices.find((s) => s.id === paymentServiceId)
    const finalDescription =
      paymentDescription.trim() ||
      (ps ? `Pagamento: ${ps.service?.name}` : 'Pagamento Geral')

    const payload = {
      project_id: projectId,
      client_id: project.client_id || project.client?.id,
      amount: cleanAmount,
      description: finalDescription,
      type: 'income',
      status: 'completed',
      user_id: organizationId,
      date: new Date().toISOString(),
      category: 'Projeto',
    }

    try {
      await registerPaymentMutation.mutateAsync(payload)
      setIsPaymentDialogOpen(false)
      setPaymentServiceId('')
      setPaymentAmount('')
      setPaymentDescription('')
      refetch()
    } catch (_error) {}
  }

  const handleSelectService = (serviceId: string) => {
    setSelectedServiceId(serviceId)
    const service = services.find((s) => s.id === serviceId)
    if (service?.price) {
      setServicePrice(service.price.toString())
    }
  }

  return {
    newTaskTitle,
    setNewTaskTitle,
    copied,
    isServiceDialogOpen,
    setIsServiceDialogOpen,
    selectedServiceId,
    serviceQuantity,
    setServiceQuantity,
    servicePrice,
    setServicePrice,
    isPaymentDialogOpen,
    setIsPaymentDialogOpen,
    paymentServiceId,
    setPaymentServiceId,
    paymentAmount,
    setPaymentAmount,
    paymentDescription,
    setPaymentDescription,
    addTask,
    toggleTask,
    deleteTask,
    copyPortalLink,
    handleSendReminder,
    createDefaultBriefing,
    addServiceToProject,
    removeServiceFromProject,
    registerPayment,
    handleSelectService,
  }
}

import { useQuery, useQueryClient } from '@tanstack/react-query'
import { useEffect } from 'react'
import { ProjectService as ProjectServiceClass } from '../api/projectService'

import { supabase } from '@/integrations/supabase/client'
import type {
  ProjectDetailsResponse,
  ProjectWithRelations,
  BriefingUI,
  BriefingContent,
  ServiceUI,
} from '@/types/api.types'
import type { Database } from '@/integrations/supabase/types'

type LocalProjectWithRelations =
  Database['public']['Tables']['projects']['Row'] & {
    client: Database['public']['Tables']['wedding_clients']['Row'] | null
  }

export const useProjectDetails = (projectId: string | undefined) => {
  const queryClient = useQueryClient()

  useEffect(() => {
    if (!projectId) return

    const channel = supabase
      .channel(`project-details-${projectId}`)
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'projects',
          filter: `id=eq.${projectId}`,
        },
        () => {
          queryClient.invalidateQueries({ queryKey: ['project', projectId] })
        },
      )
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'contracts',
          filter: `project_id=eq.${projectId}`,
        },
        () => {
          queryClient.invalidateQueries({ queryKey: ['project', projectId] })
        },
      )
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'transactions',
          filter: `project_id=eq.${projectId}`,
        },
        () => {
          queryClient.invalidateQueries({ queryKey: ['project', projectId] })
        },
      )
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [projectId, queryClient])

  return useQuery<ProjectDetailsResponse>({
    queryKey: ['project', projectId],
    queryFn: async () => {
      if (!projectId) throw new Error('Project ID is required')

      const [
        projectRes,
        tasksRes,
        briefingRes,
        servicesRes,
        linkedServicesRes,
        transactionsRes,
      ] = await Promise.all([
        ProjectServiceClass.get(projectId),
        ProjectServiceClass.getTasks(projectId),
        ProjectServiceClass.getBriefing(projectId),
        supabase.from('services').select('*'),
        ProjectServiceClass.getProjectServices(projectId),
        supabase.from('transactions').select('*').eq('project_id', projectId),
      ])

      if (projectRes.error) throw projectRes.error

      const project = projectRes.data as LocalProjectWithRelations

      const adaptedProject: Record<string, any> = { ...project }
      if (adaptedProject.client) {
        adaptedProject.clients = {
          ...adaptedProject.client,
          name: adaptedProject.client.full_name || adaptedProject.client.name,
        }
      }

      const { data: contractsData } = await supabase
        .from('contracts')
        .select('*')
        .or(
          `project_id.eq.${projectId},client_id.eq.${project?.client_id || project?.client?.id}`,
        )

      let briefing = null
      if (briefingRes.data) {
        const content = briefingRes.data.content as BriefingContent
        briefing = {
          ...briefingRes.data,
          questions: content?.questions || [],
          answers: content?.answers || {},
          is_submitted: briefingRes.data.status === 'submitted',
        } as BriefingUI
      }

      const services = (servicesRes.data || []).map((s) => ({
        ...s,
        price: Number(s.price),
        duration_minutes: Number(s.duration_minutes || 0),
        base_price: s.base_price || 0,
      }))

      const projectServices = (linkedServicesRes.data || []).map((s) => ({
        ...s,
        quantity: Number(s.quantity),
        unit_price: Number(s.unit_price),
        total_price: Number(s.total_price),
        service: s.service
          ? {
              ...s.service,
              price: Number(s.service.price),
              base_price: Number(s.service.price),
              duration_minutes: Number(s.service.duration_minutes || 0),
            }
          : undefined,
      }))

      const response: ProjectDetailsResponse = {
        project: adaptedProject as ProjectWithRelations,
        tasks: tasksRes.data || [],
        briefing,
        contracts: contractsData || [],
        services: services as ServiceUI[],
        projectServices: projectServices,
        transactions: transactionsRes.data || [],
        invoices: [],
      }

      return response
    },
    enabled: !!projectId,
    staleTime: 1000 * 60 * 5,
  })
}

import { useMutation, useQueryClient } from '@tanstack/react-query'
import { supabase } from '@/integrations/supabase/client'
import { ProjectService } from '../api/projectService'
import { QUERY_KEYS } from '@/constants/queryKeys'
import { useToast } from '@/hooks/use-toast'
import { logger } from '@/services/logger'
import { sanitizeFormData } from '@/lib/security'

export function useProjectMutations() {
  const queryClient = useQueryClient()
  const { toast } = useToast()

  const createProjectMutation = useMutation({
    mutationFn: async (projectData: any) => {
      const cleanData = sanitizeFormData(projectData)
      const { data, error } = await supabase
        .from('projects')
        .insert(cleanData)
        .select()
        .single()
      if (error) throw error
      return data
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['projects'] })
      queryClient.invalidateQueries({ queryKey: [QUERY_KEYS.DASHBOARD_STATS] })
      toast({ title: 'Projeto criado!' })
    },
    onError: (error) => {
      logger.error(error, 'useProjectMutations.createProject')
      toast({ title: 'Erro ao criar projeto', variant: 'destructive' })
    },
  })

  const updateProjectMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string; data: any }) => {
      const cleanData = sanitizeFormData(data)
      const { data: result, error } = await supabase
        .from('projects')
        .update(cleanData)
        .eq('id', id)
        .select()
        .single()
      if (error) throw error
      return result
    },
    onSuccess: (_, variables) => {
      queryClient.invalidateQueries({ queryKey: ['projects'] })
      queryClient.invalidateQueries({ queryKey: ['project', variables.id] })
      queryClient.invalidateQueries({ queryKey: [QUERY_KEYS.DASHBOARD_STATS] })
      toast({ title: 'Projeto atualizado!' })
    },
    onError: (error) => {
      logger.error(error, 'useProjectMutations.updateProject')
      toast({ title: 'Erro ao atualizar projeto', variant: 'destructive' })
    },
  })

  const createTaskMutation = useMutation({
    mutationFn: async (taskData: any) => {
      const { data, error } = await ProjectService.createTask(taskData)
      if (error) throw error
      return data
    },
    onSuccess: (_, variables) => {
      queryClient.invalidateQueries({
        queryKey: ['project', variables.project_id, 'tasks'],
      })
      queryClient.invalidateQueries({
        queryKey: ['project', variables.project_id],
      })
    },
    onError: (error) => {
      logger.error(error, 'useProjectMutations.createTask')
      toast({ title: 'Erro ao criar tarefa', variant: 'destructive' })
    },
  })

  const updateTaskMutation = useMutation({
    mutationFn: async ({
      id,
      data,
      project_id,
    }: {
      id: string
      data: any
      project_id: string
    }) => {
      const success = await ProjectService.updateTask(id, data)
      if (!success) throw new Error('Falha ao atualizar tarefa')
      return { id, project_id }
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({
        queryKey: ['project', data.project_id, 'tasks'],
      })
    },
  })

  const deleteTaskMutation = useMutation({
    mutationFn: async ({
      id,
      project_id,
    }: {
      id: string
      project_id: string
    }) => {
      const success = await ProjectService.deleteTask(id)
      if (!success) throw new Error('Falha ao deletar tarefa')
      return { id, project_id }
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({
        queryKey: ['project', data.project_id, 'tasks'],
      })
    },
  })

  const addServiceMutation = useMutation({
    mutationFn: async (serviceData: any) => {
      const { data: _data, error } =
        await ProjectService.addProjectService(serviceData)
      if (error) throw error
      return serviceData
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ['project', data.project_id] })
      queryClient.invalidateQueries({
        queryKey: ['project', data.project_id, 'services'],
      })
      toast({ title: 'Servi├ºo adicionado!' })
    },
    onError: (error) => {
      logger.error(error, 'useProjectMutations.addService')
      toast({ title: 'Erro ao adicionar servi├ºo', variant: 'destructive' })
    },
  })

  const removeServiceMutation = useMutation({
    mutationFn: async ({
      id,
      project_id,
    }: {
      id: string
      project_id: string
    }) => {
      const { error } = await ProjectService.deleteProjectService(id)
      if (error) throw error
      return { project_id }
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ['project', data.project_id] })
      queryClient.invalidateQueries({
        queryKey: ['project', data.project_id, 'services'],
      })
      toast({ title: 'Servi├ºo removido!' })
    },
  })

  const registerPaymentMutation = useMutation({
    mutationFn: async (paymentData: any) => {
      const cleanData = sanitizeFormData(paymentData)
      const { error } = await supabase.from('transactions').insert([cleanData])
      if (error) throw error
      return paymentData
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ['project', data.project_id] })
      queryClient.invalidateQueries({
        queryKey: ['project', data.project_id, 'payments'],
      })
      queryClient.invalidateQueries({ queryKey: [QUERY_KEYS.DASHBOARD_STATS] })
      toast({ title: 'Pagamento registrado!' })
    },
    onError: (error) => {
      logger.error(error, 'useProjectMutations.registerPayment')
      toast({ title: 'Erro ao registrar pagamento', variant: 'destructive' })
    },
  })

  return {
    createProjectMutation,
    updateProjectMutation,
    createTaskMutation,
    updateTaskMutation,
    deleteTaskMutation,
    addServiceMutation,
    removeServiceMutation,
    registerPaymentMutation,
  }
}

import { useState, useEffect } from 'react'
import { supabase } from '@/integrations/supabase/client'
import { useToast } from '@/hooks/use-toast'
import { Database } from '@/integrations/supabase/types'
import { SupabaseClient } from '@supabase/supabase-js'
import { logger } from '@/services/logger'
import { addMinutes } from 'date-fns/addMinutes'
import { isBefore } from 'date-fns/isBefore'
import { startOfDay } from 'date-fns/startOfDay'
import { parse } from 'date-fns/parse'
import { formatDate, toZonedTime } from '@/lib/date-utils'
import { Profile, Service, TimeSlot } from '../types'

type LocalDatabase = Database & {
  public: {
    Functions: {
      get_day_availability: {
        Args: {
          target_slug: string
          query_date: string
        }
        Returns: {
          start_time: string
          end_time?: string
          duration_minutes?: number
        }[]
      }
    }
  }
}

export const usePublicBooking = (
  slug: string | undefined,
  refParam: string | null,
) => {
  const { toast } = useToast()

  const [profile, setProfile] = useState<Profile | null>(null)
  const [services, setServices] = useState<Service[]>([])
  const [loading, setLoading] = useState(true)

  const [step, setStep] = useState<1 | 2 | 3 | 4>(1)
  const [selectedService, setSelectedService] = useState<Service | null>(null)
  const [selectedDate, setSelectedDate] = useState<Date | undefined>(undefined)
  const [selectedTime, setSelectedTime] = useState<string | null>(null)

  const [clientName, setClientName] = useState('')
  const [clientPhone, setClientPhone] = useState('')
  const [submitting, setSubmitting] = useState(false)

  const [timeSlots, setTimeSlots] = useState<TimeSlot[]>([])
  const [loadingSlots, setLoadingSlots] = useState(false)

  useEffect(() => {
    if (slug) {
      fetchProfileAndServices()
    }
  }, [slug])

  useEffect(() => {
    if (selectedDate && profile && selectedService) {
      generateTimeSlots()
    }
  }, [selectedDate, profile, selectedService])

  const fetchProfileAndServices = async () => {
    try {
      setLoading(true)
      const { data: profileData, error: profileError } = await supabase
        .from('profiles')
        .select('id, full_name, avatar_url, bio, business_name, address')
        .eq('id', slug)
        .maybeSingle()

      if (profileError || !profileData) {
        throw new Error('Perfil n├úo encontrado')
      }

      setProfile({
        id: profileData.id,
        name: profileData.full_name || 'Profissional',
        full_name: profileData.full_name,
        avatar_url: profileData.avatar_url,
        bio: profileData.bio,
        slug: slug || '',
        business_address:
          profileData.address || profileData.business_name || null,
      })

      const { data: servicesData, error: servicesError } = await supabase
        .from('services')
        .select('id, name, description, price, duration_minutes')
        .eq('user_id', profileData.id)

      if (servicesError) throw servicesError

      setServices(
        (servicesData || []).map((s) => ({
          id: s.id,
          name: s.name,
          description: s.description,
          price: Number(s.price),
          duration_minutes: Number(s.duration_minutes),
        })),
      )
    } catch (error) {
      logger.error(error, 'usePublicBooking.fetchProfile', { showToast: false })
      toast({ title: 'Perfil n├úo encontrado', variant: 'destructive' })
    } finally {
      setLoading(false)
    }
  }

  const generateTimeSlots = async () => {
    if (!selectedDate || !profile || !selectedService) return

    setLoadingSlots(true)
    try {
      const dateStr = formatDate(selectedDate, 'yyyy-MM-dd')
      const typedSupabase = supabase as unknown as SupabaseClient<LocalDatabase>

      const { data: eventsData, error } = await typedSupabase.rpc(
        'get_day_availability',
        {
          target_slug: slug,
          query_date: dateStr,
        },
      )

      const events = eventsData || []

      if (error) throw error

      const startHour = 9
      const endHour = 18
      const serviceDuration = selectedService.duration_minutes
      const slots: TimeSlot[] = []

      for (let hour = startHour; hour < endHour; hour++) {
        for (let min = 0; min < 60; min += 30) {
          const time = `${hour.toString().padStart(2, '0')}:${min.toString().padStart(2, '0')}`
          const slotStart = parse(time, 'HH:mm', new Date())
          const slotEnd = addMinutes(slotStart, serviceDuration)
          let isBlocked = false

          if (events) {
            for (const event of events) {
              const eventStart = parse(event.start_time, 'HH:mm', new Date())
              let eventEnd
              if (event.end_time) {
                eventEnd = parse(event.end_time, 'HH:mm', new Date())
              } else {
                eventEnd = addMinutes(eventStart, event.duration_minutes || 60)
              }

              if (
                (slotStart >= eventStart && slotStart < eventEnd) ||
                (slotEnd > eventStart && slotEnd <= eventEnd) ||
                (slotStart <= eventStart && slotEnd >= eventEnd)
              ) {
                isBlocked = true
                break
              }
            }
          }

          if (
            isBefore(selectedDate, startOfDay(toZonedTime(new Date()))) &&
            isBefore(slotStart, toZonedTime(new Date()))
          ) {
            isBlocked = true
          }

          slots.push({ time, available: !isBlocked })
        }
      }

      setTimeSlots(slots)
    } catch (error) {
      logger.error(error, 'usePublicBooking.generateTimeSlots', {
        showToast: false,
      })
      toast({ title: 'Erro ao gerar hor├írios', variant: 'destructive' })
    } finally {
      setLoadingSlots(false)
    }
  }

  const handleBookingSubmit = async () => {
    if (!clientName || !clientPhone) {
      toast({ title: 'Preencha seus dados', variant: 'destructive' })
      return
    }

    setSubmitting(true)
    try {
      if (!profile || !selectedService || !selectedDate || !selectedTime)
        throw new Error('Missing data')

      const dateStr = formatDate(selectedDate, 'yyyy-MM-dd')
      let clientId = null

      try {
        const tags: string[] = []
        if (refParam) tags.push(`ref:${refParam}`)
        tags.push('origem:agendamento_online')

        const { data: newClient, error: clientError } = await supabase
          .from('wedding_clients')
          .insert({
            full_name: clientName,
            name: clientName,
            phone: clientPhone,
            user_id: profile.id,
            tags: tags,
            origin: 'site_booking',
          })
          .select()
          .single()

        if (!clientError && newClient) {
          clientId = newClient.id
        }
      } catch (_err) {}

      const description = `Agendamento Online\nCliente: ${clientName}\nWhatsApp: ${clientPhone}\nServi├ºo: ${selectedService.name}`

      const { error } = await supabase.from('events').insert({
        user_id: profile.id,
        title: `${clientName} - ${selectedService.name}`,
        description: description,
        event_date: dateStr,
        start_time: selectedTime,
        duration_minutes: selectedService.duration_minutes,
        is_active: true,
        total_value: selectedService.price,
        client_id: clientId,
      })

      if (error) throw error

      setStep(4)
    } catch (error) {
      logger.error(error, 'usePublicBooking.handleBookingSubmit', {
        showToast: false,
      })
      toast({ title: 'Erro ao realizar agendamento', variant: 'destructive' })
    } finally {
      setSubmitting(false)
    }
  }

  return {
    profile,
    services,
    loading,
    step,
    setStep,
    selectedService,
    setSelectedService,
    selectedDate,
    setSelectedDate,
    selectedTime,
    setSelectedTime,
    clientName,
    setClientName,
    clientPhone,
    setClientPhone,
    submitting,
    timeSlots,
    loadingSlots,
    handleBookingSubmit,
  }
}

import { useCallback, useEffect, useRef, useState } from 'react'

const ACTIVATION_THRESHOLD = 50

const MIN_SCROLL_UP_THRESHOLD = 10

export function useAutoScroll(dependencies: React.DependencyList) {
  const containerRef = useRef<HTMLDivElement | null>(null)
  const previousScrollTop = useRef<number | null>(null)
  const [shouldAutoScroll, setShouldAutoScroll] = useState(true)

  const shouldAutoScrollRef = useRef(shouldAutoScroll)
  shouldAutoScrollRef.current = shouldAutoScroll

  const scrollToBottom = useCallback(() => {
    if (containerRef.current) {
      containerRef.current.scrollTop = containerRef.current.scrollHeight
    }
  }, [])

  const handleScroll = useCallback(() => {
    if (containerRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = containerRef.current

      const isOverscrolling =
        scrollTop < 0 || scrollTop + clientHeight > scrollHeight + 1

      if (isOverscrolling) {
        return
      }

      const distanceFromBottom = Math.abs(
        scrollHeight - scrollTop - clientHeight,
      )

      const isScrollingUp =
        previousScrollTop.current !== null
          ? scrollTop < previousScrollTop.current
          : false

      const scrollUpDistance =
        previousScrollTop.current !== null
          ? previousScrollTop.current - scrollTop
          : 0

      const isDeliberateScrollUp =
        isScrollingUp && scrollUpDistance > MIN_SCROLL_UP_THRESHOLD

      const isScrolledToBottom = distanceFromBottom < ACTIVATION_THRESHOLD

      if (isDeliberateScrollUp && !isScrolledToBottom) {
        setShouldAutoScroll(false)
      } else if (!isScrollingUp || isScrolledToBottom) {
        setShouldAutoScroll(isScrolledToBottom)
      }

      previousScrollTop.current = scrollTop
    }
  }, [])

  const handleTouchStart = useCallback(() => {
    setShouldAutoScroll(false)
  }, [])

  useEffect(() => {
    if (containerRef.current) {
      previousScrollTop.current = containerRef.current.scrollTop
    }
  }, [])

  useEffect(() => {
    const container = containerRef.current
    if (!container) return

    let previousHeight = container.scrollHeight

    const resizeObserver = new ResizeObserver(() => {
      const currentHeight = container.scrollHeight

      if (shouldAutoScrollRef.current && currentHeight > previousHeight) {
        scrollToBottom()
      }
      previousHeight = currentHeight
    })

    resizeObserver.observe(container)

    return () => {
      resizeObserver.disconnect()
    }
  }, [scrollToBottom])

  useEffect(() => {
    if (shouldAutoScroll) {
      scrollToBottom()
    }
  }, dependencies)

  return {
    containerRef,
    scrollToBottom,
    handleScroll,
    shouldAutoScroll,
    handleTouchStart,
  }
}

import { useState, useEffect, useRef, useCallback } from 'react'
import type { TaskDTO as Task } from '@inferencesh/sdk'
import type { AgentClient } from '@inferencesh/sdk/agent'
import {
  StreamManager,
  TaskStatusCompleted,
  TaskStatusFailed,
  TaskStatusCancelled,
} from '@inferencesh/sdk'

export interface UseTaskOptions {
  client: AgentClient

  taskId: string

  onUpdate?: (task: Task) => void

  onComplete?: (task: Task) => void

  onError?: (error: Error) => void

  autoReconnect?: boolean

  maxReconnects?: number
}

export interface UseTaskResult {
  task: Task | null

  isLoading: boolean

  isStreaming: boolean

  error: Error | null

  refetch: () => Promise<void>

  stopStream: () => void
}

export function isTerminalStatus(status: number | undefined): boolean {
  return (
    status !== undefined &&
    [TaskStatusCompleted, TaskStatusFailed, TaskStatusCancelled].includes(
      status,
    )
  )
}

export function useTask({
  client,
  taskId,
  onUpdate,
  onComplete,
  onError,
  autoReconnect = true,
  maxReconnects = 5,
}: UseTaskOptions): UseTaskResult {
  const [task, setTask] = useState<Task | null>(null)
  const [isLoading, setIsLoading] = useState(true)
  const [isStreaming, setIsStreaming] = useState(false)
  const [error, setError] = useState<Error | null>(null)

  const streamManagerRef = useRef<StreamManager<Task> | null>(null)
  const taskRef = useRef<Task | null>(null)

  useEffect(() => {
    taskRef.current = task
  }, [task])

  const stopStream = useCallback(() => {
    if (streamManagerRef.current) {
      streamManagerRef.current.stop()
      streamManagerRef.current = null
    }
    setIsStreaming(false)
  }, [])

  const startStream = useCallback(() => {
    if (!taskId || !client) return

    stopStream()

    const manager = new StreamManager<Task>({
      createEventSource: async () => {
        return client.http.createEventSource(`/tasks/${taskId}/stream`)
      },
      autoReconnect,
      maxReconnects,
      reconnectDelayMs: 1000,
      onStart: () => setIsStreaming(true),
      onStop: () => setIsStreaming(false),
      onError: (err) => {
        setError(err)
        onError?.(err)
      },
      onData: (taskData: Task) => {
        setTask(taskData)
        onUpdate?.(taskData)

        if (isTerminalStatus(taskData.status)) {
          onComplete?.(taskData)
          manager.stopAfter(500)
        }
      },
      onPartialData: (partialData: Task, fields: string[]) => {
        const currentTask = taskRef.current
        if (currentTask) {
          const updates = fields.reduce((acc, field) => {
            const key = field as keyof Task
            ;(acc as Record<string, unknown>)[key] = partialData[key]
            return acc
          }, {} as Partial<Task>)
          const mergedTask = { ...currentTask, ...updates }
          setTask(mergedTask)
          onUpdate?.(mergedTask)

          if (isTerminalStatus(mergedTask.status)) {
            onComplete?.(mergedTask)
            manager.stopAfter(500)
          }
        } else {
          setTask(partialData)
          onUpdate?.(partialData)
        }
      },
    })

    streamManagerRef.current = manager
    manager.connect()
  }, [
    taskId,
    client,
    autoReconnect,
    maxReconnects,
    onUpdate,
    onComplete,
    onError,
    stopStream,
  ])

  const fetchTask = useCallback(async () => {
    if (!taskId || !client) return

    setIsLoading(true)
    setError(null)

    try {
      const taskData = await client.http.request<Task>(
        'get',
        `/tasks/${taskId}`,
      )

      setTask(taskData)
      onUpdate?.(taskData)

      if (!isTerminalStatus(taskData.status)) {
        startStream()
      } else {
        onComplete?.(taskData)
      }
    } catch (err) {
      const error =
        err instanceof Error ? err : new Error('Failed to fetch task')
      setError(error)
      onError?.(error)
    } finally {
      setIsLoading(false)
    }
  }, [taskId, client, onUpdate, onComplete, onError, startStream])

  useEffect(() => {
    fetchTask()

    return () => {
      stopStream()
    }
  }, [taskId])

  return {
    task,
    isLoading,
    isStreaming,
    error,
    refetch: fetchTask,
    stopStream,
  }
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { useEffect } from 'react'
import { supabase } from '@/integrations/supabase/client'
import { useAuth } from '@/hooks/useAuth'
import { logger } from '@/services/logger'

interface AdminNotification {
  id: string
  type: string
  title: string
  message: string
  related_id: string | null
  action_url: string | null
  is_read: boolean
  created_at: string
}

interface NotificationsResponse {
  unread_count: number
  notifications: AdminNotification[]
}

export function useAdminNotifications() {
  const queryClient = useQueryClient()
  const { user } = useAuth()

  const notificationsQuery = useQuery({
    queryKey: ['admin-notifications'],
    queryFn: async (): Promise<NotificationsResponse> => {
      const { data, error } = await (supabase.rpc as any)('get_admin_notifications', {
        p_limit: 30,
        p_unread_only: false,
      })

      if (error) {
        if (error.message.includes('Unauthorized')) {
          console.warn('[AdminNotifications] RPC Unauthorized. Access denied by DB function.')
          return { unread_count: 0, notifications: [] }
        }
        logger.error('useAdminNotifications.fetch', error)
        throw error
      }

      return data as unknown as NotificationsResponse
    },
    staleTime: 1000 * 30,
  })

  const markRead = useMutation({
    mutationFn: async (notificationIds: string[]) => {
      const { data, error } = await (supabase.rpc as any)('mark_notifications_read', {
        p_notification_ids: notificationIds,
      })

      if (error) throw error
      return data
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-notifications'] })
    },
  })

  const markAllRead = useMutation({
    mutationFn: async () => {
      const unread =
        notificationsQuery.data?.notifications?.filter((n) => !n.is_read) || []
      if (unread.length === 0) return 0

      const { data, error } = await (supabase.rpc as any)('mark_notifications_read', {
        p_notification_ids: unread.map((n) => n.id),
      })

      if (error) throw error
      return data
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-notifications'] })
    },
  })

  useEffect(() => {
    if (!user?.id) return

    const channel = supabase
      .channel('admin-notifications-realtime')
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'notifications',
          filter: `user_id=eq.${user.id}`,
        },
        () => {
          queryClient.invalidateQueries({ queryKey: ['admin-notifications'] })
        },
      )
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [user?.id, queryClient])

  return {
    notifications: notificationsQuery.data?.notifications || [],
    unreadCount: notificationsQuery.data?.unread_count || 0,
    isLoading: notificationsQuery.isLoading,
    markRead,
    markAllRead,
    refetch: notificationsQuery.refetch,
  }
}

import { useState, useEffect } from 'react'
import { supabase } from '@/integrations/supabase/client'
import { useToast } from '@/hooks/use-toast'
import { logger } from '@/services/logger'

export interface SubscriptionUser {
  id: string
  full_name: string | null
  email: string | null
  plan: string | null
  created_at: string | null
}

export interface SubscriptionStats {
  mrr: number
  activeSubscribers: number
  churnRate: string
  growth: string
}

const PLAN_PRICES = {
  free: 0,
  starter: 29.9,
  pro: 59.9,
  empire: 99.9,
}

export function useAdminSubscriptions() {
  const { toast } = useToast()
  const [loading, setLoading] = useState(true)
  const [users, setUsers] = useState<SubscriptionUser[]>([])
  const [stats, setStats] = useState<SubscriptionStats>({
    mrr: 0,
    activeSubscribers: 0,
    churnRate: '0%',
    growth: '+0%',
  })

  useEffect(() => {
    fetchData()
  }, [])

  const calculateStats = (profiles: SubscriptionUser[]) => {
    let mrr = 0
    let subscribers = 0

    profiles.forEach((user) => {
      const plan = (user.plan || 'free').toLowerCase()
      const price = PLAN_PRICES[plan as keyof typeof PLAN_PRICES] || 0
      if (price > 0) {
        mrr += price
        subscribers++
      }
    })

    setStats({
      mrr,
      activeSubscribers: subscribers,
      churnRate: '2.4%',
      growth: '+12.5%',
    })
  }

  const fetchData = async () => {
    setLoading(true)
    try {
      const { data: profiles, error } = await supabase
        .from('profiles')
        .select('*')
        .order('created_at', { ascending: false })

      if (error) throw error

      if (profiles) {
        setUsers(profiles)
        calculateStats(profiles)
      }
    } catch (error) {
      logger.error(error, {
        message: 'Erro ao carregar dados de assinaturas.',
        showToast: false,
      })
      toast({
        title: 'Erro ao carregar dados',
        variant: 'destructive',
      })
    } finally {
      setLoading(false)
    }
  }

  const handleUpdatePlan = async (userId: string, newPlan: string) => {
    try {
      const { error } = await supabase
        .from('profiles')
        .update({ plan: newPlan })
        .eq('id', userId)

      if (error) throw error

      toast({
        title: 'Plano atualizado',
        description: `Usu├írio alterado para ${newPlan}`,
      })

      fetchData()
    } catch (_error) {
      toast({
        title: 'Erro ao atualizar plano',
        variant: 'destructive',
      })
    }
  }

  return {
    users,
    stats,
    loading,
    handleUpdatePlan,
    refresh: fetchData,
  }
}

