  const fetchData = async () => {
    setLoadingData(true)

    const { data: profileData } = await supabase
      .from('profiles')
      .select('business_name, bio, phone, avatar_url')
      .eq('id', user!.id)
      .maybeSingle()

    if (profileData) {
      setBusinessName(profileData.business_name || '')
      setPhone(profileData.phone || '')
      setBio(profileData.bio || '')
      setLogoUrl(profileData.avatar_url)
    }

    const { data: aiSettings } = await supabase
      .from('user_ai_settings')
      .select('*')
      .eq('user_id', user!.id)
      .maybeSingle()

    if (aiSettings) {
      setAiProvider(aiSettings.provider || 'google')
      setAiKey(aiSettings.api_key || '')
      setAiModel(aiSettings.model_name || 'gemini-1.5-pro')
    }

    setLoadingData(false)
  }

  const saveSettings = async () => {
    setSaving(true)
    try {
      const { error: settingsError } = await supabase
        .from('profiles')
        .update({
          business_name: businessName.trim() || null,
          phone: phone.trim() || null,
          bio: bio.trim() || null,
          avatar_url: logoUrl,
        })
        .eq('id', user!.id)

      if (settingsError) throw settingsError

      if (fullName !== user?.user_metadata?.full_name) {
        const { error: userError } = await supabase.auth.updateUser({
          data: { full_name: fullName },
        })
        if (userError) throw userError
      }

      const { error: aiError } = await supabase
        .from('user_ai_settings')
        .upsert({
          user_id: user!.id,
          provider: aiProvider,
          api_key: aiKey.trim() || null,
          model_name: aiModel.trim() || null,
        })

      if (aiError) throw aiError

      toast({
        title: 'Configura├º├Áes salvas',
        description: 'Todas as altera├º├Áes foram aplicadas.',
      })
    } catch (error: unknown) {
      const message =
        error instanceof Error ? error.message : 'Erro desconhecido'
      toast({
        title: 'Erro ao salvar',
        description: message,
        variant: 'destructive',
      })
    } finally {
      setSaving(false)
    }
  }

  const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || e.target.files.length === 0) return
    setUploadingLogo(true)
    try {
      const file = e.target.files[0]
      const publicUrl = await uploadImageSafely(file, 'avatars', 'logos')
      setLogoUrl(publicUrl)
    } catch (error: unknown) {
      const message =
        error instanceof Error ? error.message : 'Erro desconhecido'
      toast({
        title: 'Erro no upload',
        description: message,
        variant: 'destructive',
      })
    } finally {
      setUploadingLogo(false)
    }
  }

  return {
    user,
    loading,
    loadingData,
    saving,
    uploadingLogo,
    businessName,
    setBusinessName,
    primaryColor,
    setPrimaryColor,
    phone,
    setPhone,
    instagram,
    setInstagram,
    website,
    setWebsite,
    bio,
    setBio,
    logoUrl,
    fullName,
    setFullName,
    pixKeyType,
    setPixKeyType,
    pixKey,
    setPixKey,
    bankName,
    setBankName,
    bankCode,
    setBankCode,
    accountType,
    setAccountType,
    agency,
    setAgency,
    accountNumber,
    setAccountNumber,
    accountHolderName,
    setAccountHolderName,
    accountHolderDocument,
    setAccountHolderDocument,
    digitalWalletType,
    setDigitalWalletType,
    digitalWalletAccount,
    setDigitalWalletAccount,
    preferredMethod,
    setPreferredMethod,
    aiProvider,
    setAiProvider,
    aiKey,
    setAiKey,
    aiModel,
    setAiModel,
    saveSettings,
    handleLogoUpload,
  }
}

import { useState, useEffect } from 'react'
import { supabase } from '@/integrations/supabase/client'
import { useAuth } from '@/hooks/useAuth'

export const useGoogleCalendar = () => {
  const { user } = useAuth()
  const [isConnected, setIsConnected] = useState(false)
  const [isLoading, setIsLoading] = useState(true)

  useEffect(() => {
    checkConnection()
  }, [user])

  const checkConnection = async () => {
    if (!user) {
      setIsConnected(false)
      setIsLoading(false)
      return
    }

    const { data } = await supabase
      .from('google_calendar_tokens')
      .select('id')
      .eq('user_id', user.id)
      .maybeSingle()

    setIsConnected(!!data)
    setIsLoading(false)
  }

  const connectGoogleCalendar = () => {
    const clientId = import.meta.env.VITE_GOOGLE_CLIENT_ID
    const redirectUri = `${window.location.origin}/calendar/callback`
    const scope =
      'https://www.googleapis.com/auth/calendar https://www.googleapis.com/auth/calendar.events'

    if (!clientId) {
      return
    }

    const authUrl = new URL('https://accounts.google.com/o/oauth2/v2/auth')
    authUrl.searchParams.set('client_id', clientId)
    authUrl.searchParams.set('redirect_uri', redirectUri)
    authUrl.searchParams.set('response_type', 'code')
    authUrl.searchParams.set('scope', scope)
    authUrl.searchParams.set('access_type', 'offline')
    authUrl.searchParams.set('prompt', 'consent')
    authUrl.searchParams.set('state', user?.id || '')

    window.location.href = authUrl.toString()
  }

  const disconnectGoogleCalendar = async () => {
    if (!user) return

    await supabase
      .from('google_calendar_tokens')
      .delete()
      .eq('user_id', user.id)

    setIsConnected(false)
  }

  return {
    isConnected,
    isLoading,
    connectGoogleCalendar,
    disconnectGoogleCalendar,
    checkConnection,
  }
}

import { useState, useEffect } from 'react'
import { supabase } from '@/integrations/supabase/client'
import { useAuth } from '@/hooks/useAuth'
import { useToast } from '@/hooks/use-toast'
import { Database } from '@/integrations/supabase/types'
import { SupabaseClient } from '@supabase/supabase-js'

interface UserIntegration {
  id: string
  provider: string
  is_active: boolean
  sync_enabled: boolean
  last_sync_at: string | null
  user_id: string
  created_at: string
  updated_at: string
  access_token: string | null
  refresh_token: string | null
  expires_at: string | null
  metadata: Record<string, unknown> | null
}

interface NotificationSettings {
  id: string
  user_id: string
  email_enabled: boolean
  reminder_days: number[]
  notify_new_event: boolean
  notify_event_update: boolean
  notify_event_cancel: boolean
  notify_assistant_assigned: boolean
  created_at?: string
  updated_at?: string
}

type LocalDatabase = Database & {
  public: {
    Tables: {
      notification_settings: {
        Row: NotificationSettings
        Insert: Omit<NotificationSettings, 'id' | 'created_at' | 'updated_at'>
        Update: Partial<
          Omit<NotificationSettings, 'id' | 'created_at' | 'updated_at'>
        >
        Relationships: []
      }
    }
  }
}

interface DeliverabilityStatus {
  bounces: number
  complaints: number
  invalid_profiles: number
  invalid_clients: number
  invalid_leads: number
  invalid_invites: number
}

export type { UserIntegration, NotificationSettings, DeliverabilityStatus }

const DEFAULT_NOTIFICATION_SETTINGS: Omit<
  NotificationSettings,
  'id' | 'user_id'
> = {
  email_enabled: true,
  reminder_days: [1, 3, 7],
  notify_new_event: true,
  notify_event_update: true,
  notify_event_cancel: true,
  notify_assistant_assigned: true,
}

export function useIntegrations() {
  const { user } = useAuth()
  const { toast } = useToast()

  const typedSupabase = supabase as unknown as SupabaseClient<LocalDatabase>

  const [integrations, setIntegrations] = useState<UserIntegration[]>([])
  const [notificationSettings, setNotificationSettings] = useState<
    Omit<NotificationSettings, 'user_id'>
  >({
    id: '',
    ...DEFAULT_NOTIFICATION_SETTINGS,
  })
  const [deliverabilityStatus, setDeliverabilityStatus] =
    useState<DeliverabilityStatus>({
      bounces: 0,
      complaints: 0,
      invalid_profiles: 0,
      invalid_clients: 0,
      invalid_leads: 0,
      invalid_invites: 0,
    })
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  const [connecting, setConnecting] = useState(false)
  const [syncing, setSyncing] = useState<string | null>(null)

  useEffect(() => {
    if (user) fetchData()
  }, [user])

  useEffect(() => {
    const handleCallback = async () => {
      const urlParams = new URLSearchParams(window.location.search)
      const code = urlParams.get('code')
      const state = urlParams.get('state')

      if (code && state) {
        setConnecting(true)
        try {
          const {
            data: { session },
            error,
          } = await supabase.auth.getSession()
          if (error) throw error
          if (session?.provider_token) {
            toast({
              title: 'Google Calendar conectado!',
              description: 'Autentica├º├úo realizada com sucesso.',
            })
          }
          window.history.replaceState(
            {},
            document.title,
            window.location.pathname,
          )
          fetchData()
        } catch (error: unknown) {
          const message =
            error instanceof Error
              ? error.message
              : 'N├úo foi poss├¡vel conectar ao Google Calendar'
          toast({
            title: 'Erro ao conectar',
            description: message,
            variant: 'destructive',
          })
        } finally {
          setConnecting(false)
        }
      }
    }
    handleCallback()
  }, [])

  const fetchData = async () => {
    if (!user) return
    setLoading(true)

    const { data: integrationsData } = await typedSupabase
      .from('user_integrations')
      .select('*')
      .eq('user_id', user.id)

    const mappedIntegrations: UserIntegration[] = (integrationsData || []).map(
      (i: Record<string, unknown>) => ({
        id: i.id as string,
        provider: i.provider as string,
        is_active: true,
        sync_enabled: true,
        last_sync_at: i.updated_at as string | null,
        user_id: i.user_id as string,
        created_at: i.created_at as string,
        updated_at: i.updated_at as string,
        access_token: i.access_token as string | null,
        refresh_token: i.refresh_token as string | null,
        expires_at: i.expires_at as string | null,
        metadata: (i.metadata as Record<string, unknown>) || null,
      }),
    )

    setIntegrations(mappedIntegrations)

    const { data: notifData } = await typedSupabase
      .from('notification_settings')
      .select('*')
      .eq('user_id', user.id)
      .maybeSingle()

    if (notifData) {
      const nd = notifData as NotificationSettings
      setNotificationSettings({
        id: nd.id,
        email_enabled: nd.email_enabled,
        reminder_days: nd.reminder_days || [1, 3, 7],
        notify_new_event: nd.notify_new_event,
        notify_event_update: nd.notify_event_update,
        notify_event_cancel: nd.notify_event_cancel,
        notify_assistant_assigned: nd.notify_assistant_assigned,
        created_at: nd.created_at,
        updated_at: nd.updated_at,
      })
    }

    const [
      { count: bounceCount },
      { count: complaintCount },
      { count: invProfiles },
      { count: invClients },
      { count: invLeads },
      { count: invInvites },
    ] = await Promise.all([
      supabase
        .from('notification_logs')
        .select('*', { count: 'exact', head: true })
        .like('error_message', '%SES Bounce%'),
      supabase
        .from('notification_logs')
        .select('*', { count: 'exact', head: true })
        .like('error_message', '%SES Complaint%'),
      supabase
        .from('profiles')
        .select('*', { count: 'exact', head: true })
        .eq('email_status', 'invalid'),
      supabase
        .from('wedding_clients')
        .select('*', { count: 'exact', head: true })
        .eq('email_status', 'invalid'),
      supabase
        .from('leads')
        .select('*', { count: 'exact', head: true })
        .eq('email_status', 'invalid'),
      supabase
        .from('assistant_invites')
        .select('*', { count: 'exact', head: true })
        .eq('email_status', 'invalid'),
    ])

    setDeliverabilityStatus({
      bounces: bounceCount || 0,
      complaints: complaintCount || 0,
      invalid_profiles: invProfiles || 0,
      invalid_clients: invClients || 0,
      invalid_leads: invLeads || 0,
      invalid_invites: invInvites || 0,
    })

    setLoading(false)
  }

  const connectGoogleCalendar = async () => {
    setConnecting(true)
    try {
      const { error } = await supabase.auth.signInWithOAuth({
        provider: 'google',
        options: {
          scopes: 'https://www.googleapis.com/auth/calendar',
          redirectTo: `${window.location.origin}/configuracoes`,
          queryParams: { access_type: 'offline', prompt: 'consent' },
        },
      })
      if (error) throw error
    } catch (error: unknown) {
      const message =
        error instanceof Error
          ? error.message
          : 'N├úo foi poss├¡vel iniciar a conex├úo'
      toast({ title: 'Erro', description: message, variant: 'destructive' })
      setConnecting(false)
    }
  }

  const disconnectCalendar = async (
    integrationId: string,
    _provider: string,
  ) => {
    try {
      const { error } = await typedSupabase
        .from('user_integrations')
        .delete()
        .eq('id', integrationId)
      if (error) {
        toast({ title: 'Erro ao desconectar', variant: 'destructive' })
      } else {
        toast({ title: 'Calend├írio desconectado' })
        fetchData()
      }
    } catch (_) {
      toast({ title: 'Erro ao desconectar', variant: 'destructive' })
    }
  }

  const syncCalendar = async (direction: 'from-google' | 'to-google') => {
    setSyncing(direction)
    try {
      const {
        data: { session },
      } = await supabase.auth.getSession()
      if (!session?.provider_token)
        throw new Error('N├úo autenticado com Google')

      const response = await fetch(
        'https://www.googleapis.com/calendar/v3/calendars/primary/events?maxResults=10',
        {
          headers: {
            Authorization: `Bearer ${session.provider_token}`,
            'Content-Type': 'application/json',
          },
        },
      )
      if (!response.ok) throw new Error('Falha ao contactar Google API')

      const data = await response.json()
      toast({
        title: 'Sincroniza├º├úo conclu├¡da!',
        description: `Conex├úo verificada. ${data.items?.length || 0} eventos encontrados.`,
      })
      fetchData()
    } catch (error: unknown) {
      const message =
        error instanceof Error ? error.message : 'N├úo foi poss├¡vel sincronizar'
      toast({
        title: 'Erro na sincroniza├º├úo',
        description: message,
        variant: 'destructive',
      })
    } finally {
      setSyncing(null)
    }
  }

  const toggleReminderDay = (day: number) => {
    const currentDays = notificationSettings.reminder_days || []
    setNotificationSettings({
      ...notificationSettings,
      reminder_days: currentDays.includes(day)
        ? currentDays.filter((d) => d !== day)
        : [...currentDays, day].sort((a, b) => a - b),
    })
  }

  const saveNotificationSettings = async () => {
    setSaving(true)
    const { id, ...settingsWithoutId } = notificationSettings
    const _payload = id ? notificationSettings : settingsWithoutId

    const { error } = await typedSupabase.from('notification_settings').upsert(
      {
        user_id: user!.id,
        email_enabled: notificationSettings.email_enabled,
        reminder_days: notificationSettings.reminder_days,
        notify_new_event: notificationSettings.notify_new_event,
        notify_event_update: notificationSettings.notify_event_update,
        notify_event_cancel: notificationSettings.notify_event_cancel,
        notify_assistant_assigned:
          notificationSettings.notify_assistant_assigned,
      } as never,
      { onConflict: 'user_id' },
    )

    if (error) {
      toast({ title: 'Erro ao salvar configura├º├Áes', variant: 'destructive' })
    } else {
      toast({ title: 'Configura├º├Áes de notifica├º├úo salvas!' })
    }
    setSaving(false)
  }

  const getIntegrationByProvider = (provider: string) =>
    integrations.find((i) => i.provider === provider)

  return {
    integrations,
    notificationSettings,
    setNotificationSettings,
    loading,
    saving,
    connecting,
    syncing,
    connectGoogleCalendar,
    disconnectCalendar,
    syncCalendar,
    toggleReminderDay,
    saveNotificationSettings,
    getIntegrationByProvider,
    deliverabilityStatus,
  }
}

import { useState, useEffect } from 'react'
import { useSearchParams, useNavigate, useParams } from 'react-router-dom'
import { supabase } from '@/integrations/supabase/client'
import { toast } from 'sonner'

export interface AssistantInvite {
  id: string
  email: string
  name: string | null
  status: string
  is_registered: boolean
  invite_token: string | null
}

export function useInviteLanding() {
  const { token: pathToken } = useParams()
  const [searchParams] = useSearchParams()
  const token = pathToken || searchParams.get('token')
  const navigate = useNavigate()

  const [status, setStatus] = useState<'loading' | 'valid' | 'invalid'>(
    'loading',
  )
  const [inviteData, setInviteData] = useState<AssistantInvite | null>(null)
  const [loading, setLoading] = useState(false)

  const [formData, setFormData] = useState({
    fullName: '',
    phone: '',
    password: '',
    confirmPassword: '',
  })

  useEffect(() => {
    if (!token) {
      setStatus('invalid')
      return
    }
    checkInvite()
  }, [token])

  const checkInvite = async () => {
    try {
      const query = supabase
        .from('assistants')
        .select('id, email, name, status, is_registered, invite_token')

      const { data, error } = await query
        .eq('invite_token', token)
        .maybeSingle()

      if (error || !data) {
        setStatus('invalid')
        return
      }

      const safeData = data

      if (safeData.is_registered) {
        toast.error('Este convite j├í foi utilizado.')
        navigate('/auth')
        return
      }

      if (safeData.status !== 'pending') {
        setStatus('invalid')
        return
      }

      setInviteData(safeData)
      setStatus('valid')
    } catch (_error) {
      setStatus('invalid')
    }
  }

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault()

    if (formData.password !== formData.confirmPassword) {
      toast.error('As senhas n├úo coincidem.')
      return
    }

    if (formData.password.length < 6) {
      toast.error('A senha deve ter pelo menos 6 caracteres.')
      return
    }

    if (!inviteData) return

    setLoading(true)

    try {
      const originalEmail = inviteData.email
      const sanitizedEmail = originalEmail
        .replace(/[^\x20-\x7E]/g, '')
        .trim()
        .toLowerCase()
      const cleanFullName = formData.fullName.trim()
      const cleanPhone = formData.phone.trim()

      let userId = null

      const { data: authData, error: authError } = await supabase.auth.signUp({
        email: sanitizedEmail,
        password: formData.password.trim(),
        options: {
          data: {
            full_name: cleanFullName,
            phone: cleanPhone,
            role: 'assistant',
          },
        },
      })

      if (authError) {
        if (
          authError.message.includes('already registered') ||
          authError.message.includes('User already registered') ||
          authError.status === 400
        ) {
          toast.info('Conta existente identificada!', {
            description: 'Tentando vincular com a senha informada...',
          })

          const { data: loginData, error: loginError } =
            await supabase.auth.signInWithPassword({
              email: sanitizedEmail,
              password: formData.password.trim(),
            })

          if (loginError) {
            toast.error(
              'Voc├¬ j├í possui uma conta, mas a senha est├í incorreta.',
              { description: 'Use sua senha antiga para aceitar o convite.' },
            )
            setLoading(false)
            return
          }

          if (loginData.user) {
            userId = loginData.user.id
            toast.success('Login realizado! Vinculando agenda...')
          }
        } else {
          throw authError
        }
      } else if (authData.user) {
        userId = authData.user.id
      }

      if (userId) {
        const { error: updateError } = await supabase
          .from('assistants')
          .update({
            assistant_user_id: userId,
            is_registered: true,
            status: 'accepted',
            phone: cleanPhone,
            name: cleanFullName,
            invite_token: null,
          })
          .eq('id', inviteData.id)

        if (updateError) {
          throw new Error('Falha ao vincular contrato. Tente novamente.')
        }

        const { error: profileError } = await supabase.from('profiles').upsert(
          {
            id: userId,
            email: sanitizedEmail,
            full_name: cleanFullName,
            role: 'assistant',
            updated_at: new Date().toISOString(),
          },
          { onConflict: 'id' },
        )

        if (profileError) {
          toast.error('Erro ao criar perfil de usu├írio.')
        }

        toast.success('Acesso liberado com sucesso!')

        setTimeout(() => {
          navigate('/portal-assistente')
        }, 1000)
      }
    } catch (error: unknown) {
      const message =
        error instanceof Error ? error.message : 'Erro ao processar cadastro.'
      toast.error(message)
    } finally {
      setLoading(false)
    }
  }

  return {
    status,
    inviteData,
    loading,
    formData,
    setFormData,
    handleRegister,
  }
}

import { useContext } from 'react'
