import { useState, useEffect } from 'react'
import { supabase } from '@/integrations/supabase/client'
import { addDays } from 'date-fns/addDays'

export interface NotificationItem {
  id: string
  type: 'event' | 'payment' | 'commission'
  title: string
  description: string
  date?: string
  read: boolean
  link?: string
}

export const useNotifications = (userId: string | undefined) => {
  const [notifications, setNotifications] = useState<NotificationItem[]>([])
  const [loading, setLoading] = useState(true)
  const [unreadCount, setUnreadCount] = useState(0)

  useEffect(() => {
    if (!userId) return

    const fetchNotifications = async () => {
      setLoading(true)
      const newNotifications: NotificationItem[] = []

      try {
        const today = new Date()
        const nextWeek = addDays(today, 7)

        const { data: upcomingEvents } = await supabase
          .from('events')
          .select('id, title, event_date, event_type')
          .gte('event_date', today.toISOString())
          .lte('event_date', nextWeek.toISOString())
          .order('event_date', { ascending: true })

        if (upcomingEvents) {
          upcomingEvents.forEach((event) => {
            newNotifications.push({
              id: `evt-${event.id}`,
              type: 'event',
              title: 'Evento Pr├│ximo',
              description: `${event.title} - ${new Date(event.event_date).toLocaleDateString('pt-BR')}`,
              date: event.event_date,
              read: false,
              link: '/agenda',
            })
          })
        }

        const { data: pendingInvoices } = await supabase
          .from('invoices')
          .select(
            `
            id, amount, due_date, status,
            projects (
              id,
              name,
              client:wedding_clients (name:full_name)
            )
          `,
          )
          .eq('status', 'pending')

        if (pendingInvoices) {
          pendingInvoices.forEach((inv: any) => {
            const clientName = inv.projects?.client?.name || 'Cliente'
            newNotifications.push({
              id: `pay-${inv.id}`,
              type: 'payment',
              title: 'Pagamento Pendente',
              description: `${clientName} - R$ ${inv.amount}`,
              date: inv.due_date,
              read: false,
              link: '/financeiro',
            })
          })
        }

        const startOfMonth = new Date(
          today.getFullYear(),
          today.getMonth(),
          1,
        ).toISOString()
        const { data: commissionEvents } = await supabase
          .from('events')
          .select('id, title, assistant_commission, event_date')
          .gt('assistant_commission', 0)
          .gte('event_date', startOfMonth)

        if (commissionEvents) {
          commissionEvents.forEach((evt) => {
            newNotifications.push({
              id: `com-${evt.id}`,
              type: 'commission',
              title: 'Comiss├úo de Equipe',
              description: `Confirmar pgto: ${evt.title} (R$ ${evt.assistant_commission})`,
              date: evt.event_date,
              read: false,
              link: '/admin/financials',
            })
          })
        }

        const readIds = JSON.parse(
          localStorage.getItem('read_notifications') || '[]',
        )
        const filtered = newNotifications.filter((n) => !readIds.includes(n.id))

        setNotifications(filtered)
        setUnreadCount(filtered.length)
      } catch (error) {
        void error
      } finally {
        setLoading(false)
      }
    }

    fetchNotifications()
  }, [userId])

  const markAsRead = (id: string) => {
    const readIds = JSON.parse(
      localStorage.getItem('read_notifications') || '[]',
    )
    if (!readIds.includes(id)) {
      const newReadIds = [...readIds, id]
      localStorage.setItem('read_notifications', JSON.stringify(newReadIds))

      setNotifications((prev) => prev.filter((n) => n.id !== id))
      setUnreadCount((prev) => prev - 1)
    }
  }

  return { notifications, loading, unreadCount, markAsRead }
}

import { useState, useEffect } from 'react'
import { supabase } from '@/integrations/supabase/client'
import { useToast } from '@/hooks/use-toast'
import { format } from 'date-fns/format'

import { ptBR } from 'date-fns/locale'
import { v4 as uuidv4 } from 'uuid'
import jsPDF from 'jspdf'
import type { Tables } from '@/integrations/supabase/types'
import type { Editor } from '@tiptap/react'

interface ProjectData {
  id: string
  name: string
  status: string
  notes?: string | null
}

interface ContractData extends Omit<Tables<'contracts'>, 'signature_data'> {
  signature_data: string | null
}

export type { ProjectData, ContractData }

interface UseProjectContractProps {
  projectId: string | undefined
  isClientView: boolean
  editor: Editor | null
}

export function useProjectContract({
  projectId,
  isClientView: _isClientView,
  editor,
}: UseProjectContractProps) {
  const { toast } = useToast()

  const [project, setProject] = useState<ProjectData | null>(null)
  const [contract, setContract] = useState<ContractData | null>(null)
  const [loading, setLoading] = useState(true)
  const [isSignatureModalOpen, setIsSignatureModalOpen] = useState(false)
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [signedSuccess, setSignedSuccess] = useState(false)
  const [finalPdfUrl, setFinalPdfUrl] = useState<string | null>(null)

  useEffect(() => {
    const fetchData = async () => {
      if (!projectId) {
        setLoading(false)
        return
      }

      try {
        const { data: projectData, error: projectError } = await supabase
          .from('projects')
          .select('id, name, status, notes')
          .eq('id', projectId)
          .single()

        if (projectError) throw projectError
        setProject(projectData)

        const { data: contractData, error: contractError } = await supabase
          .from('contracts')
          .select('*')
          .eq('project_id', projectId)
          .maybeSingle()

        if (contractError && contractError.code !== 'PGRST116') {
          throw contractError
        }

        if (contractData) {
          setContract(contractData)
          if (contractData.status === 'signed') {
            setSignedSuccess(true)
            if (contractData.signature_data) {
              try {
                const parsed =
                  typeof contractData.signature_data === 'string'
                    ? JSON.parse(contractData.signature_data)
                    : contractData.signature_data
                if (parsed?.pdf_url) setFinalPdfUrl(parsed.pdf_url)
              } catch (_) {}
            }
          }
        }

        const savedContent = localStorage.getItem(`contract_${projectId}`)
        const contentToLoad = savedContent || contractData?.content || ''
        if (editor && contentToLoad) {
          editor.commands.setContent(contentToLoad)
        }
      } catch (_error) {
        toast({
          title: 'Erro',
          description: 'N├úo foi poss├¡vel carregar o contrato.',
          variant: 'destructive',
        })
      } finally {
        setLoading(false)
      }
    }

    fetchData()
  }, [projectId, editor, toast])

  const handleGenerateSignatureLink = async () => {
    if (!projectId) return
    const signatureUrl = `${window.location.origin}/projects/${projectId}/contract?mode=client`

    try {
      await navigator.clipboard.writeText(signatureUrl)
      toast({
        title: 'Sucesso!',
        description: 'Link de assinatura copiado para a ├írea de transfer├¬ncia.',
      })
    } catch (_) {
      toast({
        title: 'Erro',
        description: 'N├úo foi poss├¡vel copiar o link.',
        variant: 'destructive',
      })
    }
  }

  const getClientIP = () => 'IP Logged by Server'

  const buildSignatureBlock = (
    signatureDataUrl: string,
    signedAt: string,
    contractHash: string,
  ) => `
    <div style="margin-top: 60px; page-break-inside: avoid; background-color: #000; color: #fff; padding: 30px; border: 1px solid #333;">
        <div style="display: flex; justify-content: space-between; gap: 20px;">
                <p style="font-family: 'Inter', sans-serif; font-size: 8px; text-transform: uppercase; color: #666;">AUTENTICADO POR KHAOS STUDIO<br/>Paula Larosa</p>
            </div>
            <div style="flex: 1; border-right: 1px solid #333; padding-right: 20px; padding-left: 20px;">
                <p style="font-family: 'Playfair Display', serif; font-size: 10px; letter-spacing: 2px; text-transform: uppercase; margin-bottom: 20px; color: #888;">Contratante</p>
                <div style="height: 60px; display: flex; align-items: center; justify-content: center; border-bottom: 1px solid #333; margin-bottom: 10px;">
                    <img src="${signatureDataUrl}" style="max-height: 50px; filter: invert(1);" />
                </div>
                <p style="font-family: 'Inter', sans-serif; font-size: 8px; text-transform: uppercase; color: #666;">ASSINATURA DIGITAL DA CLIENTE<br/>IP: ${getClientIP()} | ${signedAt}</p>
            </div>
            <div style="flex: 1; padding-left: 20px; display: flex; flex-col; justify-content: flex-end; align-items: flex-start;">
                <div style="border: 1px solid #fff; padding: 10px; width: 100%;">
                    <p style="font-family: 'Inter', sans-serif; font-size: 8px; text-transform: uppercase; color: #888; margin-bottom: 5px;">System ID</p>
                    <p style="font-family: 'Inter', sans-serif; font-size: 10px; color: #fff; word-break: break-all;">${contractHash}</p>
                    <p style="font-family: 'Inter', sans-serif; font-size: 8px; text-transform: uppercase; color: #666; margin-top: 10px;">CERTIFICADO POR<br/>KONTROL SYSTEM</p>
                </div>
            </div>
        </div>
        <div style="margin-top: 20px; border-top: 1px solid #333; padding-top: 10px; text-align: center;">
             <p style="font-family: 'Inter', sans-serif; font-size: 8px; text-transform: uppercase; color: #444; letter-spacing: 3px;">SECURE DIGITAL TRANSACTION ÔÇó KHAOSKONTROL.COM.BR</p>
        </div>
    </div>
  `

  const handleConfirmSignature = async (signatureDataUrl: string) => {
    setIsSubmitting(true)
    setIsSignatureModalOpen(false)

    try {
      const contractHTML = editor?.getHTML() || ''
      const signedAt = format(new Date(), 'dd/MM/yyyy HH:mm:ss', {
        locale: ptBR,
      })
      const contractHash = uuidv4()
        .replace(/-/g, '')
        .toUpperCase()
        .substring(0, 16)
      const signatureBlock = buildSignatureBlock(
        signatureDataUrl,
        signedAt,
        contractHash,
      )

      if (typeof window !== 'undefined' && window.gtag) {
        window.gtag('event', 'contract_signed', {
          event_category: 'engagement',
          event_label: projectId,
        })
      }

      const fullHTML = `<!DOCTYPE html><html><head><meta charset="UTF-8"><style>body{font-family:'Times New Roman',serif;line-height:1.6;color:#000;padding:40px;}p{margin:10px 0;}h1{font-size:24px;margin:20px 0;}h2{font-size:18px;margin:15px 0;}ul,ol{margin:10px 0 10px 20px;}li{margin:5px 0;}</style></head><body>${contractHTML}${signatureBlock}</body></html>`

      const pdfBlob = await new Promise<Blob>((resolve, reject) => {
        const doc = new jsPDF({
          unit: 'mm',
          format: 'a4',
          orientation: 'portrait',
        })
        const container = document.createElement('div')
        container.innerHTML = fullHTML
        container.style.width = '190mm'
        container.style.fontSize = '12px'

        doc
          .html(container, {
            callback: function (doc) {
              resolve(doc.output('blob'))
            },
            margin: [10, 10, 10, 10],
            x: 10,
            y: 10,
            width: 190,
            windowWidth: 800,
          })
          .catch((err: Error) => reject(err))
      })

      const fileName = `contracts/${projectId}/${Date.now()}_signed.pdf`
      const { error: uploadError } = await supabase.storage
        .from('briefing-files')
        .upload(fileName, pdfBlob, { cacheControl: '3600', upsert: false })
      if (uploadError) throw new Error('Falha no upload do contrato.')

      const { data: urlData } = supabase.storage
        .from('briefing-files')
        .getPublicUrl(fileName)

      const signaturePayload = {
        signed_at: new Date().toISOString(),
        ip_address: getClientIP(),
        pdf_url: urlData.publicUrl,
        contract_hash: contractHash,
        signature_base64_snippet: signatureDataUrl.substring(0, 50) + '...',
      }

      if (contract) {
        const { error: updateError } = await supabase
          .from('contracts')
          .update({
            content: contractHTML,
            status: 'signed',
            signature_data: JSON.stringify(signaturePayload),
            signed_at: new Date().toISOString(),
            signature_url: fileName,
          })
          .eq('id', contract.id)
        if (updateError) throw updateError
      } else {
        const {
          data: { user },
        } = await supabase.auth.getUser()
        if (user) {
          await supabase.from('contracts').insert({
            project_id: projectId!,
            user_id: user.id,
            title: `Contrato - ${project?.name}`,
            content: contractHTML,
            status: 'signed',
            signature_data: JSON.stringify(signaturePayload),
            signed_at: new Date().toISOString(),
          })
        }
      }

      setFinalPdfUrl(urlData.publicUrl)
      setSignedSuccess(true)
      if (project) setProject({ ...project, status: 'signed' })

      toast({
        title: 'CONTRATO SELADO',
        description: 'Sua c├│pia assinada j├í est├í dispon├¡vel.',
        className: 'bg-black text-white border-neutral-800 font-mono',
      })
    } catch (_error) {
      toast({
        title: 'Erro',
        description: 'N├úo foi poss├¡vel finalizar o contrato. Tente novamente.',
        variant: 'destructive',
      })
    } finally {
      setIsSubmitting(false)
    }
  }

  const handleDownloadPDF = async () => {
    if (finalPdfUrl) {
      window.open(finalPdfUrl, '_blank')
      return
    }
    if (!editor) return

    try {
      const html = editor.getHTML()
      const doc = new jsPDF({
        unit: 'mm',
        format: 'a4',
        orientation: 'portrait',
      })
      const container = document.createElement('div')
      container.innerHTML = html
      container.style.width = '190mm'
      container.style.fontSize = '12px'

      doc.html(container, {
        callback: function (doc) {
          doc.save(`${project?.name || 'contrato'}_draft.pdf`)
        },
        margin: [10, 10, 10, 10],
        x: 10,
        y: 10,
        width: 190,
        windowWidth: 800,
      })
    } catch (_) {}
  }

  return {
    project,
    loading,
    signedSuccess,
    isSignatureModalOpen,
    setIsSignatureModalOpen,
    isSubmitting,
    finalPdfUrl,
    handleGenerateSignatureLink,
    handleConfirmSignature,
    handleDownloadPDF,
  }
}

import { useState, useEffect, useCallback } from 'react'
import { supabase } from '@/integrations/supabase/client'
import { useAuth } from '@/hooks/useAuth'
import { logger } from '@/services/logger'

const VAPID_PUBLIC_KEY = import.meta.env.VITE_VAPID_PUBLIC_KEY || ''

function urlBase64ToUint8Array(base64String: string): Uint8Array {
  const padding = '='.repeat((4 - (base64String.length % 4)) % 4)
  const base64 = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/')
  const rawData = window.atob(base64)
  const outputArray = new Uint8Array(rawData.length)
  for (let i = 0; i < rawData.length; ++i) {
    outputArray[i] = rawData.charCodeAt(i)
  }
  return outputArray
}

export function usePushNotifications() {
  const { user } = useAuth()
  const [isSupported, setIsSupported] = useState(false)
  const [isSubscribed, setIsSubscribed] = useState(false)
  const [permission, setPermission] =
    useState<NotificationPermission>('default')
  const [loading, setLoading] = useState(false)

  useEffect(() => {
    const supported =
      'serviceWorker' in navigator &&
      'PushManager' in window &&
      'Notification' in window &&
      !!VAPID_PUBLIC_KEY

    setIsSupported(supported)

    if (supported) {
      setPermission(Notification.permission)
      checkExistingSubscription()
    }
  }, [])

  const checkExistingSubscription = useCallback(async () => {
    try {
      const registration = await navigator.serviceWorker.ready
      const subscription = await registration.pushManager.getSubscription()
      setIsSubscribed(!!subscription)
    } catch {
      setIsSubscribed(false)
    }
  }, [])

  const subscribe = useCallback(async () => {
    if (!user || !isSupported) return false

    setLoading(true)
    try {
      const perm = await Notification.requestPermission()
      setPermission(perm)

      if (perm !== 'granted') {
        setLoading(false)
        return false
      }

      const registration = await navigator.serviceWorker.ready
      const subscription = await registration.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(VAPID_PUBLIC_KEY),
      })

      const keys = subscription.toJSON().keys
      if (!keys?.p256dh || !keys?.auth) throw new Error('Missing push keys')

      const { error } = await supabase.rpc('save_push_subscription', {
        p_endpoint: subscription.endpoint,
        p_p256dh: keys.p256dh,
        p_auth: keys.auth,
        p_user_agent: navigator.userAgent,
      })

      if (error) throw error

      setIsSubscribed(true)
      return true
    } catch (error) {
      logger.error('usePushNotifications.subscribe', error)
      return false
    } finally {
      setLoading(false)
    }
  }, [user, isSupported])

  const unsubscribe = useCallback(async () => {
    setLoading(true)
    try {
      const registration = await navigator.serviceWorker.ready
      const subscription = await registration.pushManager.getSubscription()

      if (subscription) {
        await supabase.rpc('remove_push_subscription', {
          p_endpoint: subscription.endpoint,
        })
        await subscription.unsubscribe()
      }

      setIsSubscribed(false)
      return true
    } catch (error) {
      logger.error('usePushNotifications.unsubscribe', error)
      return false
    } finally {
      setLoading(false)
    }
  }, [])

  return {
    isSupported,
    isSubscribed,
    permission,
    loading,
    subscribe,
    unsubscribe,
  }
}

import { useMutation, UseMutationOptions } from '@tanstack/react-query'
import { supabase } from '@/integrations/supabase/client'
import { Database } from '@/integrations/supabase/types'

type TableName = keyof Database['public']['Tables']
type Operation = 'insert' | 'update' | 'upsert' | 'delete'

interface SupabaseMutationParams<T extends TableName> {
  table: T
  operation: Operation

  options?: Omit<UseMutationOptions<any, Error, any, unknown>, 'mutationFn'>
}

export function useSupabaseMutation<T extends TableName>({
  table,
  operation,
  options,
}: SupabaseMutationParams<T>) {
  return useMutation({
    mutationFn: async (payload: any) => {
      const query = supabase.from(table)[operation](payload)

      if (operation !== 'delete') {
        const { data, error } = await query.select().single()
        if (error) throw error
        return data
      } else {
        const { data, error } = await query
        if (error) throw error
        return data
      }
    },
    ...options,
  })
}

import { supabase } from '@/integrations/supabase/client'
import { nanoid } from 'nanoid'

export async function uploadImageSafely(
  file: File,
  bucket: string,
  folder: string,
): Promise<string> {
  const fileExt = file.name.split('.').pop()
  const fileName = `${nanoid()}.${fileExt}`
  const filePath = `${folder}/${fileName}`

  const { error } = await supabase.storage.from(bucket).upload(filePath, file, {
    cacheControl: '3600',
    upsert: false,
  })

  if (error) throw error

  const { data: urlData } = supabase.storage.from(bucket).getPublicUrl(filePath)

  return urlData.publicUrl
}

export async function deletePhotoSafely(
  photoUrl: string,
  bucket: string = 'avatars',
) {
  try {
    const urlParts = photoUrl.split('/')

    const bucketIndex = urlParts.indexOf(bucket)
    if (bucketIndex === -1) return

    const filePath = urlParts.slice(bucketIndex + 1).join('/')

    await supabase.storage.from(bucket).remove([filePath])
  } catch (error) {}
}

